  -- ============================================================
  -- FRANÇAIS - Chapitre 1 : La Dissertation Littéraire
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_francais_id, 'dissertation-litteraire', 1, 'La Dissertation Littéraire', 'Méthodologie et pratique de la dissertation littéraire', 1)
  RETURNING id INTO v_ch_01;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_01, 'dissertation-litteraire', 'La Dissertation Littéraire',
  'La dissertation littéraire est un exercice argumentatif structuré qui consiste à discuter une problématique liée à la littérature. Elle requiert une méthode rigoureuse d''analyse, de rédaction et d''organisation des idées en trois grandes parties.',
  '{"key_points": ["Comprendre le sujet et dégager la problématique", "Construire un plan dialectique (thèse, antithèse, synthèse)", "Rédiger une introduction avec amorce, reformulation et annonce du plan", "Développer chaque partie avec argument, exemple littéraire et explication", "Maîtriser les transitions et la conclusion avec ouverture", "Utiliser des citations d''auteurs pour appuyer l''argumentation", "Respecter la structure : introduction, développement, conclusion"], "content": "## Qu''est-ce que la dissertation littéraire ?\n\nLa dissertation littéraire est un exercice d''argumentation organisé en plusieurs parties. Elle consiste à **analyser un sujet**, à en dégager une **problématique** et à y répondre de manière structurée en s''appuyant sur des **exemples littéraires** précis.\n\n## Les étapes de la méthode\n\n### 1. Analyser le sujet\n- Lire attentivement l''énoncé et repérer les **mots-clés**\n- Identifier le **thème** (ex : le roman, la poésie, le théâtre)\n- Dégager la **problématique** : la question centrale à laquelle répondre\n- Déterminer le **type de plan** : dialectique (oui/non/dépassement), thématique ou analytique\n\n### 2. Construire le plan\n- **Plan dialectique** : Thèse (oui) / Antithèse (non) / Synthèse (dépassement)\n- Chaque partie contient **2 à 3 sous-parties**\n- Chaque sous-partie = **argument + exemple littéraire + explication**\n\n### 3. Rédiger l''introduction\nL''introduction comporte :\n- Une **amorce** (citation, fait littéraire, contexte historique)\n- La **reformulation du sujet** et la **problématique**\n- L''**annonce du plan** (les grandes parties)\n\n### 4. Rédiger le développement\n- Chaque paragraphe suit le schéma : **argument → exemple → explication**\n- Les **transitions** entre les parties sont obligatoires\n- Utiliser des **connecteurs logiques** : en effet, cependant, par conséquent, néanmoins\n\n### 5. Rédiger la conclusion\n- **Bilan** : résumer les grandes idées du développement\n- **Réponse à la problématique**\n- **Ouverture** : élargir le sujet vers une nouvelle réflexion\n\n## Les erreurs à éviter\n- Paraphraser le sujet sans l''analyser\n- Juxtaposer des exemples sans argumentation\n- Oublier les transitions entre les parties\n- Rédiger une conclusion trop courte ou absente\n- Ne pas citer d''auteurs ou d''œuvres précises"}',
  '[{"question": "Quel est l''objectif principal de la dissertation littéraire ?", "options": ["Résumer une œuvre littéraire", "Argumenter autour d''une problématique littéraire", "Raconter une histoire inventée", "Décrire un personnage de roman"], "correct": 1, "explanation": "La dissertation littéraire vise à argumenter de manière structurée autour d''une problématique liée à la littérature, en s''appuyant sur des exemples précis."},
  {"question": "Quel plan est le plus courant pour une dissertation littéraire ?", "options": ["Le plan chronologique", "Le plan dialectique (thèse, antithèse, synthèse)", "Le plan descriptif", "Le plan narratif"], "correct": 1, "explanation": "Le plan dialectique est le plus utilisé. Il permet de défendre une thèse, de la nuancer avec une antithèse, puis de proposer une synthèse qui dépasse l''opposition."},
  {"question": "Que doit contenir l''introduction d''une dissertation ?", "options": ["Uniquement la problématique", "L''amorce, la problématique et l''annonce du plan", "Un résumé de l''œuvre étudiée", "La conclusion anticipée"], "correct": 1, "explanation": "L''introduction doit comporter une amorce pour accrocher le lecteur, la formulation de la problématique et l''annonce claire du plan que l''on va suivre."},
  {"question": "Quel schéma suit chaque paragraphe du développement ?", "options": ["Citation, résumé, commentaire", "Argument, exemple littéraire, explication", "Introduction, développement, conclusion", "Question, réponse, illustration"], "correct": 1, "explanation": "Chaque paragraphe du développement suit la structure argument-exemple-explication pour construire une démonstration rigoureuse et convaincante."},
  {"question": "Quel élément est indispensable dans la conclusion ?", "options": ["Une nouvelle problématique complète", "Le bilan du développement et une ouverture", "La répétition de l''introduction", "Une liste de toutes les œuvres citées"], "correct": 1, "explanation": "La conclusion doit contenir un bilan synthétisant les idées développées, une réponse à la problématique, et une ouverture vers une réflexion plus large."}]',
  '[{"question": "Quelles sont les trois parties du plan dialectique ?", "answer": "Thèse (défendre une position), Antithèse (nuancer ou contredire), Synthèse (dépasser l''opposition en proposant une vision plus complète).", "category": "Vocabulaire"},
  {"question": "Qu''est-ce qu''une amorce dans l''introduction ?", "answer": "L''amorce est la première phrase de l''introduction qui sert à accrocher le lecteur. Elle peut être une citation, un fait historique, une référence culturelle ou une question rhétorique.", "category": "Vocabulaire"},
  {"question": "Quel est le rôle des connecteurs logiques ?", "answer": "Les connecteurs logiques (en effet, cependant, par conséquent, de plus) assurent la cohérence du texte en liant les idées entre elles et en marquant les relations logiques.", "category": "Vocabulaire"},
  {"question": "Quelle différence entre argument et exemple ?", "answer": "L''argument est une idée abstraite qui soutient la thèse. L''exemple est un fait concret (œuvre, auteur, passage) qui illustre et prouve l''argument. Les deux sont complémentaires.", "category": "Vocabulaire"},
  {"question": "Qu''est-ce qu''une ouverture en conclusion ?", "answer": "L''ouverture est la dernière phrase de la conclusion qui élargit la réflexion vers un nouveau sujet, une question connexe, ou un autre domaine artistique, sans introduire de nouvel argument.", "category": "Vocabulaire"}]',
  false, 1);

  -- ============================================================
  -- FRANÇAIS - Chapitre 2 : Le Commentaire Composé
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_francais_id, 'commentaire-compose', 2, 'Le Commentaire Composé', 'Méthode d''analyse et de rédaction du commentaire composé', 2)
  RETURNING id INTO v_ch_02;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_02, 'commentaire-compose', 'Le Commentaire Composé',
  'Le commentaire composé est un exercice d''analyse littéraire qui consiste à étudier un texte en dégageant ses axes de lecture. Il allie l''observation des procédés stylistiques à l''interprétation du sens pour montrer comment la forme sert le fond.',
  '{"key_points": ["Lire attentivement le texte et identifier le genre, le registre et le thème", "Repérer les procédés stylistiques : figures de style, champs lexicaux, rythme", "Dégager deux ou trois axes de lecture cohérents", "Construire un plan organisé autour des axes identifiés", "Rédiger avec des citations intégrées au commentaire", "Analyser le rapport entre la forme et le fond", "Éviter la paraphrase : toujours interpréter les procédés relevés"], "content": "## Définition du commentaire composé\n\nLe commentaire composé est un exercice qui consiste à **analyser un texte littéraire** en montrant comment les procédés d''écriture servent le sens. Contrairement à la dissertation, on part du **texte lui-même** et non d''une question générale.\n\n## Méthode en cinq étapes\n\n### 1. La lecture attentive\n- Lire le texte **plusieurs fois**\n- Identifier : l''auteur, l''œuvre, le genre (roman, poésie, théâtre), l''époque\n- Repérer le **thème principal** et le **registre** (lyrique, tragique, comique, satirique)\n\n### 2. L''analyse des procédés\nRepérer systématiquement :\n- Les **figures de style** : métaphore, comparaison, personnification, hyperbole, antithèse, anaphore, allitération, assonance\n- Les **champs lexicaux** : groupes de mots appartenant au même thème\n- La **structure du texte** : rythme des phrases, ponctuation, enjambements\n- Le **point de vue narratif** : interne, externe, omniscient\n- Les **temps verbaux** et leur valeur\n\n### 3. La construction des axes\n- Regrouper les observations en **2 ou 3 axes de lecture**\n- Chaque axe = une idée directrice appuyée par plusieurs procédés\n- Exemple d''axes : « La dimension lyrique du poème » / « La critique sociale dans le texte »\n\n### 4. La rédaction\n- **Introduction** : présentation de l''auteur, de l''œuvre, du passage, annonce des axes\n- **Développement** : un paragraphe par sous-partie, avec citation + procédé + interprétation\n- **Conclusion** : bilan des axes et ouverture\n\n### 5. Les figures de style essentielles\n- **Métaphore** : comparaison sans outil (« la mer de ses yeux »)\n- **Comparaison** : avec outil (comme, tel, semblable à)\n- **Personnification** : attribuer des traits humains à un objet\n- **Hyperbole** : exagération (« mourir de faim »)\n- **Antithèse** : opposition de deux idées\n- **Anaphore** : répétition en début de phrase\n- **Allitération** : répétition de consonnes\n- **Assonance** : répétition de voyelles"}',
  '[{"question": "Quel est le principe fondamental du commentaire composé ?", "options": ["Résumer le texte de manière linéaire", "Montrer comment la forme sert le fond", "Donner son avis personnel sur le texte", "Comparer le texte avec d''autres œuvres"], "correct": 1, "explanation": "Le commentaire composé vise à montrer comment les procédés d''écriture (la forme) contribuent à créer le sens du texte (le fond). C''est l''articulation entre forme et fond qui est au cœur de l''exercice."},
  {"question": "Qu''est-ce qu''une anaphore ?", "options": ["Une exagération volontaire", "La répétition d''un mot en début de vers ou de phrase", "Une comparaison implicite", "L''opposition de deux idées"], "correct": 1, "explanation": "L''anaphore est la répétition d''un même mot ou groupe de mots au début de plusieurs vers, phrases ou propositions successives. Elle crée un effet d''insistance et de rythme."},
  {"question": "Combien d''axes de lecture faut-il généralement dégager ?", "options": ["Un seul axe très détaillé", "Deux ou trois axes cohérents", "Cinq axes minimum", "Autant que de paragraphes dans le texte"], "correct": 1, "explanation": "Le commentaire composé s''organise généralement autour de deux ou trois axes de lecture qui regroupent les observations faites sur le texte de manière cohérente et progressive."},
  {"question": "Quelle est la différence entre métaphore et comparaison ?", "options": ["Il n''y a aucune différence", "La métaphore utilise un outil de comparaison, pas la comparaison", "La comparaison utilise un outil (comme, tel), la métaphore non", "La métaphore est toujours plus longue"], "correct": 2, "explanation": "La comparaison rapproche deux éléments à l''aide d''un outil de comparaison (comme, tel, semblable à), tandis que la métaphore effectue ce rapprochement sans outil, de manière implicite."},
  {"question": "Quelle erreur majeure faut-il éviter dans un commentaire ?", "options": ["Citer le texte", "Utiliser des figures de style", "Paraphraser le texte sans l''analyser", "Structurer en plusieurs parties"], "correct": 2, "explanation": "La paraphrase consiste à reformuler le texte sans l''analyser ni l''interpréter. C''est l''erreur la plus courante et la plus pénalisée. Il faut toujours associer un procédé relevé à une interprétation."}]',
  '[{"question": "Qu''est-ce qu''un champ lexical ?", "answer": "Un champ lexical est un ensemble de mots qui se rapportent à un même thème ou à une même notion. Par exemple, le champ lexical de la guerre : combat, arme, soldat, bataille, victoire.", "category": "Vocabulaire"},
  {"question": "Qu''est-ce que la personnification ?", "answer": "La personnification consiste à attribuer des caractéristiques humaines (sentiments, actions, paroles) à un animal, un objet ou une idée abstraite. Exemple : « Le vent gémissait dans les arbres ».", "category": "Vocabulaire"},
  {"question": "Qu''est-ce qu''une hyperbole ?", "answer": "L''hyperbole est une figure de style qui consiste à exagérer une idée pour la mettre en relief. Elle amplifie la réalité pour créer un effet d''insistance. Exemple : « Je meurs de soif », « un bruit à réveiller les morts ».", "category": "Vocabulaire"},
  {"question": "Quelle est la différence entre allitération et assonance ?", "answer": "L''allitération est la répétition de sons consonantiques (ex : « Pour qui sont ces serpents qui sifflent sur vos têtes »). L''assonance est la répétition de sons vocaliques (ex : « Je fais souvent ce rêve étrange et pénétrant »).", "category": "Vocabulaire"},
  {"question": "Qu''est-ce qu''une antithèse ?", "answer": "L''antithèse est une figure d''opposition qui rapproche deux termes ou deux idées contraires dans une même phrase pour créer un contraste saisissant. Exemple : « Je vis, je meurs » (Louise Labé).", "category": "Vocabulaire"}]',
  true, 1);

  -- ============================================================
  -- FRANÇAIS - Chapitre 3 : La Littérature Africaine Francophone
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_francais_id, 'litterature-africaine', 3, 'La Littérature Africaine Francophone', 'Les grands auteurs et mouvements de la littérature africaine d''expression française', 3)
  RETURNING id INTO v_ch_03;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_03, 'litterature-africaine', 'La Littérature Africaine Francophone',
  'La littérature africaine francophone s''est développée au XXe siècle autour de mouvements majeurs comme la Négritude. De Senghor à Kourouma, en passant par Mariama Bâ et Hampaté Bâ, elle exprime les réalités africaines, la quête identitaire et la critique sociale.',
  '{"key_points": ["La Négritude : mouvement fondateur porté par Senghor, Césaire et Damas", "Léopold Sédar Senghor : poète de la Négritude et chantre de la civilisation africaine", "Ahmadou Kourouma : renouveau du roman africain avec une écriture subversive", "Mariama Bâ : voix féminine engagée contre la polygamie et les traditions oppressives", "Amadou Hampâté Bâ : défenseur de la tradition orale et des savoirs ancestraux", "Camara Laye : autobiographie et nostalgie de l''Afrique traditionnelle", "La littérature africaine entre tradition et modernité, oralité et écriture"], "content": "## Les origines : la Négritude\n\nLa **Négritude** est un mouvement littéraire et intellectuel né dans les années 1930 à Paris. Ses fondateurs sont **Léopold Sédar Senghor** (Sénégal), **Aimé Césaire** (Martinique) et **Léon-Gontran Damas** (Guyane). Ce mouvement vise à :\n- **Réhabiliter** la culture et l''identité noires face au colonialisme\n- **Affirmer** la dignité des peuples noirs\n- **Revaloriser** les traditions, l''art et la spiritualité africains\n\nSenghor définit la Négritude comme « l''ensemble des valeurs culturelles du monde noir ».\n\n## Les grands auteurs\n\n### Léopold Sédar Senghor (1906-2001)\n- Poète, homme d''État, premier président du Sénégal\n- Œuvres majeures : *Chants d''ombre* (1945), *Hosties noires* (1948), *Éthiopiques* (1956)\n- Thèmes : l''Afrique natale, le métissage culturel, la femme noire, le dialogue des civilisations\n- Style : rythme poétique inspiré des chants traditionnels africains\n\n### Aimé Césaire (1913-2008)\n- Poète et dramaturge martiniquais, voix de la révolte anticoloniale\n- Œuvre fondatrice : *Cahier d''un retour au pays natal* (1939)\n- Style engagé, surréaliste et incandescent\n\n### Ahmadou Kourouma (1927-2003)\n- Romancier ivoirien, révolutionnaire de l''écriture romanesque africaine\n- Œuvres : *Les Soleils des indépendances* (1968), *Allah n''est pas obligé* (2000)\n- Innovation : intégration de la syntaxe malinké dans le français, ironie et satire politique\n\n### Mariama Bâ (1929-1981)\n- Romancière sénégalaise, féministe engagée\n- Œuvre majeure : *Une si longue lettre* (1979)\n- Thèmes : la condition de la femme africaine, la polygamie, l''éducation des filles\n\n### Amadou Hampâté Bâ (1900-1991)\n- Écrivain et ethnologue malien, défenseur de la tradition orale\n- Citation célèbre : « En Afrique, quand un vieillard meurt, c''est une bibliothèque qui brûle »\n- Œuvres : *L''Étrange destin de Wangrin* (1973), *Amkoullel, l''enfant peul* (1991)\n\n### Camara Laye (1928-1980)\n- Écrivain guinéen, pionnier du roman autobiographique africain\n- Œuvre majeure : *L''Enfant noir* (1953)\n- Thèmes : nostalgie de l''enfance, vie traditionnelle, passage à la modernité\n\n## Les thèmes récurrents\n- La **quête identitaire** face à la colonisation et à la mondialisation\n- Le **conflit tradition/modernité**\n- La **condition féminine** en Afrique\n- La **critique politique** des régimes postcoloniaux\n- L''**oralité** comme source d''inspiration littéraire"}',
  '[{"question": "Qui sont les trois fondateurs du mouvement de la Négritude ?", "options": ["Kourouma, Camara Laye, Hampâté Bâ", "Senghor, Césaire, Damas", "Mariama Bâ, Ousmane Sembène, Mongo Beti", "Soyinka, Achebe, Ngũgĩ"], "correct": 1, "explanation": "La Négritude a été fondée dans les années 1930 par Léopold Sédar Senghor (Sénégal), Aimé Césaire (Martinique) et Léon-Gontran Damas (Guyane), tous trois étudiants à Paris."},
  {"question": "Quelle est l''œuvre majeure de Mariama Bâ ?", "options": ["L''Enfant noir", "Les Soleils des indépendances", "Une si longue lettre", "Cahier d''un retour au pays natal"], "correct": 2, "explanation": "Une si longue lettre (1979) est le roman le plus célèbre de Mariama Bâ. C''est une lettre-roman qui dénonce la polygamie et la condition de la femme dans la société sénégalaise."},
  {"question": "Quelle est la particularité stylistique d''Ahmadou Kourouma ?", "options": ["Il écrit en vers classiques français", "Il intègre la syntaxe malinké dans le français", "Il n''utilise que le style oral traditionnel", "Il écrit exclusivement en langue africaine"], "correct": 1, "explanation": "Kourouma a révolutionné le roman africain en intégrant la syntaxe et les tournures de la langue malinké dans son écriture en français, créant un style unique et subversif."},
  {"question": "Quelle célèbre citation est attribuée à Amadou Hampâté Bâ ?", "options": ["L''existence précède l''essence", "Je pense, donc je suis", "En Afrique, quand un vieillard meurt, c''est une bibliothèque qui brûle", "L''homme est un loup pour l''homme"], "correct": 2, "explanation": "Cette citation prononcée à l''UNESCO en 1960 illustre l''importance de la tradition orale en Afrique et le rôle des anciens comme dépositaires du savoir collectif."},
  {"question": "Quel thème central traverse L''Enfant noir de Camara Laye ?", "options": ["La révolte politique", "La nostalgie de l''enfance et la vie traditionnelle", "La guerre civile", "La vie urbaine moderne"], "correct": 1, "explanation": "L''Enfant noir est un roman autobiographique dans lequel Camara Laye évoque avec nostalgie son enfance en Guinée, la vie traditionnelle et le passage douloureux vers la modernité."}]',
  '[{"question": "Qu''est-ce que la Négritude ?", "answer": "Mouvement littéraire et intellectuel né dans les années 1930, fondé par Senghor, Césaire et Damas. Il vise à réhabiliter la culture noire, affirmer la dignité des peuples noirs et revaloriser les traditions africaines face au colonialisme.", "category": "Vocabulaire"},
  {"question": "Qui est Léopold Sédar Senghor ?", "answer": "Poète sénégalais (1906-2001), cofondateur de la Négritude et premier président du Sénégal. Œuvres : Chants d''ombre, Hosties noires, Éthiopiques. Il chante l''Afrique, la femme noire et le métissage culturel.", "category": "Vocabulaire"},
  {"question": "Quelle est la contribution d''Ahmadou Kourouma ?", "answer": "Romancier ivoirien (1927-2003) qui a révolutionné le roman africain. Les Soleils des indépendances (1968) intègre la syntaxe malinké dans le français. Il use d''ironie et de satire pour critiquer les pouvoirs postcoloniaux.", "category": "Vocabulaire"},
  {"question": "Pourquoi Mariama Bâ est-elle importante ?", "answer": "Romancière sénégalaise féministe (1929-1981). Une si longue lettre (1979) dénonce la polygamie et les traditions oppressives envers les femmes. Elle est une voix majeure de la littérature féminine africaine.", "category": "Vocabulaire"},
  {"question": "Quel est l''apport d''Amadou Hampâté Bâ ?", "answer": "Écrivain et ethnologue malien (1900-1991), défenseur de la tradition orale africaine. Il a collecté contes, mythes et savoirs ancestraux. Œuvres : L''Étrange destin de Wangrin, Amkoullel l''enfant peul.", "category": "Vocabulaire"}]',
  true, 1);

  -- ============================================================
  -- FRANÇAIS - Chapitre 4 : Les Mouvements Littéraires
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_francais_id, 'mouvements-litteraires', 4, 'Les Mouvements Littéraires', 'Les grands courants littéraires du XVIe au XXe siècle', 4)
  RETURNING id INTO v_ch_04;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_04, 'mouvements-litteraires', 'Les Mouvements Littéraires',
  'Les mouvements littéraires sont des courants esthétiques et intellectuels qui regroupent des auteurs partageant une même vision de la littérature. Du Romantisme au Surréalisme, en passant par le Réalisme et le Naturalisme, chaque mouvement répond au précédent et marque son époque.',
  '{"key_points": ["Le Romantisme : exaltation du moi, de la nature et des sentiments (Hugo, Lamartine, Musset)", "Le Réalisme : représentation fidèle de la société (Balzac, Flaubert, Stendhal)", "Le Naturalisme : approche scientifique de la réalité sociale (Zola, Maupassant)", "Le Symbolisme : suggestion et musicalité poétique (Baudelaire, Verlaine, Rimbaud, Mallarmé)", "Le Surréalisme : exploration de l''inconscient et de l''imaginaire (Breton, Éluard, Aragon)", "La Négritude : réhabilitation de l''identité noire (Senghor, Césaire, Damas)", "Chaque mouvement naît en réaction au précédent et propose une nouvelle esthétique"], "content": "## Les grands mouvements littéraires\n\n### Le Classicisme (XVIIe siècle)\n- **Principes** : imitation des Anciens, respect des règles, raison et mesure\n- **Théâtre** : règle des trois unités (lieu, temps, action)\n- **Auteurs** : Molière, Racine, Corneille, La Fontaine, Boileau\n- **Devise** : « Plaire et instruire »\n\n### Le Romantisme (1820-1850)\n- **Principes** : exaltation du **moi**, des **sentiments**, de la **nature** et de la **liberté** créatrice\n- Réaction contre le rationalisme classique\n- **Auteurs** : Victor Hugo, Lamartine, Alfred de Musset, Chateaubriand\n- **Genres** : poésie lyrique, drame romantique, roman historique\n- Hugo dans la préface de *Cromwell* (1827) : le drame doit mêler le sublime et le grotesque\n\n### Le Réalisme (1850-1890)\n- **Principes** : représentation **fidèle** et **objective** de la réalité sociale\n- Le romancier observe la société comme un scientifique\n- **Auteurs** : Honoré de Balzac (*La Comédie humaine*), Gustave Flaubert (*Madame Bovary*), Stendhal (*Le Rouge et le Noir*)\n- Balzac veut faire « concurrence à l''état civil »\n\n### Le Naturalisme (1870-1900)\n- **Principes** : prolongement du réalisme avec une approche **scientifique** et **expérimentale**\n- Influence de la science et du déterminisme (milieu, hérédité, moment historique)\n- **Auteur principal** : Émile Zola (*Les Rougon-Macquart*, *Germinal*, *L''Assommoir*)\n- Le roman est un « roman expérimental » selon Zola\n\n### Le Symbolisme (1880-1900)\n- **Principes** : la poésie doit **suggérer** plutôt que décrire, musicalité du vers\n- Rejet du réalisme et du positivisme\n- **Auteurs** : Charles Baudelaire (*Les Fleurs du mal*), Paul Verlaine, Arthur Rimbaud, Stéphane Mallarmé\n- Verlaine : « De la musique avant toute chose »\n\n### Le Surréalisme (1920-1940)\n- **Principes** : exploration de l''**inconscient**, de l''**imaginaire** et du **rêve**\n- Écriture automatique, images inattendues, refus de la logique\n- **Auteurs** : André Breton (*Manifeste du surréalisme*, 1924), Paul Éluard, Louis Aragon\n- Influence de la psychanalyse de Freud"}',
  '[{"question": "Quel mouvement littéraire prône l''exaltation du moi et des sentiments ?", "options": ["Le Classicisme", "Le Réalisme", "Le Romantisme", "Le Naturalisme"], "correct": 2, "explanation": "Le Romantisme, né au début du XIXe siècle, se caractérise par l''exaltation du moi, des sentiments, de la nature et de la liberté créatrice, en réaction contre le rationalisme classique."},
  {"question": "Quel auteur est le chef de file du Naturalisme ?", "options": ["Victor Hugo", "Gustave Flaubert", "Émile Zola", "Charles Baudelaire"], "correct": 2, "explanation": "Émile Zola est le chef de file du Naturalisme. Dans Le Roman expérimental (1880), il défend une approche scientifique du roman, influencée par le déterminisme et l''hérédité."},
  {"question": "Quelle règle est caractéristique du théâtre classique ?", "options": ["La liberté totale de création", "La règle des trois unités (lieu, temps, action)", "Le mélange des genres", "L''écriture automatique"], "correct": 1, "explanation": "Le théâtre classique du XVIIe siècle impose la règle des trois unités : unité de lieu (un seul décor), unité de temps (24 heures), unité d''action (une seule intrigue principale)."},
  {"question": "Quel mouvement utilise l''écriture automatique ?", "options": ["Le Romantisme", "Le Réalisme", "Le Symbolisme", "Le Surréalisme"], "correct": 3, "explanation": "Le Surréalisme, fondé par André Breton en 1924, utilise l''écriture automatique pour accéder à l''inconscient. Il s''agit d''écrire sans contrôle de la raison, en laissant libre cours aux associations d''idées."},
  {"question": "Quel poète a dit « De la musique avant toute chose » ?", "options": ["Victor Hugo", "Arthur Rimbaud", "Paul Verlaine", "Stéphane Mallarmé"], "correct": 2, "explanation": "Paul Verlaine ouvre son Art poétique par « De la musique avant toute chose », résumant l''esthétique symboliste qui privilégie la musicalité, la suggestion et le rythme du vers."}]',
  '[{"question": "Quels sont les principes du Réalisme ?", "answer": "Le Réalisme vise la représentation fidèle et objective de la réalité sociale. Le romancier observe et décrit la société telle qu''elle est, sans idéalisation. Auteurs majeurs : Balzac, Flaubert, Stendhal.", "category": "Vocabulaire"},
  {"question": "Quelle est la différence entre Réalisme et Naturalisme ?", "answer": "Le Naturalisme prolonge le Réalisme en ajoutant une dimension scientifique. Zola applique la méthode expérimentale au roman : il étudie l''influence du milieu, de l''hérédité et du moment historique sur les individus.", "category": "Vocabulaire"},
  {"question": "Qu''est-ce que le Symbolisme ?", "answer": "Mouvement poétique (1880-1900) qui refuse la description réaliste. La poésie doit suggérer plutôt que nommer, en privilégiant la musicalité et les images symboliques. Auteurs : Baudelaire, Verlaine, Rimbaud, Mallarmé.", "category": "Vocabulaire"},
  {"question": "Qu''est-ce que le Surréalisme ?", "answer": "Mouvement artistique et littéraire fondé par André Breton en 1924. Il explore l''inconscient, le rêve et l''imaginaire, sous l''influence de Freud. Techniques : écriture automatique, cadavre exquis, collage.", "category": "Vocabulaire"},
  {"question": "Quel est le lien entre chaque mouvement ?", "answer": "Chaque mouvement littéraire naît en réaction au précédent : le Romantisme rejette le Classicisme, le Réalisme s''oppose au Romantisme, le Naturalisme prolonge le Réalisme, le Symbolisme rejette le Naturalisme.", "category": "Vocabulaire"}]',
  true, 1);

  -- ============================================================
  -- FRANÇAIS - Chapitre 5 : La Poésie : Formes et Figures
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_francais_id, 'poesie-formes-figures', 5, 'La Poésie : Formes et Figures', 'Les formes poétiques, la versification et les figures de style', 5)
  RETURNING id INTO v_ch_05;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_05, 'poesie-formes-figures', 'La Poésie : Formes et Figures',
  'La poésie est un art du langage qui joue sur les sonorités, le rythme et les images. Elle repose sur la versification (règles du vers), les formes fixes (sonnet, ballade, ode) et les figures de style pour créer des effets esthétiques et émotionnels.',
  '{"key_points": ["La versification : vers, strophes, rimes (plates, croisées, embrassées)", "Les types de vers : alexandrin (12 syllabes), décasyllabe (10), octosyllabe (8)", "Le sonnet : 2 quatrains + 2 tercets, forme fixe majeure", "Les figures de son : allitération, assonance, paronomase", "Les figures de sens : métaphore, métonymie, synecdoque, oxymore", "Le vers libre et la poésie en prose : rupture avec les formes classiques", "Les registres poétiques : lyrique, épique, élégiaque, satirique"], "content": "## La versification\n\n### Le vers\nLe vers est une unité rythmique définie par le nombre de **syllabes** :\n- **Alexandrin** : 12 syllabes (le vers le plus noble en poésie française)\n- **Décasyllabe** : 10 syllabes\n- **Octosyllabe** : 8 syllabes\n- **Heptasyllabe** : 7 syllabes\n\n### Les règles de décompte des syllabes\n- Le **e muet** se prononce devant une consonne, s''élide devant une voyelle\n- La **diérèse** sépare deux voyelles en deux syllabes (vi-o-lon = 3 syllabes)\n- La **synérèse** réunit deux voyelles en une syllabe (vio-lon = 2 syllabes)\n\n### La rime\n- **Rimes plates** (AABB) : vers qui riment deux par deux\n- **Rimes croisées** (ABAB) : alternance régulière\n- **Rimes embrassées** (ABBA) : encadrement\n- **Rime riche** : 3 sons ou plus en commun\n- **Rime suffisante** : 2 sons en commun\n- **Rime pauvre** : 1 seul son en commun\n\n### La strophe\n- **Distique** : 2 vers\n- **Tercet** : 3 vers\n- **Quatrain** : 4 vers\n- **Quintil** : 5 vers\n- **Sizain** : 6 vers\n\n## Les formes fixes\n\n### Le sonnet\n- 14 vers répartis en **2 quatrains + 2 tercets**\n- Schéma de rimes classique : ABBA ABBA CCD EDE\n- Forme noble de la poésie, pratiquée par Ronsard, Du Bellay, Baudelaire\n\n### L''ode\n- Poème lyrique célébrant un événement ou un sentiment\n- Strophes régulières, ton élevé et enthousiaste\n\n## Les figures de style en poésie\n\n### Figures de son\n- **Allitération** : répétition de consonnes (« Pour qui sont ces serpents qui sifflent... »)\n- **Assonance** : répétition de voyelles\n- **Paronomase** : rapprochement de mots aux sons proches (« Qui se ressemble s''assemble »)\n\n### Figures de sens\n- **Métaphore** : comparaison implicite\n- **Métonymie** : désigner le tout par la partie ou inversement (« boire un verre »)\n- **Oxymore** : alliance de deux mots contradictoires (« cette obscure clarté »)\n- **Synesthésie** : mélange de sensations (« les parfums verts » chez Baudelaire)\n\n### L''enjambement, le rejet et le contre-rejet\n- **Enjambement** : la phrase déborde sur le vers suivant\n- **Rejet** : un mot court est repoussé au début du vers suivant\n- **Contre-rejet** : un élément du vers suivant est anticipé en fin de vers"}',
  '[{"question": "Combien de syllabes compte un alexandrin ?", "options": ["8 syllabes", "10 syllabes", "12 syllabes", "14 syllabes"], "correct": 2, "explanation": "L''alexandrin est un vers de 12 syllabes, considéré comme le vers le plus noble de la poésie française. Il est souvent coupé en deux hémistiches de 6 syllabes par une césure à l''hémistiche."},
  {"question": "Quelle est la structure d''un sonnet ?", "options": ["4 quatrains", "2 quatrains et 2 tercets", "3 tercets et 1 quatrain", "14 tercets"], "correct": 1, "explanation": "Le sonnet est composé de 14 vers répartis en 2 quatrains (4 vers) et 2 tercets (3 vers). C''est une forme fixe majeure, pratiquée par Ronsard, Du Bellay et Baudelaire."},
  {"question": "Comment appelle-t-on des rimes de schéma ABAB ?", "options": ["Rimes plates", "Rimes embrassées", "Rimes croisées", "Rimes libres"], "correct": 2, "explanation": "Les rimes croisées suivent le schéma ABAB, où les vers riment en alternance. Les rimes plates sont AABB et les rimes embrassées sont ABBA."},
  {"question": "Qu''est-ce qu''un oxymore ?", "options": ["Une exagération volontaire", "L''alliance de deux mots contradictoires", "La répétition d''un son consonantique", "Un changement de sens d''un mot"], "correct": 1, "explanation": "L''oxymore est une figure de style qui associe deux termes de sens opposés, créant un effet de surprise. Exemple célèbre : « cette obscure clarté qui tombe des étoiles » (Corneille)."},
  {"question": "Qu''est-ce qu''un enjambement en poésie ?", "options": ["La fin d''une phrase qui coïncide avec la fin du vers", "Le débordement de la phrase sur le vers suivant", "La suppression d''une syllabe", "La répétition d''un vers entier"], "correct": 1, "explanation": "L''enjambement se produit quand la phrase ne s''arrête pas à la fin du vers mais continue sur le vers suivant, créant un effet de continuité ou de fluidité."}]',
  '[{"question": "Qu''est-ce que la diérèse ?", "answer": "La diérèse consiste à prononcer en deux syllabes distinctes deux voyelles qui normalement n''en forment qu''une. Exemple : « vi-o-lon » au lieu de « vio-lon ». Elle permet d''allonger le vers.", "category": "Vocabulaire"},
  {"question": "Qu''est-ce qu''une rime riche ?", "answer": "Une rime riche est une rime comportant trois sons ou plus en commun entre les deux mots qui riment. Exemple : « tendresse / caresse » (r-è-s). Plus une rime a de sons communs, plus elle est considérée riche.", "category": "Vocabulaire"},
  {"question": "Qu''est-ce que la métonymie ?", "answer": "La métonymie est une figure de style qui consiste à désigner un objet par un autre qui lui est lié par un rapport logique : le contenant pour le contenu (« boire un verre »), l''auteur pour l''œuvre (« lire un Molière »).", "category": "Vocabulaire"},
  {"question": "Qu''est-ce que la synesthésie ?", "answer": "La synesthésie est une figure de style qui associe des sensations appartenant à des domaines sensoriels différents. Exemple : « les parfums verts » (odorat + vue) chez Baudelaire dans Correspondances.", "category": "Vocabulaire"},
  {"question": "Quelle est la différence entre rejet et contre-rejet ?", "answer": "Le rejet : un élément court de la phrase est repoussé au début du vers suivant, créant un effet de mise en relief. Le contre-rejet : un élément du vers suivant est anticipé à la fin du vers précédent.", "category": "Vocabulaire"}]',
  true, 1);

  -- ============================================================
  -- FRANÇAIS - Chapitre 6 : Le Théâtre Classique et Moderne
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_francais_id, 'theatre-classique-moderne', 6, 'Le Théâtre Classique et Moderne', 'Du théâtre classique au théâtre contemporain africain', 6)
  RETURNING id INTO v_ch_06;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_06, 'theatre-classique-moderne', 'Le Théâtre Classique et Moderne',
  'Le théâtre est un genre littéraire destiné à la représentation. Du théâtre classique français (Molière, Racine, Corneille) au théâtre moderne et africain, il évolue dans ses formes, ses règles et ses thématiques tout en conservant sa fonction de miroir de la société.',
  '{"key_points": ["Le théâtre classique : règle des trois unités, bienséance, vraisemblance", "La tragédie classique : héros nobles face à la fatalité (Racine, Corneille)", "La comédie classique : correction des mœurs par le rire (Molière)", "Le drame romantique : rupture avec les règles classiques (Hugo)", "Le théâtre de l''absurde : Beckett, Ionesco, crise du langage et du sens", "Le théâtre africain : engagement politique et social (Soyinka, Césaire)", "Les éléments de l''analyse théâtrale : didascalies, monologue, aparté, quiproquo"], "content": "## Le théâtre classique (XVIIe siècle)\n\n### Les règles classiques\n- **Règle des trois unités** : unité de lieu, de temps (24h), d''action\n- **Bienséance** : ne pas montrer de violence ni de mort sur scène\n- **Vraisemblance** : l''action doit être crédible\n- **Séparation des genres** : tragédie et comédie ne se mélangent pas\n\n### La tragédie\n- Personnages **nobles** (rois, princes, héros mythologiques)\n- Thèmes : la **fatalité**, le **devoir** contre la **passion**, l''honneur\n- Dénouement **malheureux** (mort du héros)\n- **Racine** : *Phèdre*, *Andromaque*, *Britannicus* — la passion destructrice\n- **Corneille** : *Le Cid*, *Horace*, *Cinna* — le dilemme entre devoir et amour\n\n### La comédie\n- Personnages **ordinaires** (bourgeois, valets, marchands)\n- But : **corriger les mœurs par le rire** (castigat ridendo mores)\n- **Molière** : *L''Avare*, *Le Tartuffe*, *Le Misanthrope*, *Le Malade imaginaire*\n- Procédés comiques : **quiproquo**, **ironie**, **satire**, **comique de gestes**\n\n## Le drame romantique (XIXe siècle)\n\n- **Victor Hugo** : préface de *Cromwell* (1827), manifeste du drame romantique\n- **Rupture avec les règles classiques** : mélange des genres, du sublime et du grotesque\n- Liberté de lieu, de temps et d''action\n- Œuvres : *Hernani* (1830), *Ruy Blas* (1838)\n\n## Le théâtre moderne et contemporain\n\n### Le théâtre de l''absurde (XXe siècle)\n- **Crise du sens** : le langage ne communique plus, l''existence est absurde\n- **Samuel Beckett** : *En attendant Godot* (1953) — l''attente sans fin\n- **Eugène Ionesco** : *La Cantatrice chauve* (1950) — la vacuité du langage\n- Remise en question des conventions théâtrales\n\n### Le théâtre africain\n- **Wole Soyinka** (Nigeria) : théâtre engagé, entre traditions yoruba et modernité\n- **Aimé Césaire** : *La Tragédie du roi Christophe* (1963), *Une tempête* (1969)\n- Thèmes : décolonisation, pouvoir, identité africaine\n\n## Vocabulaire de l''analyse théâtrale\n- **Didascalie** : indication scénique de l''auteur (décor, gestes, ton)\n- **Monologue** : un personnage parle seul sur scène\n- **Aparté** : parole adressée au public, inaudible pour les autres personnages\n- **Quiproquo** : malentendu entre personnages, source de comique\n- **Tirade** : longue réplique d''un personnage"}',
  '[{"question": "Quelle règle impose que l''action se déroule en 24 heures maximum ?", "options": ["La règle de bienséance", "L''unité de temps", "L''unité de lieu", "La vraisemblance"], "correct": 1, "explanation": "L''unité de temps exige que l''action de la pièce se déroule en 24 heures maximum. C''est l''une des trois unités du théâtre classique avec l''unité de lieu et l''unité d''action."},
  {"question": "Quel auteur a écrit la préface de Cromwell, manifeste du drame romantique ?", "options": ["Racine", "Molière", "Victor Hugo", "Corneille"], "correct": 2, "explanation": "Victor Hugo a écrit la préface de Cromwell en 1827, véritable manifeste du drame romantique. Il y préconise le mélange du sublime et du grotesque et rejette les règles classiques."},
  {"question": "Quel est le but de la comédie selon la tradition classique ?", "options": ["Faire pleurer le public", "Corriger les mœurs par le rire", "Raconter des histoires mythologiques", "Célébrer les héros"], "correct": 1, "explanation": "La comédie classique vise à corriger les mœurs par le rire (castigat ridendo mores). Molière dénonce les travers humains comme l''avarice, l''hypocrisie ou la vanité pour les corriger."},
  {"question": "Qu''est-ce qu''un aparté au théâtre ?", "options": ["Un long discours d''un personnage", "Une parole adressée au public, inaudible pour les autres personnages", "Un combat entre deux personnages", "Un changement de décor"], "correct": 1, "explanation": "L''aparté est une convention théâtrale par laquelle un personnage s''adresse directement au public, ses paroles étant censées être inaudibles pour les autres personnages sur scène."},
  {"question": "Quel dramaturge africain a écrit La Tragédie du roi Christophe ?", "options": ["Wole Soyinka", "Aimé Césaire", "Léopold Sédar Senghor", "Ahmadou Kourouma"], "correct": 1, "explanation": "Aimé Césaire a écrit La Tragédie du roi Christophe (1963), pièce qui traite du pouvoir et de la décolonisation à travers l''histoire du roi d''Haïti Henri Christophe."}]',
  '[{"question": "Qu''est-ce qu''une didascalie ?", "answer": "Une didascalie est une indication scénique écrite par l''auteur, qui ne fait pas partie du dialogue. Elle précise le décor, les gestes, les déplacements, le ton ou les costumes des personnages.", "category": "Vocabulaire"},
  {"question": "Quelle est la différence entre tragédie et comédie classiques ?", "answer": "La tragédie met en scène des personnages nobles face à la fatalité, avec un dénouement malheureux. La comédie met en scène des personnages ordinaires dans des situations drôles, avec un dénouement heureux.", "category": "Vocabulaire"},
  {"question": "Qu''est-ce que le théâtre de l''absurde ?", "answer": "Courant théâtral du XXe siècle (Beckett, Ionesco) qui remet en question le sens de l''existence et du langage. Les dialogues sont incohérents, l''action est circulaire, les personnages sont désorientés.", "category": "Vocabulaire"},
  {"question": "Qu''est-ce qu''un quiproquo ?", "answer": "Le quiproquo est un procédé comique fondé sur un malentendu : un personnage prend une personne ou une situation pour une autre. C''est une source majeure de comique dans les comédies de Molière.", "category": "Vocabulaire"},
  {"question": "Qu''est-ce que le drame romantique ?", "answer": "Genre théâtral créé par Victor Hugo au XIXe siècle qui rompt avec les règles classiques. Il mélange le sublime et le grotesque, la prose et le vers, la comédie et la tragédie.", "category": "Vocabulaire"}]',
  true, 1);

  -- ============================================================
  -- FRANÇAIS - Chapitre 7 : Le Roman : Analyse Narrative
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_francais_id, 'roman-analyse-narrative', 7, 'Le Roman : Analyse Narrative', 'Les techniques narratives et l''analyse du roman', 7)
  RETURNING id INTO v_ch_07;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_07, 'roman-analyse-narrative', 'Le Roman : Analyse Narrative',
  'Le roman est le genre littéraire le plus lu et le plus varié. Son analyse repose sur l''étude des techniques narratives : le point de vue du narrateur, la structure du récit, la construction des personnages et les registres employés par l''auteur.',
  '{"key_points": ["Les points de vue narratifs : interne, externe, omniscient", "Le schéma narratif : situation initiale, élément perturbateur, péripéties, dénouement, situation finale", "Le schéma actantiel : sujet, objet, adjuvants, opposants, destinateur, destinataire", "Les types de narrateur : homodiégétique (je) et hétérodiégétique (il)", "Les temps du récit : passé simple (premier plan), imparfait (arrière-plan)", "Les formes de discours : direct, indirect, indirect libre", "L''incipit et l''excipit : entrée et sortie du récit"], "content": "## Les techniques narratives\n\n### Le narrateur\nLe narrateur est celui qui raconte l''histoire. Il ne se confond pas toujours avec l''auteur.\n\n- **Narrateur homodiégétique** : il est un personnage de l''histoire, il dit « je »\n  - Exemple : Camara Laye dans *L''Enfant noir*\n- **Narrateur hétérodiégétique** : il est extérieur à l''histoire, il utilise « il/elle »\n  - Exemple : le narrateur de *Germinal* de Zola\n\n### Les points de vue (focalisations)\n- **Focalisation interne** : le récit est filtré par la perception d''un personnage. Le lecteur sait ce que le personnage voit, pense et ressent.\n- **Focalisation externe** : le narrateur décrit de l''extérieur, comme une caméra. Il ne connaît pas les pensées des personnages.\n- **Focalisation zéro (omnisciente)** : le narrateur sait tout — pensées, passé, avenir de tous les personnages.\n\n### Le schéma narratif\nTout récit suit une progression en cinq étapes :\n1. **Situation initiale** : présentation du cadre et des personnages\n2. **Élément perturbateur** : événement qui rompt l''équilibre\n3. **Péripéties** : enchaînement d''actions et de complications\n4. **Dénouement** : résolution du conflit\n5. **Situation finale** : nouvel équilibre\n\n### Le schéma actantiel (Greimas)\nAnalyse les forces en jeu dans le récit :\n- **Sujet** : le personnage principal qui agit\n- **Objet** : ce qu''il cherche à obtenir\n- **Destinateur** : ce qui pousse le sujet à agir\n- **Destinataire** : celui qui bénéficie de l''action\n- **Adjuvants** : ceux qui aident le sujet\n- **Opposants** : ceux qui s''opposent au sujet\n\n### Les temps du récit\n- **Passé simple** : actions de premier plan, événements ponctuels\n- **Imparfait** : arrière-plan, descriptions, habitudes\n- **Plus-que-parfait** : antériorité par rapport au récit\n- **Présent de narration** : rendre l''action plus vivante\n\n### Les formes de discours rapporté\n- **Discours direct** : les paroles sont rapportées telles quelles (avec guillemets)\n- **Discours indirect** : les paroles sont intégrées au récit (« il dit que... »)\n- **Discours indirect libre** : mélange entre narration et pensée du personnage, sans marques typographiques\n\n### L''incipit et l''excipit\n- **Incipit** : les premières lignes du roman, qui doivent accrocher le lecteur\n- **Excipit** : les dernières lignes, qui clôturent le récit (fin ouverte ou fermée)"}',
  '[{"question": "Quel point de vue permet au narrateur de connaître les pensées de tous les personnages ?", "options": ["La focalisation interne", "La focalisation externe", "La focalisation zéro (omnisciente)", "Le point de vue subjectif"], "correct": 2, "explanation": "La focalisation zéro, ou point de vue omniscient, permet au narrateur de tout savoir sur les personnages : leurs pensées, leurs sentiments, leur passé et même leur avenir."},
  {"question": "Quel est l''élément qui déclenche l''action dans le schéma narratif ?", "options": ["La situation initiale", "L''élément perturbateur", "Le dénouement", "La situation finale"], "correct": 1, "explanation": "L''élément perturbateur est l''événement qui rompt l''équilibre de la situation initiale et déclenche les péripéties du récit. Sans lui, il n''y aurait pas d''histoire."},
  {"question": "Comment appelle-t-on un narrateur qui est aussi personnage de l''histoire ?", "options": ["Narrateur hétérodiégétique", "Narrateur omniscient", "Narrateur homodiégétique", "Narrateur externe"], "correct": 2, "explanation": "Le narrateur homodiégétique participe à l''histoire qu''il raconte, il utilise le « je ». Par opposition, le narrateur hétérodiégétique est extérieur à l''histoire."},
  {"question": "Dans le schéma actantiel, qui aide le sujet dans sa quête ?", "options": ["Les opposants", "Les adjuvants", "Le destinateur", "Le destinataire"], "correct": 1, "explanation": "Les adjuvants sont les personnages, les objets ou les forces qui aident le sujet à atteindre son objectif. Ils s''opposent aux opposants qui font obstacle à la quête."},
  {"question": "Qu''est-ce que le discours indirect libre ?", "options": ["Les paroles entre guillemets", "Un mélange de narration et de pensée du personnage sans guillemets", "Un monologue intérieur classique", "Une description du décor"], "correct": 1, "explanation": "Le discours indirect libre rapporte les pensées ou paroles d''un personnage en les intégrant à la narration sans guillemets ni verbe introducteur. C''est un procédé très utilisé par Flaubert."}]',
  '[{"question": "Qu''est-ce que l''incipit d''un roman ?", "answer": "L''incipit désigne les premières lignes ou les premières pages d''un roman. Il a pour fonction d''accrocher le lecteur, de présenter le cadre spatio-temporel, les personnages et de donner le ton du récit.", "category": "Vocabulaire"},
  {"question": "Quels sont les trois types de focalisation ?", "answer": "Focalisation interne (vision limitée à un personnage), focalisation externe (vision de l''extérieur, comme une caméra) et focalisation zéro ou omnisciente (le narrateur sait tout sur tous).", "category": "Vocabulaire"},
  {"question": "Qu''est-ce que le schéma actantiel ?", "answer": "Modèle d''analyse narrative de Greimas avec 6 forces : le sujet (qui agit), l''objet (ce qu''il cherche), le destinateur (qui l''envoie), le destinataire (qui bénéficie), les adjuvants (qui aident), les opposants (qui font obstacle).", "category": "Vocabulaire"},
  {"question": "Quel est le rôle du passé simple dans le récit ?", "answer": "Le passé simple exprime les actions de premier plan : événements ponctuels, achevés, qui font avancer l''intrigue. Il s''oppose à l''imparfait qui décrit l''arrière-plan (décors, habitudes, états).", "category": "Vocabulaire"},
  {"question": "Qu''est-ce qu''un excipit ?", "answer": "L''excipit désigne les dernières lignes du roman. Il peut proposer une fin fermée (tout est résolu) ou une fin ouverte (le lecteur imagine la suite). Il fait écho à l''incipit et clôt le récit.", "category": "Vocabulaire"}]',
  true, 1);

  -- ============================================================
  -- ANGLAIS LV1 - Chapter 1: Essay Writing & Argumentation
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_anglais_lv1_id, 'essay-writing-argumentation', 1, 'Essay Writing & Argumentation', 'Structure, techniques and strategies for writing academic essays', 1)
  RETURNING id INTO v_ch_08;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_08, 'essay-writing-argumentation', 'Essay Writing & Argumentation',
  'Essay writing is a fundamental skill for the Baccalaureate English exam. A well-structured essay includes a clear thesis statement, well-developed body paragraphs with evidence and analysis, and a compelling conclusion that ties everything together.',
  '{"key_points": ["Understand the essay prompt and identify the type of essay required", "Write a strong thesis statement that presents your main argument", "Structure body paragraphs using the PEEL method: Point, Evidence, Explanation, Link", "Use transition words and phrases to ensure coherence and flow", "Develop arguments with specific examples and evidence", "Write an effective introduction with a hook and clear thesis", "Craft a conclusion that summarizes key points and provides a final thought"], "content": "## What is an Academic Essay?\n\nAn academic essay is a structured piece of writing that presents a **clear argument** or analysis on a given topic. It requires **critical thinking**, **logical organization** and **effective use of evidence**.\n\n## Types of Essays\n\n### Argumentative Essay\n- Presents a **thesis** and defends it with evidence\n- Acknowledges and refutes **counterarguments**\n- Goal: persuade the reader to agree with your position\n\n### Expository Essay\n- Explains or informs about a topic **objectively**\n- Does not include personal opinions\n- Uses facts, statistics and examples\n\n### Comparative Essay\n- Analyzes **similarities and differences** between two subjects\n- Can be organized point-by-point or block-by-block\n\n## Essay Structure\n\n### 1. Introduction\n- **Hook**: an attention-grabbing opening (quote, question, surprising fact)\n- **Background**: brief context about the topic\n- **Thesis statement**: the main argument in one or two sentences\n\n### 2. Body Paragraphs (PEEL Method)\nEach paragraph follows this structure:\n- **Point**: state the main idea of the paragraph (topic sentence)\n- **Evidence**: provide facts, quotes, examples or statistics\n- **Explanation**: analyze the evidence and show how it supports your point\n- **Link**: connect back to the thesis and transition to the next paragraph\n\n### 3. Conclusion\n- **Restate the thesis** in different words\n- **Summarize** the main arguments\n- **Final thought**: a broader reflection, call to action, or question for the reader\n\n## Transition Words and Phrases\n\n### Adding ideas\n- Furthermore, moreover, in addition, additionally, also\n\n### Contrasting\n- However, nevertheless, on the other hand, conversely, although\n\n### Giving examples\n- For instance, for example, such as, to illustrate, namely\n\n### Concluding\n- In conclusion, to sum up, ultimately, in summary, all in all\n\n### Showing cause and effect\n- Therefore, consequently, as a result, thus, hence\n\n## Common Mistakes to Avoid\n- Writing without a clear thesis statement\n- Using informal language or slang\n- Failing to provide evidence for claims\n- Repeating the same argument in different words\n- Writing a conclusion that introduces new ideas"}',
  '[{"question": "What is the purpose of a thesis statement?", "options": ["To summarize the entire essay", "To present the main argument or position of the essay", "To provide background information", "To list all the topics to be discussed"], "correct": 1, "explanation": "The thesis statement presents the main argument or central claim of the essay. It tells the reader what position the writer will defend and guides the direction of the entire essay."},
  {"question": "What does PEEL stand for in essay writing?", "options": ["Paragraph, Essay, Evidence, Logic", "Point, Evidence, Explanation, Link", "Persuade, Explain, Evaluate, List", "Plan, Execute, Edit, Learn"], "correct": 1, "explanation": "PEEL stands for Point (topic sentence), Evidence (supporting facts or quotes), Explanation (analysis of evidence), and Link (connection to the thesis or next paragraph). It is a method for structuring strong body paragraphs."},
  {"question": "Which of the following is an appropriate hook for an essay?", "options": ["My essay is about education", "In this essay I will discuss...", "Did you know that over 70 million children worldwide lack access to education?", "Education is important"], "correct": 2, "explanation": "A hook should grab the reader''s attention. A surprising statistic or thought-provoking question is much more effective than a generic statement like ''My essay is about...'' or ''Education is important''."},
  {"question": "Which transition word is used to introduce a contrasting idea?", "options": ["Furthermore", "However", "Moreover", "In addition"], "correct": 1, "explanation": "''However'' is used to introduce a contrasting or opposing idea. ''Furthermore'', ''moreover'' and ''in addition'' are used to add supporting ideas, not to contrast them."},
  {"question": "What should a conclusion NOT do?", "options": ["Restate the thesis", "Summarize the main arguments", "Introduce new arguments or evidence", "Provide a final thought or reflection"], "correct": 2, "explanation": "A conclusion should never introduce new arguments or evidence. Its purpose is to summarize what has already been discussed, restate the thesis in different words, and leave the reader with a final thought."}]',
  '[{"question": "What is a thesis statement?", "answer": "A thesis statement is a one or two sentence declaration that presents the main argument or claim of an essay. It appears at the end of the introduction and guides the direction of the entire paper.", "category": "Vocabulaire"},
  {"question": "What is a topic sentence?", "answer": "A topic sentence is the first sentence of a body paragraph. It states the main idea of that paragraph and connects it to the overall thesis. Every body paragraph should begin with a clear topic sentence.", "category": "Vocabulaire"},
  {"question": "What are transition words?", "answer": "Transition words and phrases connect ideas between sentences and paragraphs, ensuring smooth flow. Examples: however (contrast), furthermore (addition), therefore (cause/effect), for instance (example).", "category": "Vocabulaire"},
  {"question": "What is a counterargument?", "answer": "A counterargument is an opposing viewpoint that challenges your thesis. In an argumentative essay, acknowledging and refuting counterarguments strengthens your position by showing you have considered multiple perspectives.", "category": "Vocabulaire"},
  {"question": "What is the difference between an argumentative and an expository essay?", "answer": "An argumentative essay presents a thesis and defends it with evidence to persuade the reader. An expository essay explains a topic objectively without taking a personal position, using facts and examples.", "category": "Vocabulaire"}]',
  false, 1);

  -- ============================================================
  -- ANGLAIS LV1 - Chapter 2: Reading Comprehension & Analysis
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_anglais_lv1_id, 'reading-comprehension-analysis', 2, 'Reading Comprehension & Analysis', 'Strategies for understanding and analyzing written texts', 2)
  RETURNING id INTO v_ch_09;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_09, 'reading-comprehension-analysis', 'Reading Comprehension & Analysis',
  'Reading comprehension involves understanding, interpreting and analyzing written texts. It requires identifying the main idea, recognizing the author''s purpose and tone, making inferences, and critically evaluating the text''s arguments and evidence.',
  '{"key_points": ["Identify the main idea and supporting details in a text", "Recognize the author''s purpose: to inform, persuade, entertain or describe", "Understand tone and register: formal, informal, satirical, neutral", "Make inferences by reading between the lines", "Distinguish between fact and opinion in a text", "Analyze text structure: chronological, cause-effect, compare-contrast, problem-solution", "Use context clues to determine the meaning of unfamiliar words"], "content": "## Reading Strategies\n\n### Before Reading\n- **Preview** the text: read the title, headings, introduction and conclusion\n- **Predict** what the text will be about based on visual clues\n- **Activate prior knowledge** about the topic\n\n### During Reading\n- **Identify the main idea**: what is the text primarily about?\n- **Highlight key details** that support the main idea\n- **Annotate** the text: underline important phrases, write notes in the margins\n- **Ask questions** as you read: Who? What? When? Where? Why? How?\n\n### After Reading\n- **Summarize** the text in your own words\n- **Evaluate** the author''s arguments and evidence\n- **Connect** the text to your own knowledge and experience\n\n## Author''s Purpose\n\nEvery text is written with a specific purpose:\n- **To inform**: presents facts and information objectively (news articles, textbooks)\n- **To persuade**: tries to convince the reader to adopt a viewpoint (editorials, speeches)\n- **To entertain**: aims to engage and amuse the reader (novels, short stories)\n- **To describe**: creates vivid images through descriptive language (travel writing, poetry)\n\n## Tone and Register\n\n**Tone** is the author''s attitude toward the subject:\n- Serious, humorous, critical, sympathetic, ironic, nostalgic, passionate\n\n**Register** is the level of formality:\n- **Formal**: academic papers, official documents (complex sentences, specialized vocabulary)\n- **Informal**: personal letters, blogs (contractions, colloquial language)\n- **Neutral**: news reports (objective, factual language)\n\n## Making Inferences\n\nAn inference is a conclusion drawn from **evidence in the text** combined with **prior knowledge**. The information is not stated directly but **implied**.\n\nExample: \"Sarah slammed the door and threw her bag on the floor.\"\n- Inference: Sarah is angry or upset.\n\n## Fact vs. Opinion\n\n- **Fact**: a statement that can be proven true or false (\"Mali gained independence in 1960\")\n- **Opinion**: a statement that expresses a personal belief or judgment (\"Mali is the most beautiful country in West Africa\")\n- Signal words for opinions: believe, think, feel, should, best, worst, in my view\n\n## Text Structure Patterns\n\n- **Chronological**: events presented in time order\n- **Cause and effect**: explains why something happened and its consequences\n- **Compare and contrast**: examines similarities and differences\n- **Problem and solution**: presents a problem and proposes solutions\n- **Description**: provides detailed characteristics of a subject\n\n## Context Clues for Vocabulary\n\nWhen you encounter an unfamiliar word:\n- **Definition clue**: the meaning is directly stated (\"Photosynthesis, the process by which plants convert sunlight into energy...\")\n- **Synonym clue**: a similar word is nearby (\"The child was jubilant, or overjoyed\")\n- **Antonym clue**: an opposite word provides contrast (\"Unlike the timid cat, the dog was bold\")\n- **Example clue**: examples clarify meaning (\"Citrus fruits such as oranges, lemons and grapefruits\")"}',
  '[{"question": "What is an inference in reading comprehension?", "options": ["A direct quote from the text", "A conclusion drawn from evidence and prior knowledge", "The main idea of a paragraph", "A fact stated explicitly in the text"], "correct": 1, "explanation": "An inference is a conclusion that is not stated directly in the text but can be drawn from evidence in the text combined with the reader''s prior knowledge. It requires reading between the lines."},
  {"question": "Which author''s purpose aims to convince the reader to adopt a viewpoint?", "options": ["To inform", "To entertain", "To persuade", "To describe"], "correct": 2, "explanation": "When the author''s purpose is to persuade, the text tries to convince the reader to agree with a particular opinion or take a specific action. This is common in editorials, speeches and advertisements."},
  {"question": "Which of the following is a fact, not an opinion?", "options": ["English is the most beautiful language in the world", "Shakespeare is the greatest writer of all time", "The Earth orbits the Sun", "Everyone should learn at least two languages"], "correct": 2, "explanation": "''The Earth orbits the Sun'' is a fact because it can be scientifically verified. The other statements express personal beliefs or value judgments and are therefore opinions."},
  {"question": "What type of context clue uses a word with opposite meaning?", "options": ["Definition clue", "Synonym clue", "Antonym clue", "Example clue"], "correct": 2, "explanation": "An antonym clue provides a word with the opposite meaning to help the reader understand the unfamiliar word. For example: ''Unlike the timid cat, the dog was bold'' — ''timid'' helps you understand that ''bold'' means confident or brave."},
  {"question": "Which text structure examines similarities and differences?", "options": ["Chronological", "Cause and effect", "Compare and contrast", "Problem and solution"], "correct": 2, "explanation": "The compare and contrast structure examines similarities and differences between two or more subjects. Signal words include: similarly, likewise, however, on the other hand, in contrast, whereas."}]',
  '[{"question": "What is the main idea of a text?", "answer": "The main idea is the central point or message that the author wants to convey. It is the most important idea that the text is about. Supporting details provide evidence, examples and explanations for the main idea.", "category": "Vocabulaire"},
  {"question": "What is the difference between tone and register?", "answer": "Tone is the author''s attitude toward the subject (e.g., serious, ironic, sympathetic). Register is the level of formality of the language (formal, informal, neutral). Both affect how a message is received.", "category": "Vocabulaire"},
  {"question": "What are context clues?", "answer": "Context clues are hints found in the surrounding text that help the reader determine the meaning of an unfamiliar word. Types include definition clues, synonym clues, antonym clues and example clues.", "category": "Vocabulaire"},
  {"question": "What is skimming vs. scanning?", "answer": "Skimming is reading quickly to get the general idea or gist of a text (reading titles, first sentences). Scanning is searching for specific information (a date, a name, a number) without reading every word.", "category": "Vocabulaire"},
  {"question": "How do you distinguish fact from opinion?", "answer": "A fact is a statement that can be objectively verified as true or false. An opinion expresses a personal belief, judgment or feeling. Signal words for opinions include: believe, think, should, best, worst, in my view.", "category": "Vocabulaire"}]',
  true, 1);

  -- ============================================================
  -- ANGLAIS LV1 - Chapter 3: Grammar & Advanced Structures
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_anglais_lv1_id, 'grammar-advanced-structures', 3, 'Grammar & Advanced Structures', 'Advanced grammar: conditionals, reported speech, passive voice, relative clauses', 3)
  RETURNING id INTO v_ch_10;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_10, 'grammar-advanced-structures', 'Grammar & Advanced Structures',
  'Mastering advanced grammar structures is essential for the Baccalaureate English exam. This chapter covers conditionals, reported speech, the passive voice, relative clauses and other key structures that enable clear and sophisticated writing.',
  '{"key_points": ["The four conditional types: zero, first, second and third conditionals", "Reported speech: transforming direct speech into indirect speech", "The passive voice: formation and usage with different tenses", "Relative clauses: defining and non-defining with who, which, that, whose, where", "Modal verbs: can, could, may, might, must, should, would", "Subject-verb agreement and common grammar pitfalls", "Connectors and linking words for complex sentence construction"], "content": "## Conditional Sentences\n\nConditional sentences express hypothetical situations and their consequences.\n\n### Zero Conditional (general truths)\n- **Structure**: If + present simple, present simple\n- **Example**: If you heat water to 100°C, it boils.\n- **Use**: scientific facts, general truths\n\n### First Conditional (real/possible future)\n- **Structure**: If + present simple, will + infinitive\n- **Example**: If it rains tomorrow, I will stay home.\n- **Use**: likely future situations\n\n### Second Conditional (unreal present/future)\n- **Structure**: If + past simple, would + infinitive\n- **Example**: If I had a million dollars, I would travel the world.\n- **Use**: hypothetical or unlikely situations\n\n### Third Conditional (unreal past)\n- **Structure**: If + past perfect, would have + past participle\n- **Example**: If I had studied harder, I would have passed the exam.\n- **Use**: imagining a different past, expressing regret\n\n## Reported Speech\n\nReported speech (indirect speech) is used to tell someone what another person said.\n\n### Key Changes\n- **Tense shift**: present → past, past → past perfect, will → would\n- **Pronouns**: I → he/she, we → they, my → his/her\n- **Time expressions**: today → that day, tomorrow → the following day, yesterday → the day before\n- **Place**: here → there\n\n### Examples\n- Direct: \"I am studying for the exam,\" she said.\n- Reported: She said that she was studying for the exam.\n- Direct: \"We will arrive tomorrow,\" they told us.\n- Reported: They told us that they would arrive the following day.\n\n### Reporting questions\n- Yes/No questions: He asked **if/whether** I was coming.\n- Wh-questions: She asked **what** I wanted.\n\n## The Passive Voice\n\nThe passive voice emphasizes the **action** rather than the **doer**.\n\n### Formation: Subject + be + past participle (+ by agent)\n\n| Tense | Active | Passive |\n|-------|--------|---------|\n| Present simple | They clean the room | The room **is cleaned** |\n| Past simple | She wrote the letter | The letter **was written** |\n| Present perfect | They have built a school | A school **has been built** |\n| Future | They will announce the results | The results **will be announced** |\n| Modal | You must complete the form | The form **must be completed** |\n\n### When to use passive\n- The doer is **unknown**: My phone was stolen.\n- The doer is **obvious**: The suspect was arrested. (by the police)\n- To emphasize the **result**: The bridge was built in 2010.\n\n## Relative Clauses\n\n### Defining Relative Clauses (essential information)\n- **Who/that**: for people — The student **who** passed is my friend.\n- **Which/that**: for things — The book **which** I read was excellent.\n- **Where**: for places — The school **where** I study is in Bamako.\n- **Whose**: for possession — The teacher **whose** class I attend is brilliant.\n\n### Non-defining Relative Clauses (extra information)\n- Use commas: My brother, **who** lives in Dakar, is a doctor.\n- Cannot use **that** in non-defining clauses\n- Can be removed without changing the meaning of the sentence\n\n## Modal Verbs\n\n- **Can/could**: ability, permission, possibility\n- **May/might**: possibility, permission (more formal)\n- **Must**: obligation, strong deduction\n- **Should**: advice, recommendation\n- **Would**: polite requests, hypothetical situations"}',
  '[{"question": "Which conditional is used for hypothetical past situations?", "options": ["Zero conditional", "First conditional", "Second conditional", "Third conditional"], "correct": 3, "explanation": "The third conditional (If + past perfect, would have + past participle) is used to talk about hypothetical situations in the past — things that did not actually happen. Example: If I had known, I would have helped."},
  {"question": "In reported speech, what happens to the present tense?", "options": ["It stays in the present", "It changes to the past tense", "It changes to the future tense", "It changes to the present perfect"], "correct": 1, "explanation": "In reported speech, the present tense shifts back to the past tense. For example: ''I am happy'' becomes ''She said she was happy.'' This is called backshift."},
  {"question": "How is the passive voice formed?", "options": ["Subject + have + past participle", "Subject + be + past participle", "Subject + do + infinitive", "Subject + be + present participle"], "correct": 1, "explanation": "The passive voice is formed with the appropriate form of ''be'' + past participle. For example: ''The letter was written by Maria.'' The form of ''be'' changes according to the tense."},
  {"question": "Which relative pronoun is used for possession?", "options": ["Who", "Which", "Where", "Whose"], "correct": 3, "explanation": "''Whose'' is the relative pronoun used to express possession. Example: ''The student whose book I borrowed is absent.'' It replaces possessive forms like his, her, their."},
  {"question": "What is the structure of the second conditional?", "options": ["If + present simple, will + infinitive", "If + past simple, would + infinitive", "If + past perfect, would have + past participle", "If + present simple, present simple"], "correct": 1, "explanation": "The second conditional uses ''If + past simple, would + infinitive'' to express hypothetical or unlikely present/future situations. Example: ''If I were rich, I would buy a house.''"}]',
  '[{"question": "What is the zero conditional used for?", "answer": "The zero conditional (If + present simple, present simple) is used for general truths and scientific facts. Both clauses are in the present simple. Example: If you mix red and blue, you get purple.", "category": "Vocabulaire"},
  {"question": "How do you report a yes/no question?", "answer": "Use ''if'' or ''whether'' after the reporting verb, followed by subject + verb (not question word order). Example: ''Are you coming?'' becomes ''He asked if/whether I was coming.''", "category": "Vocabulaire"},
  {"question": "What is the difference between defining and non-defining relative clauses?", "answer": "Defining clauses give essential information and have no commas (The man who called is my father). Non-defining clauses give extra, non-essential information and use commas (My father, who is 60, is a teacher).", "category": "Vocabulaire"},
  {"question": "When should you use the passive voice?", "answer": "Use the passive when: the doer is unknown (My wallet was stolen), the doer is obvious (The suspect was arrested), or you want to emphasize the action/result rather than the person who did it.", "category": "Vocabulaire"},
  {"question": "What is backshift in reported speech?", "answer": "Backshift is the tense change that occurs when converting direct speech to reported speech. Present becomes past, past becomes past perfect, will becomes would. Example: ''I will go'' → She said she would go.", "category": "Vocabulaire"}]',
  true, 1);

  -- ============================================================
  -- ANGLAIS LV1 - Chapter 4: Literature & Cultural Studies
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_anglais_lv1_id, 'literature-cultural-studies', 4, 'Literature & Cultural Studies', 'Major works and themes in English and African literature', 4)
  RETURNING id INTO v_ch_11;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_11, 'literature-cultural-studies', 'Literature & Cultural Studies',
  'Studying literature in English opens a window onto diverse cultures and human experiences. From Shakespeare to Chinua Achebe and Chimamanda Ngozi Adichie, literary works explore universal themes such as identity, power, justice, love and the tension between tradition and modernity.',
  '{"key_points": ["William Shakespeare: the greatest English-language playwright and poet", "Chinua Achebe: father of modern African literature in English", "Chimamanda Ngozi Adichie: contemporary voice on identity, feminism and migration", "George Orwell: political allegory and dystopian fiction", "Key literary terms: protagonist, antagonist, theme, symbol, irony", "African literature in English: colonial and postcolonial themes", "How to analyze a literary text: character, setting, plot, themes and style"], "content": "## Major Authors and Works\n\n### William Shakespeare (1564-1616)\nShakespeare is widely regarded as the greatest writer in the English language.\n\n- **Tragedies**: *Hamlet*, *Macbeth*, *Othello*, *Romeo and Juliet*, *King Lear*\n- **Comedies**: *A Midsummer Night''s Dream*, *The Merchant of Venice*, *Twelfth Night*\n- **Key themes**: ambition, jealousy, love, fate, betrayal, appearance vs. reality\n- **Legacy**: invented over 1,700 words, his plays are still performed worldwide\n\n### Chinua Achebe (1930-2013)\nNigerian novelist, considered the **father of modern African literature** in English.\n\n- **Major work**: *Things Fall Apart* (1958)\n  - Story of Okonkwo, an Igbo leader whose world collapses with the arrival of European colonizers\n  - Themes: tradition vs. change, colonialism, masculinity, cultural identity\n- **Other works**: *No Longer at Ease*, *Arrow of God*, *A Man of the People*\n- **Significance**: showed that African stories could be told in English with dignity and complexity\n\n### Chimamanda Ngozi Adichie (born 1977)\nNigerian author and one of the most prominent contemporary African writers.\n\n- **Major works**: *Purple Hibiscus* (2003), *Half of a Yellow Sun* (2006), *Americanah* (2013)\n- **Key themes**: identity, feminism, immigration, cultural dislocation, the Nigerian Civil War\n- **Famous speech**: *The Danger of a Single Story* (TED Talk, 2009) — warns against reducing people and cultures to a single narrative\n- **Feminist essay**: *We Should All Be Feminists* (2014)\n\n### George Orwell (1903-1950)\nBritish author known for his political and dystopian fiction.\n\n- **Major works**: *Animal Farm* (1945), *Nineteen Eighty-Four* (1949)\n- *Animal Farm*: an allegorical novella about the Russian Revolution, using farm animals to critique totalitarianism\n- *Nineteen Eighty-Four*: a dystopian novel about surveillance, propaganda and thought control under a totalitarian regime\n- **Key concepts**: Big Brother, Newspeak, doublethink, thoughtcrime\n\n## Literary Analysis Framework\n\n### Key Elements to Analyze\n- **Characters**: protagonist (main character), antagonist (opposing force), character development\n- **Setting**: time and place of the story, how it influences the plot\n- **Plot**: sequence of events (exposition, rising action, climax, falling action, resolution)\n- **Themes**: the central ideas or messages explored in the work\n- **Point of view**: first person, third person limited, third person omniscient\n- **Style**: the author''s use of language, imagery, symbolism and literary devices\n\n### Key Literary Terms\n- **Irony**: when the opposite of what is expected occurs\n  - Verbal irony: saying the opposite of what you mean\n  - Dramatic irony: the audience knows something the characters do not\n  - Situational irony: events turn out differently than expected\n- **Symbol**: an object or image that represents a deeper meaning\n- **Allegory**: a story with a hidden moral or political meaning\n- **Foreshadowing**: hints about future events in the story\n- **Motif**: a recurring element that reinforces a theme"}',
  '[{"question": "Who wrote Things Fall Apart?", "options": ["Wole Soyinka", "Chinua Achebe", "Chimamanda Ngozi Adichie", "Ngugi wa Thiong''o"], "correct": 1, "explanation": "Chinua Achebe wrote Things Fall Apart in 1958. It tells the story of Okonkwo, an Igbo leader, and the devastating impact of European colonialism on his community. It is considered a masterpiece of African literature."},
  {"question": "What is the main message of Adichie''s The Danger of a Single Story?", "options": ["Africa needs more technology", "Reducing people or cultures to one narrative is harmful", "English is the best language for literature", "Traditional stories are better than modern ones"], "correct": 1, "explanation": "In her famous TED Talk, Adichie warns against the danger of reducing people, countries or cultures to a single narrative. A single story creates stereotypes and fails to capture the full complexity of human experience."},
  {"question": "What type of literary work is Orwell''s Animal Farm?", "options": ["A romance novel", "A historical biography", "A political allegory", "A science fiction novel"], "correct": 2, "explanation": "Animal Farm is a political allegory that uses a story about farm animals to critique the Russian Revolution and the rise of totalitarianism under Stalin. Each character represents a historical figure or social group."},
  {"question": "What is dramatic irony?", "options": ["When a character says the opposite of what they mean", "When the audience knows something the characters do not", "When events turn out as expected", "When the author uses exaggeration"], "correct": 1, "explanation": "Dramatic irony occurs when the audience or reader knows something important that the characters in the story do not. This creates tension, suspense or humor as the reader watches events unfold."},
  {"question": "Which Shakespeare play tells the story of a Scottish lord driven to murder by ambition?", "options": ["Hamlet", "Othello", "Macbeth", "King Lear"], "correct": 2, "explanation": "Macbeth tells the story of a Scottish general who, driven by ambition and his wife''s manipulation, murders the king to seize power. It explores themes of ambition, guilt, fate and the corrupting nature of power."}]',
  '[{"question": "Who is Chinua Achebe and why is he important?", "answer": "Chinua Achebe (1930-2013) is a Nigerian novelist considered the father of modern African literature in English. His novel Things Fall Apart (1958) was groundbreaking in presenting African life from an African perspective.", "category": "Vocabulaire"},
  {"question": "What is an allegory?", "answer": "An allegory is a narrative in which characters, events and settings represent abstract ideas or moral concepts. The surface story carries a deeper, often political or moral meaning. Example: Orwell''s Animal Farm is an allegory of the Russian Revolution.", "category": "Vocabulaire"},
  {"question": "What is the difference between a protagonist and an antagonist?", "answer": "The protagonist is the main character of a story, the one the reader follows and often sympathizes with. The antagonist is the character or force that opposes the protagonist, creating conflict in the narrative.", "category": "Vocabulaire"},
  {"question": "What are the key themes in Things Fall Apart?", "answer": "Key themes include: the clash between tradition and change, the impact of colonialism on African societies, the struggle for cultural identity, masculinity and its pressures, and the consequences of rigid adherence to custom.", "category": "Vocabulaire"},
  {"question": "What is foreshadowing?", "answer": "Foreshadowing is a literary technique where the author provides hints or clues about future events in the story. It builds suspense and prepares the reader for what is to come without revealing the outcome directly.", "category": "Vocabulaire"}]',
  true, 1);

  -- ============================================================
  -- ANGLAIS LV1 - Chapter 5: Oral Communication & Debate
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_anglais_lv1_id, 'oral-communication-debate', 5, 'Oral Communication & Debate', 'Skills for oral presentations, debates and effective communication', 5)
  RETURNING id INTO v_ch_12;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_12, 'oral-communication-debate', 'Oral Communication & Debate',
  'Oral communication skills are essential for academic success and everyday life. This chapter covers techniques for public speaking, structuring oral presentations, participating in debates, and using persuasive language effectively in English.',
  '{"key_points": ["Structure an oral presentation with a clear introduction, body and conclusion", "Use persuasive techniques: rhetorical questions, repetition, emotive language", "Understand the rules and structure of a formal debate", "Develop active listening skills and appropriate responses", "Use appropriate body language: eye contact, posture, gestures", "Master common debate phrases and expressions for agreeing and disagreeing", "Handle questions and counterarguments with confidence"], "content": "## Oral Presentation Skills\n\n### Structure of a Presentation\n\n#### 1. Introduction\n- **Greet** your audience: \"Good morning, everyone.\"\n- **Introduce** your topic: \"Today, I would like to talk about...\"\n- **State your purpose**: \"The aim of my presentation is to...\"\n- **Outline** the structure: \"First, I will discuss... Then, I will examine... Finally, I will conclude with...\"\n\n#### 2. Body\n- Organize your ideas into **2-3 main points**\n- Use **transitions** between points: \"Moving on to my next point...\", \"Now let us consider...\"\n- Support each point with **evidence, examples or statistics**\n- Speak clearly and at a **moderate pace**\n\n#### 3. Conclusion\n- **Summarize** your main points: \"To sum up...\", \"In conclusion...\"\n- **Restate** your main message\n- **Thank** the audience: \"Thank you for your attention.\"\n- **Invite questions**: \"I would be happy to answer any questions.\"\n\n### Delivery Tips\n- Maintain **eye contact** with the audience\n- Use **gestures** to emphasize key points\n- Vary your **tone and pace** to keep the audience engaged\n- Avoid reading directly from notes — use **key words** instead\n- Practice beforehand to build **confidence**\n\n## Debate Skills\n\n### What is a Debate?\nA formal debate is a structured discussion where two sides argue **for** (proposition) or **against** (opposition) a given motion or statement.\n\n### Debate Structure\n1. **Opening statements**: each side presents their position\n2. **Arguments and rebuttals**: each side presents evidence and responds to the other''s arguments\n3. **Cross-examination**: participants ask questions to challenge opponents\n4. **Closing statements**: each side summarizes their case\n\n### Useful Debate Expressions\n\n#### Expressing agreement\n- I completely agree with this statement.\n- I would like to support this argument by saying...\n- That is an excellent point, and I would add that...\n\n#### Expressing disagreement\n- I respectfully disagree because...\n- While I understand your point, I believe that...\n- I would challenge that argument on the grounds that...\n\n#### Presenting an argument\n- My first argument is that...\n- Research has shown that...\n- Statistics indicate that...\n- It is widely acknowledged that...\n\n#### Rebutting an argument\n- However, this argument fails to consider...\n- The evidence actually suggests the opposite...\n- This point is not supported by the facts because...\n\n#### Concluding\n- For all these reasons, I firmly believe that...\n- The evidence overwhelmingly supports the view that...\n- In light of everything discussed, it is clear that...\n\n## Persuasive Language Techniques\n\n- **Rhetorical questions**: questions asked for effect, not for an answer (\"Can we really afford to ignore this problem?\")\n- **Rule of three**: listing three items for emphasis (\"Education is the key to opportunity, progress and equality.\")\n- **Repetition**: repeating key phrases for impact\n- **Emotive language**: words that appeal to emotions (\"devastating\", \"inspiring\", \"unacceptable\")\n- **Direct address**: speaking directly to the audience using \"you\" and \"we\"\n- **Statistics and evidence**: using data to support claims"}',
  '[{"question": "What should you include in the introduction of an oral presentation?", "options": ["Only your name", "A greeting, your topic, purpose and outline", "All your arguments in detail", "A conclusion and thank you"], "correct": 1, "explanation": "A good introduction should include a greeting to the audience, a clear statement of your topic and purpose, and an outline of the main points you will cover. This helps the audience follow your presentation."},
  {"question": "What is the rule of three in persuasive speaking?", "options": ["Speaking for exactly three minutes", "Making three presentations", "Listing three items for emphasis and rhythm", "Asking three questions"], "correct": 2, "explanation": "The rule of three is a persuasive technique where you group ideas, arguments or words in threes for emphasis and rhythm. Example: ''Government of the people, by the people, for the people'' (Abraham Lincoln)."},
  {"question": "In a formal debate, what comes after the opening statements?", "options": ["Closing statements", "Voting", "Arguments and rebuttals", "A break"], "correct": 2, "explanation": "After opening statements, each side presents their arguments supported by evidence and then responds to the opposing side''s arguments through rebuttals. This is the main body of the debate."},
  {"question": "Which expression is appropriate for politely disagreeing?", "options": ["That is completely wrong!", "You do not know what you are talking about", "While I understand your point, I believe that...", "I refuse to listen to this argument"], "correct": 2, "explanation": "''While I understand your point, I believe that...'' is a polite and respectful way to disagree. In formal debates and academic discussions, it is important to acknowledge the other person''s position before presenting your own."},
  {"question": "What is a rhetorical question?", "options": ["A question that requires a detailed answer", "A question asked for effect, not expecting an answer", "A question asked during a quiz", "A question that has no correct answer"], "correct": 1, "explanation": "A rhetorical question is asked for dramatic effect or to make a point, not to get an actual answer. It engages the audience and makes them think. Example: ''How many more lives must be lost before we act?''"}]',
  '[{"question": "How should you handle questions after a presentation?", "answer": "Listen carefully to the question, pause to think before answering, thank the questioner, give a clear and concise answer, and admit if you do not know something rather than making up an answer.", "category": "Vocabulaire"},
  {"question": "What are the key elements of good delivery?", "answer": "Good delivery includes: maintaining eye contact, using natural gestures, speaking at a moderate pace, varying tone and volume, standing with good posture, and avoiding fillers like ''um'' and ''uh''.", "category": "Vocabulaire"},
  {"question": "What is a rebuttal in a debate?", "answer": "A rebuttal is a response to an opponent''s argument that challenges, contradicts or disproves it using evidence and reasoning. An effective rebuttal addresses the specific claims made and explains why they are flawed.", "category": "Vocabulaire"},
  {"question": "What is emotive language?", "answer": "Emotive language consists of words and phrases deliberately chosen to evoke an emotional response from the audience. Examples: devastating, inspiring, unacceptable, heartbreaking. It is a powerful persuasive tool.", "category": "Vocabulaire"},
  {"question": "What is the difference between a debate and a discussion?", "answer": "A debate is a formal, structured argument with defined rules where two sides defend opposing positions. A discussion is a less formal exchange of ideas where participants share views and may reach a consensus.", "category": "Vocabulaire"}]',
  true, 1);

  -- ============================================================
  -- ANGLAIS LV2 - Chapitre 1 : Basic Essay Writing
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_anglais_lv2_id, 'basic-essay-writing', 1, 'Basic Essay Writing', 'Learn to structure and write basic essays in English', 1)
  RETURNING id INTO v_ch_13;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_13, 'basic-essay-writing', 'Basic Essay Writing',
  'Learn the basics of writing a well-structured essay in English. This chapter covers how to organize your ideas into an introduction, body paragraphs and conclusion with clear language.',
  '{"key_points": ["Understand the three-part essay structure: introduction, body, conclusion", "Write a clear thesis statement that states your main idea", "Use topic sentences to start each body paragraph", "Support your ideas with examples and explanations", "Use simple linking words: first, then, however, in conclusion", "Write short, clear sentences to express your ideas", "Always proofread your essay before submitting"], "content": "## What is an Essay?\n\nAn essay is a short piece of writing on a specific topic. It presents your ideas in an **organized** way. A good essay has three main parts.\n\n## The Three Parts of an Essay\n\n### 1. Introduction\nThe introduction is the first paragraph. It should:\n- **Introduce the topic**: Tell the reader what you will write about\n- **Give background information**: Provide context for your topic\n- **State your thesis**: Write one sentence that gives your main idea or opinion\n\n**Example thesis**: \"Education is important because it opens doors to better opportunities.\"\n\n### 2. Body Paragraphs\nThe body is the main part of your essay. It usually has **2 to 3 paragraphs**. Each paragraph should:\n- Start with a **topic sentence** (the main idea of the paragraph)\n- Give **supporting details**: examples, reasons or facts\n- End with a **concluding sentence** that links back to your thesis\n\n**Example topic sentence**: \"First, education helps people find good jobs.\"\n\n### 3. Conclusion\nThe conclusion is the last paragraph. It should:\n- **Summarize** your main points\n- **Restate your thesis** in different words\n- **Give a final thought** or recommendation\n\n## Useful Linking Words\n\n| Purpose | Words |\n|---------|-------|\n| Adding ideas | and, also, in addition, moreover |\n| Giving examples | for example, such as, for instance |\n| Contrasting | but, however, on the other hand |\n| Showing cause | because, since, as a result |\n| Concluding | in conclusion, to sum up, finally |\n\n## Common Mistakes to Avoid\n- Writing very long sentences — keep them **short and clear**\n- Starting every sentence with \"I think\" — vary your sentence beginnings\n- Forgetting to **indent** or separate paragraphs\n- Not having a clear **thesis statement**\n- Using informal language like slang or abbreviations"}',
  '[{"question": "How many main parts does a basic essay have?", "options": ["Two", "Three", "Four", "Five"], "correct": 1, "explanation": "A basic essay has three main parts: the introduction, the body paragraphs, and the conclusion."},
  {"question": "What is a thesis statement?", "options": ["The title of the essay", "A question at the end", "One sentence that states the main idea", "A list of examples"], "correct": 2, "explanation": "A thesis statement is one sentence, usually at the end of the introduction, that clearly states the main idea or argument of the essay."},
  {"question": "What should a topic sentence do?", "options": ["End the paragraph", "Give the main idea of the paragraph", "Ask a question to the reader", "List all the examples"], "correct": 1, "explanation": "A topic sentence starts a body paragraph and tells the reader the main idea that will be developed in that paragraph."},
  {"question": "Which word is used to show contrast?", "options": ["Also", "For example", "However", "In addition"], "correct": 2, "explanation": "''However'' is used to show contrast between two ideas. For example: ''I like summer. However, I prefer spring.''"},
  {"question": "What should the conclusion of an essay do?", "options": ["Introduce a new topic", "Summarize the main points and restate the thesis", "List new examples", "Ask many questions"], "correct": 1, "explanation": "The conclusion should summarize the main points discussed in the body and restate the thesis in different words, giving the reader a sense of closure."}]',
  '[{"question": "What is a thesis statement?", "answer": "A thesis statement is one sentence that clearly states the main idea or argument of the essay. It usually appears at the end of the introduction.", "category": "Vocabulaire"},
  {"question": "What is a topic sentence?", "answer": "A topic sentence is the first sentence of a body paragraph. It tells the reader the main idea of that paragraph.", "category": "Vocabulaire"},
  {"question": "What are linking words?", "answer": "Linking words (also called transition words) are words that connect ideas in an essay. Examples: however, in addition, for example, in conclusion.", "category": "Vocabulaire"},
  {"question": "What does ''to proofread'' mean?", "answer": "To proofread means to carefully read your writing to find and correct mistakes in spelling, grammar and punctuation before submitting.", "category": "Vocabulaire"}]',
  false, 1);

  -- ============================================================
  -- ANGLAIS LV2 - Chapitre 2 : Grammar Essentials
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_anglais_lv2_id, 'grammar-essentials', 2, 'Grammar Essentials', 'Master essential English grammar rules for clear communication', 2)
  RETURNING id INTO v_ch_14;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_14, 'grammar-essentials', 'Grammar Essentials',
  'Master the essential grammar rules of English. This chapter covers verb tenses, subject-verb agreement, articles, prepositions and common grammatical structures needed for clear writing.',
  '{"key_points": ["Use the correct verb tense for each situation (present, past, future)", "Apply subject-verb agreement rules correctly", "Choose between definite (the) and indefinite (a/an) articles", "Use common prepositions of time and place correctly", "Form questions and negative sentences properly", "Understand the difference between countable and uncountable nouns", "Avoid common grammar mistakes made by French speakers"], "content": "## Verb Tenses\n\n### Present Simple\nUsed for **habits, facts and routines**.\n- I **study** English every day.\n- She **goes** to school at 8 a.m.\n- Water **boils** at 100 degrees Celsius.\n\n**Form**: Subject + base verb (add -s/-es for he/she/it)\n\n### Past Simple\nUsed for **completed actions in the past**.\n- I **studied** English yesterday.\n- She **went** to the library last week.\n- They **played** football on Saturday.\n\n**Form**: Subject + verb in past form (-ed for regular verbs)\n\n### Present Continuous\nUsed for actions happening **right now** or **temporary situations**.\n- I **am studying** English at the moment.\n- They **are playing** outside.\n\n**Form**: Subject + am/is/are + verb-ing\n\n### Future Simple\nUsed for **predictions, promises and decisions**.\n- I **will study** harder next term.\n- It **will rain** tomorrow.\n\n**Form**: Subject + will + base verb\n\n## Subject-Verb Agreement\n\nThe verb must **agree** with the subject in number:\n- He **plays** football. (singular = -s)\n- They **play** football. (plural = no -s)\n- The list of items **is** long. (singular subject)\n- The students **are** ready. (plural subject)\n\n## Articles\n\n| Article | Usage | Example |\n|---------|-------|---------|\n| **a** | Before consonant sounds (first mention) | a book, a university |\n| **an** | Before vowel sounds (first mention) | an apple, an hour |\n| **the** | Specific or already mentioned | the teacher, the sun |\n| (none) | General statements, plural/uncountable | I like music. Dogs are loyal. |\n\n## Prepositions\n\n### Time\n- **at** + time: at 3 o''clock, at noon\n- **on** + day/date: on Monday, on 5 March\n- **in** + month/year/period: in January, in 2024, in the morning\n\n### Place\n- **at** + specific place: at school, at the bus stop\n- **in** + enclosed space: in the classroom, in Mali\n- **on** + surface: on the table, on the wall\n\n## Common Mistakes for French Speakers\n- ❌ I am agree → ✅ I **agree** (no ''am'')\n- ❌ She has 16 years → ✅ She **is** 16 years old\n- ❌ I am interested to → ✅ I am interested **in**\n- ❌ It depends of → ✅ It depends **on**\n- ❌ I go to the school → ✅ I go to **school** (no ''the'')"}',
  '[{"question": "When do we use the present simple tense?", "options": ["For actions happening now", "For habits, facts and routines", "For future plans", "For past events"], "correct": 1, "explanation": "The present simple is used for habits (I study every day), facts (the sun rises in the east) and routines (she works on Mondays)."},
  {"question": "Which sentence has correct subject-verb agreement?", "options": ["The students plays football.", "He play guitar every day.", "She studies at the library.", "They goes to school."], "correct": 2, "explanation": "''She studies'' is correct because we add -s to the verb for third person singular (he/she/it) in the present simple tense."},
  {"question": "Which article should go before ''apple''?", "options": ["A", "An", "The", "No article"], "correct": 1, "explanation": "We use ''an'' before words that begin with a vowel sound. Since ''apple'' starts with the vowel sound /æ/, we say ''an apple''."},
  {"question": "Which preposition is correct: ''I was born ___ March''?", "options": ["at", "on", "in", "to"], "correct": 2, "explanation": "We use ''in'' with months: in March, in January, in December. We use ''on'' with specific dates (on 5 March) and ''at'' with times (at 3 o''clock)."},
  {"question": "What is the correct English for ''Elle a 16 ans''?", "options": ["She has 16 years.", "She has 16 years old.", "She is 16 years old.", "She is 16 years."], "correct": 2, "explanation": "In English, we use ''to be'' (not ''to have'') to express age: She IS 16 years old. This is a common mistake for French speakers."}]',
  '[{"question": "What is the difference between ''a'' and ''an''?", "answer": "Use ''a'' before words that start with a consonant sound (a book, a university) and ''an'' before words that start with a vowel sound (an apple, an hour).", "category": "Vocabulaire"},
  {"question": "How do you form the present continuous?", "answer": "Subject + am/is/are + verb-ing. Example: I am studying, she is reading, they are playing.", "category": "Vocabulaire"},
  {"question": "What preposition do we use with months?", "answer": "We use ''in'' with months (in March), ''on'' with specific dates (on 5 March), and ''at'' with times (at noon).", "category": "Vocabulaire"},
  {"question": "How do you say ''Je suis d''accord'' in English?", "answer": "I agree. (NOT ''I am agree'' — in English, ''agree'' is a verb, not an adjective.)", "category": "Vocabulaire"}]',
  true, 1);

  -- ============================================================
  -- ANGLAIS LV2 - Chapitre 3 : Vocabulary & Expression
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_anglais_lv2_id, 'vocabulary-expression', 3, 'Vocabulary & Expression', 'Build essential vocabulary for everyday and academic contexts', 3)
  RETURNING id INTO v_ch_15;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_15, 'vocabulary-expression', 'Vocabulary & Expression',
  'Build your English vocabulary for everyday life and academic work. This chapter covers word families, useful expressions, false friends between French and English, and strategies for learning new words.',
  '{"key_points": ["Learn word families to expand vocabulary quickly", "Recognize false friends between French and English", "Use common expressions for everyday communication", "Apply vocabulary learning strategies: context, repetition, association", "Master academic vocabulary for essays and exams", "Understand prefixes and suffixes to guess word meanings", "Practice using new words in sentences"], "content": "## Word Formation\n\n### Prefixes\nPrefixes are added **before** a word to change its meaning:\n- **un-** = not: happy → **unhappy**, fair → **unfair**\n- **re-** = again: do → **redo**, write → **rewrite**\n- **dis-** = opposite: agree → **disagree**, like → **dislike**\n- **mis-** = wrongly: understand → **misunderstand**\n- **pre-** = before: view → **preview**, historic → **prehistoric**\n\n### Suffixes\nSuffixes are added **after** a word to change its type:\n- **-tion/-sion** (verb → noun): educate → **education**, decide → **decision**\n- **-ful** (noun → adjective): hope → **hopeful**, care → **careful**\n- **-less** (noun → adjective, meaning without): hope → **hopeless**\n- **-ly** (adjective → adverb): quick → **quickly**, careful → **carefully**\n- **-ment** (verb → noun): develop → **development**, improve → **improvement**\n\n## False Friends (Faux Amis)\n\nWords that look similar in French and English but have different meanings:\n\n| French | Looks like | Actually means in English |\n|--------|-----------|-------------------------|\n| actuellement | actually | currently / at the moment |\n| assister à | assist | attend / be present at |\n| blesser | bless | injure / hurt |\n| librairie | library | bookshop |\n| rester | rest | stay / remain |\n| attendre | attend | wait for |\n| regarder | regard | watch / look at |\n| journée | journey | day |\n\n## Useful Everyday Expressions\n\n### Greetings and Introductions\n- How do you do? (formal)\n- Nice to meet you.\n- How is it going? / How are things?\n\n### Asking for Information\n- Could you tell me where the library is?\n- Do you know what time it starts?\n- I was wondering if you could help me.\n\n### Expressing Opinions\n- In my opinion, ...\n- I believe that ...\n- As far as I am concerned, ...\n\n### Agreeing and Disagreeing\n- I agree with you.\n- That is a good point.\n- I see your point, but ...\n- I am afraid I disagree.\n\n## Academic Vocabulary\n\nWords you need for essays and exams:\n- **analyze**: study something carefully\n- **compare**: find similarities\n- **contrast**: find differences\n- **discuss**: write about different views\n- **evaluate**: judge the value of something\n- **explain**: make something clear\n- **describe**: say what something is like\n- **justify**: give reasons for\n\n## Vocabulary Learning Strategies\n1. **Read in context**: learn words from texts, not lists\n2. **Use a vocabulary notebook**: write word + meaning + example sentence\n3. **Review regularly**: study old words, not just new ones\n4. **Use new words**: try to use each new word in a sentence\n5. **Group by topic**: organize words by themes (school, family, health)"}',
  '[{"question": "What does the prefix ''un-'' mean?", "options": ["Again", "Before", "Not", "Wrong"], "correct": 2, "explanation": "The prefix ''un-'' means ''not'' or ''the opposite of''. For example: happy → unhappy (not happy), fair → unfair (not fair)."},
  {"question": "The French word ''librairie'' means what in English?", "options": ["Library", "Bookshop", "Free", "Book"], "correct": 1, "explanation": "''Librairie'' in French means ''bookshop'' in English, not ''library''. A library in French is ''bibliothèque''. This is a common false friend."},
  {"question": "What suffix turns a verb into a noun?", "options": ["-ly", "-ful", "-tion", "-less"], "correct": 2, "explanation": "The suffix ''-tion'' (or ''-sion'') turns verbs into nouns: educate → education, decide → decision, create → creation."},
  {"question": "What does ''to evaluate'' mean in academic English?", "options": ["To describe something", "To judge the value of something", "To list facts", "To copy from a text"], "correct": 1, "explanation": "To evaluate means to judge or assess the value, importance or quality of something. In essays, it means weighing up arguments and reaching a judgment."},
  {"question": "Which is the best strategy for learning vocabulary?", "options": ["Memorize long word lists", "Read words in context and review regularly", "Only learn words for exams", "Translate every word from French"], "correct": 1, "explanation": "Learning words in context (from texts, articles, conversations) and reviewing them regularly is the most effective strategy. This helps you understand how words are used naturally."}]',
  '[{"question": "What is a ''false friend'' in language learning?", "answer": "A false friend (faux ami) is a word that looks similar in two languages but has a different meaning. Example: French ''actuellement'' means ''currently'' in English, not ''actually''.", "category": "Vocabulaire"},
  {"question": "What does the suffix ''-less'' mean?", "answer": "The suffix ''-less'' means ''without''. Examples: homeless (without a home), careless (without care), hopeless (without hope).", "category": "Vocabulaire"},
  {"question": "How do you express an opinion in English?", "answer": "Common expressions: In my opinion, I believe that, As far as I am concerned, From my point of view, It seems to me that.", "category": "Vocabulaire"},
  {"question": "What is the difference between ''compare'' and ''contrast''?", "answer": "To compare means to find similarities between things. To contrast means to find differences between things. In essays, you often do both.", "category": "Vocabulaire"}]',
  true, 1);

  -- ============================================================
  -- ANGLAIS LV2 - Chapitre 4 : Translation Techniques
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_anglais_lv2_id, 'translation-techniques', 4, 'Translation Techniques', 'Learn effective techniques for translating between French and English', 4)
  RETURNING id INTO v_ch_16;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_16, 'translation-techniques', 'Translation Techniques',
  'Learn effective techniques for translating texts between French and English. This chapter covers common translation challenges, structural differences between the two languages and practical strategies for accurate translation.',
  '{"key_points": ["Translate meaning, not word by word", "Understand structural differences between French and English", "Handle idiomatic expressions by finding equivalents", "Apply transposition: changing word class during translation", "Use modulation: changing the point of view", "Recognize and handle cultural references in translation", "Proofread translations for natural-sounding English"], "content": "## Principles of Translation\n\n### Rule 1: Translate Meaning, Not Words\nThe most important rule in translation is to convey the **meaning** of the text, not to translate each word individually.\n\n- ❌ Word-for-word: \"It makes cold today\" (Il fait froid aujourd''hui)\n- ✅ Natural translation: \"**It is cold today**\"\n\n### Rule 2: Understand Both Languages\nGood translation requires understanding the **grammar and structures** of both French and English.\n\n## Key Structural Differences\n\n### 1. Adjective Placement\n- French: noun + adjective (une maison **blanche**)\n- English: adjective + noun (a **white** house)\n\n### 2. Possession\n- French: le livre **de** Pierre\n- English: Pierre**''s** book (or: the book **of** Pierre)\n\n### 3. Negation\n- French: Je **ne** sais **pas** (double negation)\n- English: I **do not** know (single negation with auxiliary)\n\n### 4. Question Formation\n- French: Est-ce que tu aimes...? / Tu aimes...?\n- English: **Do** you like...? (auxiliary required)\n\n## Translation Techniques\n\n### Transposition\nChanging the **word class** (part of speech) while keeping the same meaning:\n- \"après son **retour**\" (noun) → \"after he **returned**\" (verb)\n- \"Il a **facilement** réussi\" (adverb) → \"His **success** was easy\" (noun)\n\n### Modulation\nChanging the **point of view** while keeping the same meaning:\n- \"Ce n''est pas difficile\" (negative) → \"It is **easy**\" (positive)\n- \"la moitié pleine\" → \"**half full**\" (vs. half empty)\n\n### Equivalence\nFinding an **equivalent expression** when direct translation is impossible:\n- \"Il pleut des cordes\" → \"It is **raining cats and dogs**\"\n- \"Bon courage\" → \"**Good luck**\" or \"**Take care**\"\n\n### Adaptation\nAdapting **cultural references** that do not exist in the other language:\n- \"le baccalauréat\" → \"the final school-leaving exam\" (explanation)\n\n## Common Translation Traps\n\n| French | Wrong Translation | Correct Translation |\n|--------|------------------|--------------------|\n| J''ai faim | I have hunger | I **am** hungry |\n| Il y a 5 ans | It has 5 years | **5 years ago** |\n| Je viens de manger | I come from eating | I **have just** eaten |\n| C''est à moi | It is at me | It is **mine** |\n| Ça fait longtemps | It makes long time | It has been **a long time** |\n\n## Steps for a Good Translation\n1. **Read** the entire text first to understand the overall meaning\n2. **Identify** key ideas and difficult passages\n3. **Draft** a first translation focusing on meaning\n4. **Revise** for grammar, spelling and natural expression\n5. **Compare** with the original to check accuracy\n6. **Read aloud** to check if it sounds natural"}',
  '[{"question": "What is the most important rule of translation?", "options": ["Translate every word exactly", "Use a dictionary for every word", "Translate the meaning, not word by word", "Keep the same sentence structure"], "correct": 2, "explanation": "The most important rule is to translate the meaning of the text, not each individual word. Word-for-word translation often produces unnatural or incorrect results."},
  {"question": "How do you translate ''J''ai faim'' into English?", "options": ["I have hunger", "I have hungry", "I am hunger", "I am hungry"], "correct": 3, "explanation": "In French, you ''have'' hunger (avoir faim), but in English, you ''are'' hungry (to be + adjective). This is a key structural difference between the two languages."},
  {"question": "What is transposition in translation?", "options": ["Translating word by word", "Changing the word class while keeping the meaning", "Removing words from the translation", "Adding extra words"], "correct": 1, "explanation": "Transposition means changing the word class (noun, verb, adjective, etc.) during translation while keeping the same meaning. Example: ''après son retour'' (noun) → ''after he returned'' (verb)."},
  {"question": "Where do adjectives go in English compared to French?", "options": ["After the noun, like in French", "Before the noun", "At the end of the sentence", "It does not matter"], "correct": 1, "explanation": "In English, adjectives come BEFORE the noun (a white house), while in French they usually come AFTER the noun (une maison blanche)."},
  {"question": "What does ''equivalence'' mean in translation?", "options": ["Using the same words", "Finding an equivalent expression when direct translation is impossible", "Copying the French structure", "Translating literally"], "correct": 1, "explanation": "Equivalence means finding an expression in the target language that conveys the same meaning when a direct translation is impossible. For example: ''Il pleut des cordes'' → ''It is raining cats and dogs''."}]',
  '[{"question": "What is the difference between transposition and modulation?", "answer": "Transposition changes the word class (noun → verb, adverb → adjective) while keeping the meaning. Modulation changes the point of view or perspective (negative → positive, part → whole) while keeping the meaning.", "category": "Vocabulaire"},
  {"question": "How do you translate ''Il y a 5 ans'' into English?", "answer": "5 years ago. The French structure ''il y a + time'' is translated as ''time + ago'' in English. Do not translate it word by word.", "category": "Vocabulaire"},
  {"question": "What is adaptation in translation?", "answer": "Adaptation is used when a cultural concept does not exist in the other language. You explain or replace it with something the reader can understand. Example: ''baccalauréat'' → ''final school-leaving exam''.", "category": "Vocabulaire"},
  {"question": "What steps should you follow for a good translation?", "answer": "1. Read the entire text first. 2. Identify key ideas and difficulties. 3. Draft a first translation. 4. Revise for grammar and naturalness. 5. Compare with the original. 6. Read aloud to check.", "category": "Vocabulaire"}]',
  true, 1);

  -- ============================================================
  -- LINGUISTIQUE - Chapitre 1 : Introduction à la Linguistique Générale
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_linguistique_id, 'introduction-linguistique', 1, 'Introduction à la Linguistique Générale', 'Les fondements de la science du langage', 1)
  RETURNING id INTO v_ch_17;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_17, 'introduction-linguistique', 'Introduction à la Linguistique Générale',
  'La linguistique est la science qui étudie le langage humain de manière systématique. Ce chapitre présente les concepts fondateurs de Ferdinand de Saussure et les principales branches de la linguistique moderne.',
  '{"key_points": ["La linguistique est l''étude scientifique du langage humain", "Saussure distingue langue (système) et parole (usage individuel)", "Le signe linguistique unit un signifiant (forme sonore) et un signifié (concept)", "Le signe linguistique est arbitraire : pas de lien naturel entre forme et sens", "La linguistique se divise en plusieurs branches : phonétique, morphologie, syntaxe, sémantique, pragmatique", "On distingue linguistique synchronique (à un moment donné) et diachronique (évolution dans le temps)", "Le langage est une faculté universelle, la langue est un système particulier"], "content": "## Qu''est-ce que la linguistique ?\n\nLa linguistique est l''**étude scientifique du langage humain**. Elle analyse les langues de manière objective et systématique, sans porter de jugement de valeur. Contrairement à la grammaire normative qui dit ce qu''il faut dire, la linguistique **décrit** ce que les locuteurs disent réellement.\n\n## Ferdinand de Saussure : le père de la linguistique moderne\n\nFerdinand de Saussure (1857-1913) est considéré comme le fondateur de la linguistique moderne grâce à son **Cours de linguistique générale** (1916).\n\n### Les dichotomies de Saussure\n\n#### 1. Langue vs Parole\n- **Langue** : le système abstrait de règles partagé par une communauté (social, collectif)\n- **Parole** : l''utilisation concrète et individuelle de la langue (individuel, variable)\n- Exemple : la grammaire du français (langue) vs ce que je dis maintenant (parole)\n\n#### 2. Signifiant vs Signifié\nLe **signe linguistique** a deux faces :\n- **Signifiant** : l''image acoustique, la forme sonore du mot (ex : /aʁbʁ/)\n- **Signifié** : le concept, l''idée associée (ex : le concept d''arbre)\n\n#### 3. Synchronie vs Diachronie\n- **Synchronie** : étude de la langue à un moment donné (ex : le français en 2024)\n- **Diachronie** : étude de l''évolution de la langue dans le temps (ex : du latin au français)\n\n### L''arbitraire du signe\nIl n''y a **aucun lien naturel** entre le signifiant et le signifié. Le mot « arbre » ne ressemble pas à un arbre. La preuve : chaque langue utilise un mot différent (tree, Baum, yiri).\n\n**Exception** : les onomatopées imitent partiellement les sons (cocorico, meow), mais elles varient aussi selon les langues.\n\n## Les branches de la linguistique\n\n| Branche | Objet d''étude |\n|---------|---------------|\n| **Phonétique** | Les sons du langage |\n| **Phonologie** | Le système des sons distinctifs |\n| **Morphologie** | La structure des mots |\n| **Syntaxe** | La structure des phrases |\n| **Sémantique** | Le sens des mots et des phrases |\n| **Pragmatique** | Le langage en contexte |\n| **Sociolinguistique** | Langue et société |\n\n## Langage, Langue, Parole\n- **Langage** : faculté humaine universelle de communiquer par des signes\n- **Langue** : système linguistique particulier (français, bambara, anglais)\n- **Parole** : réalisation individuelle et concrète de la langue"}',
  '[{"question": "Qui est considéré comme le père de la linguistique moderne ?", "options": ["Noam Chomsky", "Ferdinand de Saussure", "Roman Jakobson", "André Martinet"], "correct": 1, "explanation": "Ferdinand de Saussure (1857-1913) est considéré comme le fondateur de la linguistique moderne grâce à son Cours de linguistique générale publié en 1916."},
  {"question": "Qu''est-ce que le signifiant dans le signe linguistique ?", "options": ["Le concept ou l''idée", "La forme sonore ou image acoustique", "La phrase complète", "Le contexte de communication"], "correct": 1, "explanation": "Le signifiant est la face matérielle du signe linguistique : l''image acoustique, la forme sonore du mot. Par exemple, pour le mot arbre, le signifiant est /aʁbʁ/."},
  {"question": "Que signifie l''arbitraire du signe ?", "options": ["Le signe a un sens fixe", "Il y a un lien naturel entre le mot et la chose", "Il n''y a aucun lien naturel entre signifiant et signifié", "Seuls les noms propres sont arbitraires"], "correct": 2, "explanation": "L''arbitraire du signe signifie qu''il n''y a aucun lien naturel entre la forme du mot (signifiant) et le concept qu''il désigne (signifié). La preuve : chaque langue utilise des mots différents pour désigner la même chose."},
  {"question": "Quelle est la différence entre synchronie et diachronie ?", "options": ["Synchronie = oral, diachronie = écrit", "Synchronie = étude à un moment donné, diachronie = étude de l''évolution", "Synchronie = phonétique, diachronie = syntaxe", "Il n''y a aucune différence"], "correct": 1, "explanation": "La synchronie étudie la langue telle qu''elle est à un moment précis. La diachronie étudie comment la langue a évolué au fil du temps (par exemple, du latin au français)."},
  {"question": "Quelle branche de la linguistique étudie le sens des mots ?", "options": ["La phonétique", "La morphologie", "La syntaxe", "La sémantique"], "correct": 3, "explanation": "La sémantique est la branche de la linguistique qui étudie le sens des mots, des phrases et des textes."}]',
  '[{"question": "Qu''est-ce que la langue selon Saussure ?", "answer": "La langue est un système abstrait de signes et de règles partagé par une communauté linguistique. Elle est sociale et collective, par opposition à la parole qui est individuelle.", "category": "Définition"},
  {"question": "Qu''est-ce que le signe linguistique ?", "answer": "Le signe linguistique est l''union d''un signifiant (forme sonore/image acoustique) et d''un signifié (concept/idée). Cette union est arbitraire selon Saussure.", "category": "Définition"},
  {"question": "Quelle est la différence entre langage, langue et parole ?", "answer": "Le langage est la faculté humaine universelle de communiquer. La langue est un système particulier (français, bambara). La parole est l''utilisation individuelle et concrète de la langue.", "category": "Définition"},
  {"question": "Qu''est-ce que la linguistique synchronique ?", "answer": "La linguistique synchronique étudie une langue à un moment précis de son histoire, sans considérer son évolution. Elle s''oppose à la linguistique diachronique qui étudie l''évolution dans le temps.", "category": "Définition"}]',
  false, 1);

  -- ============================================================
  -- LINGUISTIQUE - Chapitre 2 : Phonétique et Phonologie
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_linguistique_id, 'phonetique-phonologie', 2, 'Phonétique et Phonologie', 'L''étude des sons du langage et leur fonction distinctive', 2)
  RETURNING id INTO v_ch_18;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_18, 'phonetique-phonologie', 'Phonétique et Phonologie',
  'La phonétique étudie les sons du langage dans leur réalité physique, tandis que la phonologie s''intéresse à leur fonction distinctive dans une langue. Ce chapitre explore les deux disciplines et leurs concepts clés.',
  '{"key_points": ["La phonétique étudie les sons concrets (phones), la phonologie les sons fonctionnels (phonèmes)", "Un phonème est un son qui permet de distinguer des mots : /p/ et /b/ dans pain/bain", "L''API (Alphabet Phonétique International) transcrit les sons de toutes les langues", "Les voyelles se classent selon l''aperture, le lieu d''articulation et la labialité", "Les consonnes se classent selon le mode et le lieu d''articulation, et le voisement", "La paire minimale prouve qu''un son est un phonème dans une langue donnée", "Un allophone est une variante d''un phonème qui ne change pas le sens"], "content": "## Phonétique vs Phonologie\n\n### Phonétique\nÉtude des **sons concrets** du langage dans leur réalité physique (acoustique et articulatoire).\n- Unité : le **phone** (son concret)\n- Transcription entre crochets : [p], [b], [a]\n- S''intéresse à **comment** les sons sont produits\n\n### Phonologie\nÉtude des sons en tant qu''**unités fonctionnelles** dans une langue.\n- Unité : le **phonème** (son distinctif)\n- Transcription entre barres obliques : /p/, /b/, /a/\n- S''intéresse à la **fonction** des sons (distinguer des mots)\n\n## Le phonème et la paire minimale\n\nUn **phonème** est la plus petite unité sonore qui permet de **distinguer deux mots** de sens différent.\n\nOn identifie un phonème grâce à la **paire minimale** : deux mots qui ne diffèrent que par un seul son.\n\n| Paire minimale | Phonèmes opposés |\n|---------------|------------------|\n| **p**ain / **b**ain | /p/ vs /b/ |\n| **r**ou / **l**ou | /r/ vs /l/ |\n| p**a**r / p**o**r | /a/ vs /ɔ/ |\n| **s**au / **ch**au | /s/ vs /ʃ/ |\n\n## Classification des voyelles\n\nLes voyelles se classent selon trois critères :\n\n### 1. Aperture (ouverture de la bouche)\n- **Fermées** : /i/, /y/, /u/ (bouche presque fermée)\n- **Mi-fermées** : /e/, /ø/, /o/\n- **Mi-ouvertes** : /ɛ/, /œ/, /ɔ/\n- **Ouvertes** : /a/ (bouche grande ouverte)\n\n### 2. Lieu d''articulation\n- **Antérieures** : /i/, /e/, /ɛ/ (langue vers l''avant)\n- **Postérieures** : /u/, /o/, /ɔ/ (langue vers l''arrière)\n\n### 3. Labialité\n- **Arrondies** : /y/, /u/, /ø/, /o/ (lèvres arrondies)\n- **Non arrondies** : /i/, /e/, /ɛ/, /a/ (lèvres écartées)\n\n## Classification des consonnes\n\nLes consonnes se classent selon :\n\n### Mode d''articulation\n- **Occlusives** : blocage total de l''air (/p/, /b/, /t/, /d/, /k/, /g/)\n- **Fricatives** : passage étroit de l''air (/f/, /v/, /s/, /z/, /ʃ/, /ʒ/)\n- **Nasales** : l''air passe par le nez (/m/, /n/, /ɲ/)\n- **Latérale** : l''air passe sur les côtés (/l/)\n- **Vibrante** : vibration de la langue ou de la luette (/r/)\n\n### Voisement\n- **Sourdes** : cordes vocales ne vibrent pas (/p/, /t/, /k/, /f/, /s/)\n- **Sonores** : cordes vocales vibrent (/b/, /d/, /g/, /v/, /z/)\n\n## Les allophones\nUn **allophone** est une variante de réalisation d''un phonème qui ne change pas le sens du mot. Par exemple, le /r/ français peut être roulé [r] ou grasseyé [ʁ] sans changer le sens."}',
  '[{"question": "Quelle est la différence entre un phone et un phonème ?", "options": ["Il n''y a aucune différence", "Un phone est un son concret, un phonème est une unité fonctionnelle", "Un phone est écrit, un phonème est oral", "Un phone est une voyelle, un phonème est une consonne"], "correct": 1, "explanation": "Un phone est un son concret tel qu''il est réellement prononcé (étude phonétique). Un phonème est une unité abstraite qui a une fonction distinctive dans la langue (étude phonologique)."},
  {"question": "Comment identifie-t-on un phonème ?", "options": ["Par son volume sonore", "Par la paire minimale", "Par sa fréquence d''utilisation", "Par sa position dans le mot"], "correct": 1, "explanation": "On identifie un phonème grâce à la paire minimale : deux mots qui ne diffèrent que par un seul son (ex : pain/bain). Si le changement de son change le sens, c''est un phonème."},
  {"question": "Comment se transcrit un phonème ?", "options": ["Entre crochets [p]", "Entre barres obliques /p/", "Entre parenthèses (p)", "Entre guillemets \"p\""], "correct": 1, "explanation": "Les phonèmes se transcrivent entre barres obliques /p/ (niveau phonologique). Les phones se transcrivent entre crochets [p] (niveau phonétique)."},
  {"question": "Comment classe-t-on les consonnes sourdes et sonores ?", "options": ["Par la position de la langue", "Par la vibration ou non des cordes vocales", "Par la longueur du son", "Par le volume"], "correct": 1, "explanation": "Les consonnes sourdes sont produites sans vibration des cordes vocales (/p/, /t/, /k/) et les sonores avec vibration (/b/, /d/, /g/). On peut vérifier en posant la main sur la gorge."},
  {"question": "Qu''est-ce qu''un allophone ?", "options": ["Un nouveau phonème", "Un son qui change le sens du mot", "Une variante d''un phonème qui ne change pas le sens", "Un son qui n''existe pas en français"], "correct": 2, "explanation": "Un allophone est une variante de réalisation d''un phonème qui ne change pas le sens du mot. Par exemple, le /r/ peut être roulé ou grasseyé en français sans modifier le sens."}]',
  '[{"question": "Qu''est-ce qu''une paire minimale ?", "answer": "Une paire minimale est composée de deux mots qui ne diffèrent que par un seul son et qui ont des sens différents. Elle permet de prouver qu''un son est un phonème. Exemple : pain /pɛ̃/ et bain /bɛ̃/.", "category": "Définition"},
  {"question": "Qu''est-ce qu''une consonne occlusive ?", "answer": "Une consonne occlusive est produite par un blocage total du passage de l''air suivi d''un relâchement brusque. Exemples : /p/, /b/, /t/, /d/, /k/, /g/.", "category": "Définition"},
  {"question": "Qu''est-ce que l''API ?", "answer": "L''API (Alphabet Phonétique International) est un système de symboles qui permet de transcrire les sons de toutes les langues du monde de manière univoque. Chaque symbole correspond à un seul son.", "category": "Définition"},
  {"question": "Qu''est-ce que le voisement ?", "answer": "Le voisement est la vibration des cordes vocales lors de la production d''un son. Les consonnes sonores (voisées) font vibrer les cordes vocales (/b/, /d/, /g/), les sourdes (non voisées) non (/p/, /t/, /k/).", "category": "Définition"}]',
  true, 1);

  -- ============================================================
  -- LINGUISTIQUE - Chapitre 3 : Morphologie
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_linguistique_id, 'morphologie', 3, 'Morphologie', 'L''étude de la structure interne des mots', 3)
  RETURNING id INTO v_ch_19;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_19, 'morphologie', 'Morphologie',
  'La morphologie étudie la structure interne des mots et les règles de formation des mots. Ce chapitre présente les morphèmes, les processus de dérivation et de composition, et la flexion.',
  '{"key_points": ["Le morphème est la plus petite unité de sens dans une langue", "On distingue morphèmes lexicaux (lexèmes) et grammaticaux (grammèmes)", "La dérivation crée de nouveaux mots par ajout de préfixes et suffixes", "La composition combine deux ou plusieurs mots pour en former un nouveau", "La flexion modifie la forme d''un mot selon le genre, le nombre, le temps", "Un morphème libre peut exister seul, un morphème lié ne le peut pas", "L''analyse morphologique décompose les mots en leurs morphèmes constitutifs"], "content": "## Qu''est-ce que la morphologie ?\n\nLa morphologie est la branche de la linguistique qui étudie la **structure interne des mots** et les règles de **formation des mots**.\n\n## Le morphème\n\nLe **morphème** est la plus petite unité linguistique porteuse de **sens**.\n\nExemple : le mot « incroyable » se décompose en 3 morphèmes :\n- **in-** : morphème de négation (« pas »)\n- **-croy-** : morphème lexical (racine du verbe croire)\n- **-able** : morphème qui signifie « qui peut être »\n\n### Types de morphèmes\n\n#### 1. Morphèmes lexicaux (lexèmes)\nIls portent le **sens principal** du mot (la racine).\n- Dans « chanteur » : **chant-** est le lexème\n- Dans « refaire » : **-fair-** est le lexème\n\n#### 2. Morphèmes grammaticaux (grammèmes)\nIls apportent une **information grammaticale** (genre, nombre, temps, etc.).\n- Dans « chanteurs » : **-s** marque le pluriel\n- Dans « chantons » : **-ons** marque la 1ʳᵉ personne du pluriel\n\n### Morphèmes libres vs liés\n- **Libre** : peut exister seul comme mot (ex : « chat », « beau »)\n- **Lié** : ne peut pas exister seul, toujours attaché (ex : « -ment », « in- », « -s »)\n\n## Les processus morphologiques\n\n### 1. La dérivation\nCréation de nouveaux mots par ajout d''**affixes** (préfixes ou suffixes) à une base.\n\n#### Préfixation\n| Préfixe | Sens | Exemple |\n|---------|------|---------|\n| re- | encore | refaire, relire |\n| in-/im- | négation | invisible, impossible |\n| dé-/dés- | contraire | défaire, désordre |\n| pré- | avant | prévoir, prédire |\n\n#### Suffixation\n| Suffixe | Catégorie résultante | Exemple |\n|---------|---------------------|---------|\n| -eur/-euse | nom (agent) | chanteur, danseuse |\n| -tion/-ation | nom (action) | création, formation |\n| -ment | adverbe | rapidement, facilement |\n| -able/-ible | adjectif | mangeable, lisible |\n\n### 2. La composition\nCombination de **deux mots** ou plus pour former un nouveau mot.\n- porte + manteau → **portemanteau**\n- rouge + gorge → **rouge-gorge**\n- pomme + de + terre → **pomme de terre**\n\n### 3. La flexion\nModification de la forme d''un mot selon des catégories grammaticales **sans changer sa catégorie**.\n- **Genre** : petit → petite\n- **Nombre** : chat → chats\n- **Temps** : je chante → je chantais → je chanterai\n- **Personne** : je chante → tu chantes → il chante\n\n## Analyse morphologique\nDécomposer un mot en morphèmes :\n- **Indéfendable** = in- (négation) + défend- (racine) + -able (possibilité)\n- **Anticonstitutionnellement** = anti- + constitution- + -n- + -elle- + -ment"}',
  '[{"question": "Qu''est-ce qu''un morphème ?", "options": ["La plus petite unité de son", "La plus petite unité de sens", "Un mot complet", "Une phrase"], "correct": 1, "explanation": "Le morphème est la plus petite unité linguistique porteuse de sens. Par exemple, « incroyable » contient trois morphèmes : in- (négation), -croy- (racine), -able (possibilité)."},
  {"question": "Quelle est la différence entre un lexème et un grammème ?", "options": ["Aucune différence", "Le lexème porte le sens principal, le grammème l''information grammaticale", "Le lexème est un verbe, le grammème un nom", "Le lexème est oral, le grammème est écrit"], "correct": 1, "explanation": "Le lexème (morphème lexical) porte le sens principal du mot (la racine), tandis que le grammème (morphème grammatical) apporte une information grammaticale comme le genre, le nombre ou le temps."},
  {"question": "Qu''est-ce que la dérivation ?", "options": ["Combiner deux mots", "Ajouter un préfixe ou suffixe à une base", "Changer le temps d''un verbe", "Supprimer une partie du mot"], "correct": 1, "explanation": "La dérivation consiste à créer un nouveau mot en ajoutant un affixe (préfixe ou suffixe) à une base. Exemple : chant → chanteur (ajout du suffixe -eur)."},
  {"question": "Quel processus a formé le mot « portemanteau » ?", "options": ["La dérivation", "La flexion", "La composition", "L''emprunt"], "correct": 2, "explanation": "Le mot « portemanteau » est formé par composition : la combinaison de deux mots existants (porte + manteau) pour créer un nouveau mot."},
  {"question": "Qu''est-ce qu''un morphème lié ?", "options": ["Un morphème qui peut exister seul", "Un morphème qui est toujours attaché à un autre", "Un morphème qui a plusieurs sens", "Un morphème emprunté à une autre langue"], "correct": 1, "explanation": "Un morphème lié ne peut pas exister seul comme mot indépendant. Il doit toujours être attaché à un autre morphème. Exemples : -ment, in-, -s, -tion."}]',
  '[{"question": "Qu''est-ce que la flexion ?", "answer": "La flexion est la modification de la forme d''un mot selon des catégories grammaticales (genre, nombre, temps, personne) sans changer sa catégorie grammaticale. Exemples : chat/chats (nombre), petit/petite (genre).", "category": "Définition"},
  {"question": "Qu''est-ce que la composition en morphologie ?", "answer": "La composition est un processus de formation de mots qui combine deux ou plusieurs mots existants pour créer un nouveau mot. Exemples : portemanteau, rouge-gorge, pomme de terre.", "category": "Définition"},
  {"question": "Comment décomposer le mot « indéfendable » ?", "answer": "Indéfendable = in- (préfixe de négation) + défend- (racine/lexème du verbe défendre) + -able (suffixe signifiant « qui peut être »). Sens : qui ne peut pas être défendu.", "category": "Définition"},
  {"question": "Quelle est la différence entre préfixe et suffixe ?", "answer": "Un préfixe se place AVANT la base (re-faire, in-visible) et un suffixe se place APRÈS la base (chant-eur, rapid-ement). Les deux sont des affixes utilisés dans la dérivation.", "category": "Définition"}]',
  true, 1);

  -- ============================================================
  -- LINGUISTIQUE - Chapitre 4 : Syntaxe
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_linguistique_id, 'syntaxe', 4, 'Syntaxe', 'L''étude de la structure des phrases et des règles de combinaison', 4)
  RETURNING id INTO v_ch_20;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_20, 'syntaxe', 'Syntaxe',
  'La syntaxe étudie les règles qui régissent l''agencement des mots dans la phrase. Ce chapitre couvre les constituants de la phrase, les fonctions syntaxiques et l''analyse en arbre.',
  '{"key_points": ["La syntaxe étudie la structure des phrases et l''ordre des mots", "La phrase de base en français suit l''ordre SVO (Sujet-Verbe-Objet)", "Les constituants immédiats sont les groupes qui composent la phrase", "Le syntagme nominal (SN) et le syntagme verbal (SV) sont les constituants principaux", "Les fonctions syntaxiques incluent sujet, COD, COI, complément circonstanciel", "L''analyse en constituants immédiats décompose la phrase en groupes hiérarchiques", "La récursivité permet d''enchâsser des phrases dans d''autres phrases"], "content": "## Qu''est-ce que la syntaxe ?\n\nLa syntaxe est la branche de la linguistique qui étudie les **règles de combinaison des mots** pour former des phrases grammaticalement correctes.\n\n## La phrase de base\n\nEn français, la phrase de base suit l''ordre **SVO** :\n- **S** (Sujet) + **V** (Verbe) + **O** (Objet)\n- Exemple : « L''élève lit un livre. »\n\n## Les syntagmes (constituants)\n\nUn **syntagme** est un groupe de mots qui fonctionne comme une unité syntaxique.\n\n### Types de syntagmes\n\n| Syntagme | Abréviation | Noyau | Exemple |\n|----------|------------|-------|--------|\n| Syntagme nominal | SN | Nom | **le grand arbre** |\n| Syntagme verbal | SV | Verbe | **mange une pomme** |\n| Syntagme prépositionnel | SP | Préposition | **dans la maison** |\n| Syntagme adjectival | SA | Adjectif | **très intelligent** |\n| Syntagme adverbial | SAdv | Adverbe | **très rapidement** |\n\n### Structure de la phrase\nPhrase (P) → SN + SV\n- SN → Dét + N (+ SA/SP)\n- SV → V (+ SN) (+ SP)\n\nExemple : « Le chat noir mange une souris dans le jardin. »\n- P → SN [Le chat noir] + SV [mange une souris dans le jardin]\n- SN → Dét [Le] + N [chat] + SA [noir]\n- SV → V [mange] + SN [une souris] + SP [dans le jardin]\n\n## Les fonctions syntaxiques\n\n### Fonctions essentielles\n- **Sujet** : de qui/quoi on parle → « **L''élève** travaille. »\n- **COD** (Complément d''objet direct) : quoi ? → « Il lit **un livre**. »\n- **COI** (Complément d''objet indirect) : à qui/à quoi ? → « Il parle **à son ami**. »\n- **Attribut du sujet** : après un verbe d''état → « Il est **intelligent**. »\n\n### Fonctions circonstancielles\n- **CC de lieu** : où ? → « Il travaille **à la bibliothèque**. »\n- **CC de temps** : quand ? → « Il arrive **demain**. »\n- **CC de manière** : comment ? → « Il parle **doucement**. »\n- **CC de cause** : pourquoi ? → « Il est absent **à cause de la pluie**. »\n\n## La récursivité\n\nLa récursivité est la propriété du langage qui permet d''**enchâsser** des structures les unes dans les autres indéfiniment :\n- « Le chat dort. »\n- « Le chat **que j''ai vu** dort. »\n- « Le chat **que j''ai vu dans le jardin qui est derrière la maison** dort. »\n\nC''est une propriété fondamentale du langage humain selon **Noam Chomsky**."}',
  '[{"question": "Quel est l''ordre de base de la phrase en français ?", "options": ["VSO (Verbe-Sujet-Objet)", "SOV (Sujet-Objet-Verbe)", "SVO (Sujet-Verbe-Objet)", "OVS (Objet-Verbe-Sujet)"], "correct": 2, "explanation": "En français, l''ordre de base de la phrase est SVO : Sujet + Verbe + Objet. Exemple : L''élève (S) lit (V) un livre (O)."},
  {"question": "Qu''est-ce qu''un syntagme nominal ?", "options": ["Un groupe centré sur un verbe", "Un groupe centré sur un nom", "Un groupe centré sur un adjectif", "Un mot isolé"], "correct": 1, "explanation": "Un syntagme nominal (SN) est un groupe de mots dont le noyau est un nom. Exemple : « le grand arbre » est un SN dont le noyau est « arbre »."},
  {"question": "Quelle est la fonction du mot souligné : « Il lit UN LIVRE » ?", "options": ["Sujet", "COD (Complément d''objet direct)", "COI (Complément d''objet indirect)", "Attribut du sujet"], "correct": 1, "explanation": "« Un livre » est COD car il répond à la question « Il lit quoi ? ». Le COD complète directement le verbe sans préposition."},
  {"question": "Qu''est-ce que la récursivité en syntaxe ?", "options": ["La répétition d''un mot", "La possibilité d''enchâsser des structures indéfiniment", "L''inversion du sujet et du verbe", "La suppression de mots dans la phrase"], "correct": 1, "explanation": "La récursivité est la propriété qui permet d''enchâsser des phrases ou groupes les uns dans les autres de manière potentiellement infinie. C''est une propriété fondamentale du langage humain."},
  {"question": "Quel linguiste a souligné l''importance de la récursivité ?", "options": ["Ferdinand de Saussure", "Roman Jakobson", "Noam Chomsky", "André Martinet"], "correct": 2, "explanation": "Noam Chomsky a particulièrement souligné l''importance de la récursivité comme propriété fondamentale du langage humain, la considérant comme ce qui distingue le langage humain de la communication animale."}]',
  '[{"question": "Qu''est-ce qu''un syntagme ?", "answer": "Un syntagme est un groupe de mots qui fonctionne comme une unité syntaxique. Il est organisé autour d''un noyau : nom (SN), verbe (SV), préposition (SP), adjectif (SA) ou adverbe (SAdv).", "category": "Définition"},
  {"question": "Qu''est-ce que le COD ?", "answer": "Le COD (Complément d''Objet Direct) est un complément essentiel du verbe qui se construit sans préposition. Il répond à la question « quoi ? » ou « qui ? » après le verbe. Exemple : Il lit UN LIVRE.", "category": "Définition"},
  {"question": "Comment décomposer une phrase en constituants immédiats ?", "answer": "On décompose la phrase en ses groupes principaux : P → SN (sujet) + SV (prédicat). Puis on décompose chaque groupe : SN → Dét + N + (modificateurs), SV → V + (compléments).", "category": "Définition"},
  {"question": "Qu''est-ce qu''un complément circonstanciel ?", "answer": "Un complément circonstanciel (CC) est un complément non essentiel qui apporte une information sur les circonstances de l''action : lieu (où ?), temps (quand ?), manière (comment ?), cause (pourquoi ?).", "category": "Définition"}]',
  true, 1);

  -- ============================================================
  -- LINGUISTIQUE - Chapitre 5 : Sémantique
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_linguistique_id, 'semantique', 5, 'Sémantique', 'L''étude du sens des mots et des phrases', 5)
  RETURNING id INTO v_ch_21;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_21, 'semantique', 'Sémantique',
  'La sémantique est la branche de la linguistique qui étudie le sens des mots, des phrases et des textes. Ce chapitre couvre les relations sémantiques, l''analyse sémique et les types de sens.',
  '{"key_points": ["La sémantique étudie le sens des unités linguistiques", "La dénotation est le sens objectif, la connotation le sens associé", "La synonymie, l''antonymie, l''hyponymie et l''hyperonymie sont des relations sémantiques", "La polysémie : un mot a plusieurs sens liés (ex : « pied » de la table, du lit)", "L''homonymie : des mots identiques en forme mais de sens différents", "L''analyse sémique décompose le sens en traits distinctifs (sèmes)", "Le champ sémantique regroupe les sens d''un mot, le champ lexical les mots d''un thème"], "content": "## Qu''est-ce que la sémantique ?\n\nLa sémantique étudie le **sens** des mots, des phrases et des textes. Elle cherche à comprendre comment le langage exprime et transmet du sens.\n\n## Dénotation et connotation\n\n- **Dénotation** : le sens objectif, neutre d''un mot (sens du dictionnaire)\n  - « Soleil » = étoile autour de laquelle tourne la Terre\n- **Connotation** : les sens associés, subjectifs, culturels\n  - « Soleil » = chaleur, bonheur, vacances, Afrique\n\n## Les relations sémantiques\n\n### 1. Synonymie\nDeux mots de **sens proche** : beau / joli, maison / demeure, rapide / vite\n\n⚠️ Les synonymes parfaits sont très rares. Il y a souvent des nuances de registre, d''intensité ou de contexte.\n\n### 2. Antonymie\nDeux mots de **sens opposé** :\n- **Complémentaires** : vivant / mort, vrai / faux (pas de milieu)\n- **Gradables** : chaud / froid (avec des degrés : tiède, frais)\n- **Réciproques** : acheter / vendre, donner / recevoir\n\n### 3. Hyponymie et hyperonymie\n- **Hyperonyme** : terme générique (« animal »)\n- **Hyponyme** : terme spécifique (« chat », « chien », « lion »)\n- Relation d''inclusion : chat EST UN animal\n\n### 4. Polysémie\nUn mot a **plusieurs sens liés** entre eux :\n- « Pied » : pied du corps, pied de la table, pied de la montagne\n- « Feuille » : feuille d''arbre, feuille de papier\n\n### 5. Homonymie\nDes mots de **même forme** mais de **sens différents et non liés** :\n- « Avocat » : le fruit / le professionnel du droit\n- « Livre » : un livre (objet) / une livre (unité de poids)\n\n## L''analyse sémique\n\nL''analyse sémique décompose le sens d''un mot en **sèmes** (traits distinctifs de sens).\n\nExemple : comparaison de « chaise », « fauteuil », « tabouret »\n\n| Sème | Chaise | Fauteuil | Tabouret |\n|------|--------|----------|----------|\n| Pour s''asseoir | + | + | + |\n| Avec dossier | + | + | - |\n| Avec accoudoirs | - | + | - |\n| Pour une personne | + | + | + |\n\n## Champ sémantique vs champ lexical\n\n- **Champ sémantique** : ensemble des **sens** d''un mot\n  - « Opération » : chirurgicale, militaire, mathématique, financière\n- **Champ lexical** : ensemble des **mots** liés à un thème\n  - Champ lexical de l''école : élève, professeur, tableau, cahier, cours"}',
  '[{"question": "Quelle est la différence entre dénotation et connotation ?", "options": ["Aucune différence", "La dénotation est le sens objectif, la connotation les sens associés", "La dénotation est orale, la connotation est écrite", "La dénotation est négative, la connotation positive"], "correct": 1, "explanation": "La dénotation est le sens objectif et neutre d''un mot (sens du dictionnaire). La connotation regroupe les sens associés, subjectifs et culturels. Par exemple, « soleil » dénote une étoile mais connote chaleur, bonheur, vacances."},
  {"question": "Qu''est-ce que la polysémie ?", "options": ["Un mot qui n''a aucun sens", "Un mot qui a plusieurs sens liés entre eux", "Deux mots qui ont le même sens", "Un mot emprunté à une autre langue"], "correct": 1, "explanation": "La polysémie est le fait qu''un même mot possède plusieurs sens liés entre eux. Par exemple, « pied » désigne le pied du corps, le pied de la table, le pied de la montagne — tous liés à l''idée de base/support."},
  {"question": "Qu''est-ce qu''un hyperonyme ?", "options": ["Un synonyme", "Un mot de sens opposé", "Un terme générique qui englobe d''autres termes", "Un mot rare"], "correct": 2, "explanation": "Un hyperonyme est un terme générique qui englobe des termes plus spécifiques (hyponymes). Par exemple, « animal » est l''hyperonyme de « chat », « chien », « lion »."},
  {"question": "Qu''est-ce qu''un sème en analyse sémique ?", "options": ["Un son distinctif", "Un trait distinctif de sens", "Un morphème", "Une figure de style"], "correct": 1, "explanation": "Un sème est un trait distinctif de sens, la plus petite unité de signification. L''analyse sémique décompose le sens d''un mot en sèmes pour le comparer à d''autres mots du même champ."},
  {"question": "Quelle est la différence entre polysémie et homonymie ?", "options": ["Aucune différence", "La polysémie : sens liés; l''homonymie : sens non liés", "La polysémie est orale, l''homonymie est écrite", "La polysémie concerne les verbes, l''homonymie les noms"], "correct": 1, "explanation": "En polysémie, un mot a plusieurs sens LIÉS entre eux (pied du corps / pied de la table). En homonymie, des mots de même forme ont des sens NON LIÉS (avocat = fruit / professionnel du droit)."}]',
  '[{"question": "Qu''est-ce que la synonymie ?", "answer": "La synonymie est une relation sémantique entre deux mots de sens proche (beau/joli, maison/demeure). Les synonymes parfaits sont rares car il y a souvent des nuances de registre ou de contexte.", "category": "Définition"},
  {"question": "Qu''est-ce que l''antonymie ?", "answer": "L''antonymie est une relation entre deux mots de sens opposé. Il existe trois types : complémentaires (vrai/faux), gradables (chaud/froid), réciproques (acheter/vendre).", "category": "Définition"},
  {"question": "Qu''est-ce qu''un champ lexical ?", "answer": "Un champ lexical est l''ensemble des mots liés à un même thème. Exemple : le champ lexical de l''école comprend élève, professeur, cours, cahier, tableau, examen.", "category": "Définition"},
  {"question": "Qu''est-ce que l''homonymie ?", "answer": "L''homonymie est le fait que des mots de même forme (même son et/ou même orthographe) aient des sens totalement différents et non liés. Exemple : « avocat » (fruit) et « avocat » (juriste).", "category": "Définition"}]',
  true, 1);

  -- ============================================================
  -- LINGUISTIQUE - Chapitre 6 : Pragmatique
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_linguistique_id, 'pragmatique', 6, 'Pragmatique', 'Le langage en contexte et les actes de langage', 6)
  RETURNING id INTO v_ch_22;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_22, 'pragmatique', 'Pragmatique',
  'La pragmatique étudie le langage en contexte : comment le sens dépend de la situation de communication. Ce chapitre couvre les actes de langage d''Austin et Searle, les maximes de Grice et l''implicite.',
  '{"key_points": ["La pragmatique étudie le sens des énoncés en contexte", "Austin distingue acte locutoire, illocutoire et perlocutoire", "Searle classe les actes de langage en 5 catégories : assertifs, directifs, commissifs, expressifs, déclaratifs", "Les maximes de Grice régissent la conversation : quantité, qualité, relation, manière", "L''implicature est ce qu''on communique sans le dire explicitement", "La présupposition est une information tenue pour acquise dans l''énoncé", "La deixis rattache l''énoncé au contexte : je, ici, maintenant"], "content": "## Qu''est-ce que la pragmatique ?\n\nLa pragmatique étudie le **langage en contexte**. Elle s''intéresse à ce que les locuteurs veulent **réellement dire** au-delà du sens littéral des mots.\n\nExemple : « Il fait froid ici » peut signifier « Ferme la fenêtre » selon le contexte.\n\n## Les actes de langage (Austin)\n\nJohn L. Austin (1911-1960) a montré que **parler, c''est agir**. En disant quelque chose, on accomplit un acte.\n\n### Les trois dimensions de l''acte de langage\n\n1. **Acte locutoire** : le fait de prononcer des mots (dire quelque chose)\n2. **Acte illocutoire** : l''intention du locuteur (ce qu''on fait en disant)\n   - promettre, ordonner, demander, informer, remercier\n3. **Acte perlocutoire** : l''effet produit sur l''interlocuteur\n   - convaincre, effrayer, amuser, persuader\n\nExemple : « Je viendrai demain. »\n- Locutoire : prononcer cette phrase\n- Illocutoire : faire une **promesse**\n- Perlocutoire : **rassurer** l''interlocuteur\n\n## La classification de Searle\n\nJohn Searle a classé les actes illocutoires en **5 catégories** :\n\n| Catégorie | Fonction | Exemple |\n|-----------|----------|---------|\n| **Assertifs** | Dire comment les choses sont | « Il pleut. », « La Terre est ronde. » |\n| **Directifs** | Faire faire quelque chose | « Ferme la porte. », « Pouvez-vous m''aider ? » |\n| **Commissifs** | S''engager à faire quelque chose | « Je promets de venir. » |\n| **Expressifs** | Exprimer un état psychologique | « Merci ! », « Félicitations ! », « Désolé. » |\n| **Déclaratifs** | Changer l''état du monde par la parole | « Je vous déclare mari et femme. » |\n\n## Les maximes de Grice\n\nPaul Grice a formulé le **principe de coopération** : dans une conversation, les participants coopèrent pour communiquer efficacement.\n\nCe principe se décline en **4 maximes** :\n\n1. **Quantité** : donner la bonne quantité d''information (ni trop, ni trop peu)\n2. **Qualité** : dire ce qu''on croit vrai, ne pas affirmer sans preuve\n3. **Relation** (pertinence) : être pertinent, rester dans le sujet\n4. **Manière** : être clair, ordonné, éviter l''ambiguïté\n\n### L''implicature conversationnelle\nQuand une maxime est **violée volontairement**, cela produit une **implicature** :\n- « Comment va ton nouveau travail ? » — « Je me lève tous les matins à 5h. »\n- Violation de la maxime de relation → implicature : le travail est pénible\n\n## La deixis\n\nLa **deixis** désigne les éléments linguistiques dont le sens dépend du contexte d''énonciation :\n- **Personnelle** : je, tu, nous (qui parle ?)\n- **Spatiale** : ici, là-bas, ce (où ?)\n- **Temporelle** : maintenant, hier, demain (quand ?)\n\n## La présupposition\n\nUne **présupposition** est une information considérée comme acquise :\n- « Pierre a arrêté de fumer. » → Présupposé : Pierre fumait avant."}',
  '[{"question": "Que signifie ''parler c''est agir'' selon Austin ?", "options": ["Parler est un exercice physique", "En parlant, on accomplit des actes (promettre, ordonner, etc.)", "Il faut agir avant de parler", "Parler et agir sont identiques"], "correct": 1, "explanation": "Selon Austin, chaque énoncé est un acte de langage : en disant quelque chose (acte locutoire), on accomplit une action comme promettre, ordonner, informer (acte illocutoire) et on produit un effet sur l''interlocuteur (acte perlocutoire)."},
  {"question": "Quel type d''acte illocutoire est ''Je promets de venir'' ?", "options": ["Assertif", "Directif", "Commissif", "Expressif"], "correct": 2, "explanation": "Une promesse est un acte commissif : le locuteur s''engage à faire quelque chose dans le futur. Selon la classification de Searle, les commissifs engagent le locuteur à une action future."},
  {"question": "Quelle est la maxime de Grice violée quand on change de sujet ?", "options": ["Quantité", "Qualité", "Relation (pertinence)", "Manière"], "correct": 2, "explanation": "La maxime de relation (ou pertinence) exige que la contribution soit pertinente par rapport au sujet de la conversation. Changer de sujet viole cette maxime."},
  {"question": "Qu''est-ce qu''une implicature conversationnelle ?", "options": ["Ce qui est dit explicitement", "Ce qui est communiqué sans être dit directement", "Une erreur de grammaire", "Un synonyme"], "correct": 1, "explanation": "L''implicature est ce qui est communiqué indirectement, au-delà du sens littéral, souvent par violation délibérée d''une maxime de Grice. Le locuteur sous-entend quelque chose que l''interlocuteur doit inférer."},
  {"question": "Qu''est-ce que la deixis ?", "options": ["L''étude des sons", "Des éléments dont le sens dépend du contexte d''énonciation", "L''analyse des morphèmes", "La structure de la phrase"], "correct": 1, "explanation": "La deixis concerne les éléments linguistiques dont le sens varie selon le contexte : ''je'' désigne celui qui parle, ''ici'' l''endroit où l''on se trouve, ''maintenant'' le moment de l''énonciation."}]',
  '[{"question": "Quels sont les trois actes de langage selon Austin ?", "answer": "1. Acte locutoire : le fait de prononcer des mots. 2. Acte illocutoire : l''intention (promettre, ordonner). 3. Acte perlocutoire : l''effet produit sur l''interlocuteur (convaincre, effrayer).", "category": "Définition"},
  {"question": "Quelles sont les 4 maximes de Grice ?", "answer": "1. Quantité (bonne dose d''info). 2. Qualité (dire vrai). 3. Relation (être pertinent). 4. Manière (être clair et ordonné). Elles forment le principe de coopération.", "category": "Définition"},
  {"question": "Qu''est-ce qu''une présupposition ?", "answer": "Une présupposition est une information implicitement tenue pour vraie dans un énoncé. Exemple : ''Pierre a arrêté de fumer'' présuppose que Pierre fumait avant.", "category": "Définition"},
  {"question": "Quels sont les 5 types d''actes illocutoires selon Searle ?", "answer": "1. Assertifs (affirmer). 2. Directifs (ordonner, demander). 3. Commissifs (promettre). 4. Expressifs (remercier, féliciter). 5. Déclaratifs (déclarer mari et femme).", "category": "Définition"}]',
  true, 1);

  -- ============================================================
  -- LINGUISTIQUE - Chapitre 7 : Sociolinguistique
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_linguistique_id, 'sociolinguistique', 7, 'Sociolinguistique', 'Les rapports entre langue et société', 7)
  RETURNING id INTO v_ch_23;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_23, 'sociolinguistique', 'Sociolinguistique',
  'La sociolinguistique étudie les rapports entre langue et société. Ce chapitre couvre la variation linguistique, la diglossie, le bilinguisme, les registres de langue et les politiques linguistiques.',
  '{"key_points": ["La sociolinguistique étudie les liens entre langue et société", "La variation linguistique peut être géographique, sociale, stylistique ou historique", "La diglossie est la coexistence de deux langues avec des fonctions différentes", "Le bilinguisme est la capacité d''utiliser deux langues couramment", "Les registres de langue : soutenu, courant, familier, populaire", "La politique linguistique décide du statut des langues dans un pays", "Le Mali est un pays multilingue avec le français comme langue officielle et le bambara comme langue nationale dominante"], "content": "## Qu''est-ce que la sociolinguistique ?\n\nLa sociolinguistique étudie les **rapports entre langue et société**. Elle analyse comment les facteurs sociaux (âge, classe sociale, région, sexe) influencent l''usage de la langue.\n\n## La variation linguistique\n\nLa langue n''est pas uniforme : elle varie selon plusieurs facteurs.\n\n### Types de variation\n\n| Type | Facteur | Exemple |\n|------|---------|--------|\n| **Diatopique** (géographique) | Région | Accent parisien vs accent malien |\n| **Diastratique** (sociale) | Classe sociale | Vocabulaire spécialisé vs courant |\n| **Diaphasique** (stylistique) | Situation | Registre formel vs informel |\n| **Diachronique** (historique) | Époque | Français du XVIIᵉ siècle vs aujourd''hui |\n\n## Les registres de langue\n\n| Registre | Caractéristiques | Exemple |\n|----------|------------------|---------|\n| **Soutenu** | Vocabulaire riche, syntaxe élaborée | « Je vous saurais gré de bien vouloir... » |\n| **Courant** | Standard, correct, neutre | « Pouvez-vous m''aider ? » |\n| **Familier** | Relâché, abréviations | « Tu peux m''aider ? » |\n| **Populaire/Argot** | Marques d''oralité, argot | « Tu peux m''filer un coup d''main ? » |\n\n## Diglossie\n\nLa **diglossie** (Ferguson, 1959) est une situation où deux langues ou variétés coexistent dans une communauté avec des **fonctions sociales différentes** :\n\n- **Variété haute (H)** : utilisée dans les contextes formels (administration, école, médias)\n- **Variété basse (B)** : utilisée dans la vie quotidienne, en famille\n\n### Exemple au Mali\n- **Variété haute** : le français (langue officielle, administration, école)\n- **Variété basse** : le bambara, le peul, le songhaï (communication quotidienne)\n\n## Le bilinguisme et le multilinguisme\n\n- **Bilinguisme** : capacité d''un individu à utiliser **deux langues**\n- **Multilinguisme** : utilisation de **plusieurs langues** dans une communauté\n\nLe Mali est un pays **multilingue** avec :\n- Le **français** comme langue officielle\n- 13 **langues nationales** (bambara, peul, songhaï, dogon, soninké, etc.)\n- Le **bambara** comme langue véhiculaire dominante (parlée par ~80% de la population)\n\n## Politique linguistique\n\nLa **politique linguistique** désigne les décisions d''un État concernant les langues :\n- Choix de la **langue officielle**\n- Reconnaissance de **langues nationales**\n- **Aménagement linguistique** : normalisation, enseignement\n- Questions d''**identité culturelle** et de **droits linguistiques**"}',
  '[{"question": "Qu''est-ce que la variation diatopique ?", "options": ["Variation selon la classe sociale", "Variation selon la région géographique", "Variation selon la situation", "Variation selon l''époque"], "correct": 1, "explanation": "La variation diatopique est la variation linguistique liée à la région géographique. Elle explique les différences d''accent, de vocabulaire et de prononciation entre le français parlé à Paris, au Mali, au Québec, etc."},
  {"question": "Qu''est-ce que la diglossie ?", "options": ["L''incapacité de parler", "La coexistence de deux langues avec des fonctions différentes", "Le fait de parler trois langues", "Un trouble du langage"], "correct": 1, "explanation": "La diglossie (Ferguson, 1959) est une situation où deux langues ou variétés coexistent dans une communauté avec des fonctions sociales différentes : une variété haute (formelle) et une variété basse (quotidienne)."},
  {"question": "Quelle est la langue officielle du Mali ?", "options": ["Le bambara", "Le peul", "Le français", "L''arabe"], "correct": 2, "explanation": "Le français est la langue officielle du Mali, utilisée dans l''administration, l''éducation et les médias officiels. Le bambara est la langue nationale la plus parlée (~80% de la population)."},
  {"question": "Quel registre utilise-t-on dans une lettre administrative ?", "options": ["Familier", "Populaire", "Courant", "Soutenu"], "correct": 3, "explanation": "Le registre soutenu est utilisé dans les situations formelles comme les lettres administratives, les discours officiels et les écrits académiques. Il se caractérise par un vocabulaire riche et une syntaxe élaborée."},
  {"question": "Combien de langues nationales le Mali reconnaît-il ?", "options": ["3", "7", "13", "20"], "correct": 2, "explanation": "Le Mali reconnaît 13 langues nationales, dont le bambara, le peul, le songhaï, le dogon, le soninké, le tamasheq, le bobo, etc., en plus du français comme langue officielle."}]',
  '[{"question": "Qu''est-ce que la sociolinguistique ?", "answer": "La sociolinguistique est la branche de la linguistique qui étudie les rapports entre langue et société. Elle analyse comment les facteurs sociaux (âge, sexe, classe, région) influencent les pratiques linguistiques.", "category": "Définition"},
  {"question": "Quels sont les quatre types de variation linguistique ?", "answer": "1. Diatopique (géographique/régionale). 2. Diastratique (sociale/classe). 3. Diaphasique (stylistique/situation). 4. Diachronique (historique/évolution dans le temps).", "category": "Définition"},
  {"question": "Qu''est-ce que le bilinguisme ?", "answer": "Le bilinguisme est la capacité d''un individu à utiliser couramment deux langues dans différentes situations de communication. Il se distingue du multilinguisme qui implique plus de deux langues.", "category": "Définition"},
  {"question": "Qu''est-ce qu''une langue véhiculaire ?", "answer": "Une langue véhiculaire est une langue utilisée comme moyen de communication entre des locuteurs de langues maternelles différentes. Au Mali, le bambara sert de langue véhiculaire parlée par environ 80% de la population.", "category": "Définition"}]',
  true, 1);

  -- ============================================================
  -- LINGUISTIQUE - Chapitre 8 : Linguistique Africaine
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_linguistique_id, 'linguistique-africaine', 8, 'Linguistique Africaine', 'Les langues d''Afrique et leurs caractéristiques', 8)
  RETURNING id INTO v_ch_24;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_24, 'linguistique-africaine', 'Linguistique Africaine',
  'L''Afrique est le continent le plus linguistiquement divers avec plus de 2000 langues. Ce chapitre explore les grandes familles linguistiques africaines, les langues du Mali et les caractéristiques typologiques des langues africaines.',
  '{"key_points": ["L''Afrique compte plus de 2000 langues, soit environ un tiers des langues du monde", "Les 4 grandes familles linguistiques africaines : Niger-Congo, Afro-Asiatique, Nilo-Saharienne, Khoïsan", "Le bambara appartient à la famille mandé (Niger-Congo)", "Les langues à tons utilisent la hauteur musicale pour distinguer les sens", "Les classes nominales sont un système de classification des noms dans de nombreuses langues africaines", "La tradition orale (griots, contes, proverbes) joue un rôle central dans la transmission culturelle", "La transcription des langues africaines utilise des alphabets adaptés"], "content": "## La diversité linguistique africaine\n\nL''Afrique est le continent le plus **linguistiquement divers** du monde avec plus de **2000 langues**, soit environ un tiers des langues de la planète.\n\n## Les grandes familles linguistiques\n\n### 1. Niger-Congo (la plus grande)\n- Environ **1500 langues**\n- Comprend les langues bantoues (swahili, zoulou) et les langues mandé\n- Langues du Mali : **bambara, malinké, dioula** (famille mandé), **peul** (famille atlantique)\n\n### 2. Afro-Asiatique\n- Environ **300 langues**\n- Comprend l''arabe, le berbère, le haoussa, l''amharique\n- Présente au nord et à l''est de l''Afrique\n\n### 3. Nilo-Saharienne\n- Environ **200 langues**\n- Comprend le songhaï, le kanouri, le zarma\n- Présente au Sahel et en Afrique de l''Est\n\n### 4. Khoïsan\n- Environ **30 langues**\n- Caractérisées par les **clics** (consonnes à mécanisme vélaire)\n- Présentes en Afrique australe\n\n## Les langues du Mali\n\nLe Mali compte **plus de 60 langues** dont 13 langues nationales :\n\n| Langue | Famille | Locuteurs estimés |\n|--------|---------|------------------|\n| **Bambara** | Mandé | ~15 millions (L1+L2) |\n| **Peul (Fulfulde)** | Atlantique | ~3 millions |\n| **Songhaï** | Nilo-Saharienne | ~2 millions |\n| **Soninké** | Mandé | ~1 million |\n| **Dogon** | Dogon (isolat) | ~800 000 |\n| **Tamasheq** | Berbère | ~500 000 |\n\n## Caractéristiques typologiques\n\n### Les tons\nBeaucoup de langues africaines sont des **langues à tons** : la hauteur musicale de la voix change le sens du mot.\n\nEn bambara :\n- **bá** (ton haut) = mère\n- **bà** (ton bas) = chèvre\n\n### Les classes nominales\nDe nombreuses langues africaines (surtout bantoues et atlantiques) classent les noms en **catégories** (humains, animaux, objets, abstraits) avec des préfixes spécifiques.\n\nEn peul :\n- **o-** pour les humains singulier : gorko (homme)\n- **ɓe-** pour les humains pluriel : worɓe (hommes)\n\n### L''ordre SOV\nPlusieurs langues africaines utilisent l''ordre **SOV** (Sujet-Objet-Verbe), différent du français (SVO).\n\nEn bambara : « Muso ye mango dun » (Femme + mangue + manger = La femme mange la mangue)\n\n## La tradition orale\n\nEn Afrique, la **tradition orale** est un mode fondamental de transmission du savoir :\n- Les **griots** (djéli en bambara) sont les gardiens de la mémoire collective\n- Les **contes**, **proverbes**, **épopées** transmettent valeurs et histoire\n- L''**épopée de Soundjata** est un exemple majeur de littérature orale mandingue"}',
  '[{"question": "Combien de langues sont parlées en Afrique environ ?", "options": ["Environ 500", "Environ 1000", "Plus de 2000", "Plus de 5000"], "correct": 2, "explanation": "L''Afrique compte plus de 2000 langues, ce qui représente environ un tiers des langues du monde. C''est le continent le plus linguistiquement divers de la planète."},
  {"question": "À quelle famille linguistique appartient le bambara ?", "options": ["Afro-Asiatique", "Nilo-Saharienne", "Niger-Congo (famille mandé)", "Khoïsan"], "correct": 2, "explanation": "Le bambara appartient à la famille mandé, elle-même partie de la grande famille Niger-Congo, la plus grande famille linguistique d''Afrique avec environ 1500 langues."},
  {"question": "Qu''est-ce qu''une langue à tons ?", "options": ["Une langue avec beaucoup de voyelles", "Une langue où la hauteur musicale change le sens des mots", "Une langue qui se chante", "Une langue sans consonnes"], "correct": 1, "explanation": "Une langue à tons utilise la hauteur musicale de la voix pour distinguer des mots. En bambara, ''bá'' (ton haut) signifie ''mère'' et ''bà'' (ton bas) signifie ''chèvre''."},
  {"question": "Quel est le rôle des griots dans la tradition orale africaine ?", "options": ["Cuisiniers", "Gardiens de la mémoire collective et transmetteurs de l''histoire", "Chefs de village", "Agriculteurs"], "correct": 1, "explanation": "Les griots (djéli en bambara) sont les gardiens de la mémoire collective. Ils transmettent l''histoire, les généalogies, les valeurs et les traditions à travers les contes, proverbes et épopées."},
  {"question": "Quel ordre des mots utilisent beaucoup de langues africaines ?", "options": ["SVO comme le français", "SOV (Sujet-Objet-Verbe)", "VSO", "OVS"], "correct": 1, "explanation": "De nombreuses langues africaines (dont le bambara) utilisent l''ordre SOV : le verbe vient à la fin de la phrase. Exemple en bambara : ''Muso ye mango dun'' (Femme mangue manger)."}]',
  '[{"question": "Quelles sont les 4 grandes familles linguistiques africaines ?", "answer": "1. Niger-Congo (~1500 langues, la plus grande). 2. Afro-Asiatique (~300 langues). 3. Nilo-Saharienne (~200 langues). 4. Khoïsan (~30 langues, avec des clics).", "category": "Définition"},
  {"question": "Qu''est-ce qu''un griot ?", "answer": "Un griot (djéli en bambara) est un gardien de la tradition orale en Afrique de l''Ouest. Il transmet l''histoire, les généalogies, les valeurs et la culture à travers les récits, chants et épopées.", "category": "Définition"},
  {"question": "Qu''est-ce que les classes nominales ?", "answer": "Les classes nominales sont un système de classification des noms en catégories (humains, animaux, objets, etc.) marquées par des préfixes ou suffixes spécifiques. Ce système est courant dans les langues bantoues et atlantiques.", "category": "Définition"},
  {"question": "Combien de langues nationales le Mali reconnaît-il et lesquelles sont les principales ?", "answer": "Le Mali reconnaît 13 langues nationales. Les principales sont : le bambara (la plus parlée, ~15 millions), le peul, le songhaï, le soninké, le dogon et le tamasheq. Le français est la langue officielle.", "category": "Définition"}]',
  true, 1);

  -- ============================================================
  -- LINGUISTIQUE - Chapitre 9 : Stylistique et Rhétorique
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_linguistique_id, 'stylistique-rhetorique', 9, 'Stylistique et Rhétorique', 'Les figures de style et l''art de persuader', 9)
  RETURNING id INTO v_ch_25;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_25, 'stylistique-rhetorique', 'Stylistique et Rhétorique',
  'La stylistique étudie les procédés d''expression et les effets de style. La rhétorique est l''art de persuader par le discours. Ce chapitre couvre les principales figures de style et les techniques rhétoriques.',
  '{"key_points": ["La stylistique analyse les procédés d''expression et les effets de style", "La rhétorique est l''art de persuader par le discours (Aristote)", "Les figures d''analogie : métaphore, comparaison, personnification, allégorie", "Les figures d''opposition : antithèse, oxymore, antiphrase", "Les figures d''amplification : hyperbole, gradation, anaphore", "Les figures d''atténuation : litote, euphémisme", "Les trois moyens de persuasion d''Aristote : ethos, pathos, logos"], "content": "## Les figures de style\n\n### Figures d''analogie (ressemblance)\n\n- **Comparaison** : rapprochement avec un outil de comparaison (comme, tel, semblable à)\n  - « Il est **fort comme** un lion. »\n\n- **Métaphore** : comparaison **sans** outil de comparaison\n  - « Cet homme est **un lion**. »\n\n- **Personnification** : attribuer des caractéristiques humaines à un objet ou un animal\n  - « Le vent **murmure** dans les arbres. »\n\n- **Allégorie** : représentation d''une idée abstraite par une image concrète\n  - La Justice représentée par une femme aux yeux bandés tenant une balance\n\n### Figures d''opposition (contraste)\n\n- **Antithèse** : opposition de deux idées dans la même phrase\n  - « Être ou ne pas être. » (Shakespeare)\n\n- **Oxymore** : association de deux mots contradictoires\n  - « Cette **obscure clarté**. » (Corneille)\n\n- **Antiphrase** : dire le contraire de ce qu''on pense (ironie)\n  - « Quel **beau** temps ! » (quand il pleut)\n\n### Figures d''amplification (insistance)\n\n- **Hyperbole** : exagération\n  - « Je meurs de faim. », « Je te l''ai dit **mille fois**. »\n\n- **Gradation** : succession de termes d''intensité croissante ou décroissante\n  - « Va, cours, **vole** et nous venge ! » (Corneille)\n\n- **Anaphore** : répétition d''un mot ou groupe de mots en début de phrase/vers\n  - « **Moi**, président... **Moi**, président... **Moi**, président... »\n\n- **Accumulation** (ou énumération) : juxtaposition de plusieurs termes\n  - « Femmes, moines, vieillards, tout était descendu. » (La Fontaine)\n\n### Figures d''atténuation\n\n- **Litote** : dire moins pour suggérer plus\n  - « Ce n''est **pas mal**. » (= c''est bien)\n  - « Va, je ne te hais point. » (= je t''aime) (Corneille)\n\n- **Euphémisme** : atténuer une réalité désagréable\n  - « Il nous a **quittés**. » (= il est mort)\n\n## La rhétorique\n\n### Les trois moyens de persuasion (Aristote)\n\n1. **Ethos** : la crédibilité de l''orateur (son image, son autorité)\n2. **Pathos** : l''appel aux émotions de l''auditoire\n3. **Logos** : la logique et la raison de l''argumentation\n\n### Les parties du discours rhétorique\n1. **Exorde** : introduction qui capte l''attention\n2. **Narration** : exposé des faits\n3. **Argumentation** : présentation des arguments\n4. **Péroraison** : conclusion qui marque les esprits"}',
  '[{"question": "Quelle est la différence entre comparaison et métaphore ?", "options": ["Aucune différence", "La comparaison utilise un outil de comparaison, la métaphore non", "La métaphore est plus courte", "La comparaison est orale, la métaphore écrite"], "correct": 1, "explanation": "La comparaison utilise un outil de comparaison (comme, tel, semblable à) : ''Il est fort COMME un lion''. La métaphore établit le même rapprochement mais SANS outil : ''Cet homme est un lion''."},
  {"question": "Qu''est-ce qu''un oxymore ?", "options": ["Une exagération", "L''association de deux mots contradictoires", "Une répétition", "Un mot inventé"], "correct": 1, "explanation": "L''oxymore est l''association de deux termes de sens contradictoires dans une même expression. Exemple : ''cette obscure clarté'' (Corneille), où ''obscure'' et ''clarté'' s''opposent."},
  {"question": "Qu''est-ce que l''anaphore ?", "options": ["La répétition d''un mot en début de phrase ou vers", "L''opposition de deux idées", "L''exagération d''une idée", "La suppression d''un mot"], "correct": 0, "explanation": "L''anaphore est la répétition d''un même mot ou groupe de mots au début de phrases ou de vers successifs. Elle crée un effet d''insistance et de rythme."},
  {"question": "Quel moyen de persuasion d''Aristote fait appel aux émotions ?", "options": ["Ethos", "Pathos", "Logos", "Exorde"], "correct": 1, "explanation": "Le pathos est le moyen de persuasion qui fait appel aux émotions de l''auditoire (peur, pitié, colère, joie). L''ethos repose sur la crédibilité de l''orateur et le logos sur la logique."},
  {"question": "Qu''est-ce qu''une litote ?", "options": ["Une exagération", "Dire le contraire de ce qu''on pense", "Dire moins pour suggérer plus", "Répéter un mot plusieurs fois"], "correct": 2, "explanation": "La litote consiste à dire moins pour suggérer plus. Exemple : ''Ce n''est pas mal'' signifie en réalité ''C''est bien''. ''Je ne te hais point'' signifie ''Je t''aime'' (Corneille)."}]',
  '[{"question": "Qu''est-ce que la personnification ?", "answer": "La personnification est une figure de style qui attribue des caractéristiques humaines à un objet, un animal ou une idée abstraite. Exemple : ''Le vent murmure dans les arbres.''", "category": "Définition"},
  {"question": "Quels sont les trois moyens de persuasion selon Aristote ?", "answer": "1. Ethos : la crédibilité et l''image de l''orateur. 2. Pathos : l''appel aux émotions du public. 3. Logos : la logique et le raisonnement de l''argumentation.", "category": "Définition"},
  {"question": "Qu''est-ce qu''un euphémisme ?", "answer": "L''euphémisme est une figure d''atténuation qui consiste à remplacer une expression jugée trop directe ou désagréable par une formulation plus douce. Exemple : ''Il nous a quittés'' au lieu de ''Il est mort''.", "category": "Définition"},
  {"question": "Qu''est-ce que la gradation ?", "answer": "La gradation est une figure d''amplification qui consiste en une succession de termes d''intensité croissante (ou décroissante). Exemple : ''Va, cours, vole et nous venge !'' (Corneille).", "category": "Définition"}]',
  true, 1);

  -- ============================================================
  -- PHILOSOPHIE TLL - Chapitre 1 : La Conscience et l'Inconscient
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_philo_id, 'conscience-inconscient', 1, 'La Conscience et l''Inconscient', 'La nature de la conscience et la découverte de l''inconscient', 1)
  RETURNING id INTO v_ch_26;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_26, 'conscience-inconscient', 'La Conscience et l''Inconscient',
  'La conscience est la capacité de l''esprit à se connaître lui-même et à connaître le monde. L''inconscient, découvert par Freud, remet en question l''idée que nous sommes pleinement maîtres de nous-mêmes.',
  '{"key_points": ["La conscience est la connaissance que l''esprit a de lui-même et du monde", "Descartes fonde la certitude sur le cogito : ''Je pense, donc je suis''", "La conscience morale distingue le bien du mal", "Freud découvre l''inconscient psychique : pulsions, désirs refoulés", "L''appareil psychique selon Freud : ça, moi, surmoi", "Le refoulement est le mécanisme qui maintient les contenus dans l''inconscient", "L''inconscient se manifeste dans les rêves, lapsus et actes manqués"], "content": "## La conscience\n\n### Définitions\n- **Conscience spontanée** : perception immédiate du monde (je vois, j''entends)\n- **Conscience réfléchie** : retour de l''esprit sur lui-même (je sais que je sais)\n- **Conscience morale** : capacité de distinguer le bien du mal\n\n### Le cogito de Descartes\nDescartes (1596-1650) cherche une vérité absolument certaine par le **doute méthodique** :\n- Je peux douter de tout : de mes sens, du monde extérieur, même des mathématiques\n- Mais je ne peux pas douter que je doute\n- **« Je pense, donc je suis »** (Cogito ergo sum)\n- La conscience est donc la première certitude, le fondement de toute connaissance\n\n### La conscience selon d''autres philosophes\n- **Husserl** : la conscience est toujours « conscience **de** quelque chose » (intentionnalité)\n- **Sartre** : la conscience est liberté, « l''existence précède l''essence »\n- **Hegel** : la conscience de soi se construit dans le rapport à l''autre (dialectique du maître et de l''esclave)\n\n## L''inconscient\n\n### La révolution freudienne\nSigmund Freud (1856-1939) bouleverse la philosophie en montrant que l''homme **n''est pas maître dans sa propre maison** :\n- Des pensées, désirs et souvenirs existent en nous **sans que nous en ayons conscience**\n- Le **refoulement** maintient dans l''inconscient les contenus inacceptables pour la conscience\n\n### L''appareil psychique (seconde topique)\n\n| Instance | Fonction | Principe |\n|----------|----------|----------|\n| **Ça** | Pulsions, désirs inconscients | Principe de plaisir |\n| **Moi** | Médiateur, s''adapte à la réalité | Principe de réalité |\n| **Surmoi** | Intériorisation des interdits moraux | Censure, idéal |\n\n### Les manifestations de l''inconscient\n- **Les rêves** : « voie royale vers l''inconscient » (Freud)\n- **Les lapsus** : erreurs de langage révélatrices\n- **Les actes manqués** : oublis, maladresses significatives\n- **Les symptômes névrotiques** : manifestations de conflits inconscients\n\n### Critique de l''inconscient\n- **Sartre** rejette l''inconscient : il y voit une forme de **mauvaise foi**, un refus d''assumer sa liberté\n- **Alain** : l''inconscient est un « autre moi » commode qui déresponsabilise\n- La question : l''inconscient est-il une excuse ou une explication ?"}',
  '[{"question": "Que signifie le cogito de Descartes ?", "options": ["Le corps existe avant l''esprit", "La pensée prouve l''existence du sujet pensant", "L''inconscient dirige nos actions", "Les sens sont toujours fiables"], "correct": 1, "explanation": "Le cogito (''Je pense, donc je suis'') signifie que l''acte même de penser prouve l''existence du sujet qui pense. Même si je doute de tout, le fait que je doute prouve que j''existe en tant qu''être pensant."},
  {"question": "Quelles sont les trois instances de l''appareil psychique selon Freud ?", "options": ["Corps, âme, esprit", "Ça, moi, surmoi", "Conscient, préconscient, inconscient", "Raison, volonté, désir"], "correct": 1, "explanation": "Freud distingue le ça (pulsions inconscientes), le moi (médiateur avec la réalité) et le surmoi (intériorisation des interdits moraux). Ces trois instances interagissent et peuvent entrer en conflit."},
  {"question": "Qu''est-ce que le refoulement selon Freud ?", "options": ["L''oubli volontaire", "Le mécanisme qui maintient des contenus inacceptables dans l''inconscient", "Un trouble de la mémoire", "La suppression des émotions"], "correct": 1, "explanation": "Le refoulement est le mécanisme psychique inconscient qui empêche les désirs, souvenirs ou pensées inacceptables d''accéder à la conscience. Les contenus refoulés restent actifs dans l''inconscient."},
  {"question": "Pourquoi Sartre rejette-t-il la notion d''inconscient ?", "options": ["Parce qu''il ne croit pas en la psychologie", "Parce qu''il y voit une forme de mauvaise foi qui déresponsabilise", "Parce qu''il préfère la notion de subconscient", "Parce qu''il est d''accord avec Descartes"], "correct": 1, "explanation": "Sartre rejette l''inconscient car il considère que c''est une façon de fuir sa responsabilité et sa liberté. Pour Sartre, invoquer l''inconscient est une forme de mauvaise foi : l''homme est toujours libre et responsable de ses choix."},
  {"question": "Comment l''inconscient se manifeste-t-il selon Freud ?", "options": ["Par la méditation", "Par les rêves, lapsus et actes manqués", "Par la raison logique", "Par les exercices physiques"], "correct": 1, "explanation": "Selon Freud, l''inconscient se manifeste à travers les rêves (''voie royale vers l''inconscient''), les lapsus (erreurs de langage révélatrices), les actes manqués (oublis significatifs) et les symptômes névrotiques."}]',
  '[{"question": "Qu''est-ce que la conscience réfléchie ?", "answer": "La conscience réfléchie est le retour de l''esprit sur lui-même : la capacité de savoir que l''on sait, de penser que l''on pense. Elle se distingue de la conscience spontanée (perception immédiate du monde).", "category": "Citation/Idée"},
  {"question": "Que signifie ''l''homme n''est pas maître dans sa propre maison'' (Freud) ?", "answer": "Cette formule signifie que l''homme n''est pas entièrement conscient de ce qui le motive. L''inconscient (pulsions, désirs refoulés) influence nos pensées et actions sans que nous en ayons conscience.", "category": "Citation/Idée"},
  {"question": "Qu''est-ce que l''intentionnalité de la conscience selon Husserl ?", "answer": "L''intentionnalité signifie que la conscience est toujours ''conscience DE quelque chose''. Elle est toujours dirigée vers un objet. Il n''y a pas de conscience vide : toute conscience est conscience de quelque chose.", "category": "Citation/Idée"},
  {"question": "Quel est le rôle du surmoi ?", "answer": "Le surmoi est l''instance psychique qui intériorise les interdits moraux et sociaux (éducation, lois, normes). Il joue le rôle de censeur et d''idéal, en s''opposant aux pulsions du ça.", "category": "Citation/Idée"}]',
  false, 1);

  -- ============================================================
  -- PHILOSOPHIE TLL - Chapitre 2 : Le Langage et la Pensée
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_philo_id, 'langage-pensee', 2, 'Le Langage et la Pensée', 'Les rapports entre langage et pensée', 2)
  RETURNING id INTO v_ch_27;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_27, 'langage-pensee', 'Le Langage et la Pensée',
  'Le langage est-il un simple instrument de communication ou constitue-t-il notre pensée ? Ce chapitre explore les rapports entre langage et pensée à travers Saussure, l''hypothèse Sapir-Whorf et les théories contemporaines.',
  '{"key_points": ["Le langage est la faculté humaine de communiquer par des signes", "Saussure définit le signe linguistique comme l''union du signifiant et du signifié", "L''hypothèse Sapir-Whorf : la langue influence la pensée (relativisme linguistique)", "Hegel : sans les mots, la pensée reste confuse et indéterminée", "Bergson : le langage trahit la pensée en la figeant", "La double articulation du langage (Martinet) : monèmes et phonèmes", "Le langage est propre à l''homme : les animaux communiquent mais ne parlent pas"], "content": "## Langage et communication\n\n### Définitions\n- **Langage** : faculté humaine universelle de communiquer au moyen de signes\n- **Langue** : système de signes particulier (français, bambara, anglais)\n- **Parole** : utilisation individuelle et concrète de la langue\n\n### Le langage est-il propre à l''homme ?\n- **Descartes** : seul l''homme possède le langage, car seul il a la raison\n- Les animaux communiquent (abeilles, dauphins) mais ne possèdent pas un **langage articulé**\n- La **double articulation** (Martinet) distingue le langage humain :\n  - 1ʳᵉ articulation : les **monèmes** (unités de sens) : « in-croy-able »\n  - 2ᵉ articulation : les **phonèmes** (unités de son) : /ɛ̃/, /k/, /r/\n\n## Langage et pensée : quel rapport ?\n\n### Thèse 1 : Le langage est un instrument de la pensée\n- Le langage sert à **exprimer** une pensée qui existe déjà\n- La pensée précède le langage\n- **Bergson** : le langage est un outil imparfait qui **trahit** la pensée\n  - Les mots sont généraux, la pensée est singulière\n  - Le langage **fige** ce qui est mouvant et vivant\n\n### Thèse 2 : Le langage constitue la pensée\n- Sans langage, pas de pensée claire\n- **Hegel** : « C''est dans les mots que nous pensons. » Sans les mots, la pensée reste **confuse et indéterminée**\n- Le mot ne vient pas après la pensée : penser, c''est déjà parler intérieurement\n\n### Thèse 3 : La langue structure la pensée (relativisme linguistique)\n- **Hypothèse Sapir-Whorf** : la structure de notre langue influence notre façon de percevoir et de penser le monde\n- Exemple : les Inuits ont plusieurs mots pour « neige », les Bambaras plusieurs mots pour « riz »\n- **Version forte** : la langue détermine la pensée (déterminisme linguistique)\n- **Version faible** : la langue influence la pensée sans la déterminer\n\n## Les fonctions du langage (Jakobson)\n\n| Fonction | Centrée sur | Exemple |\n|----------|------------|--------|\n| **Référentielle** | Le contexte | « Il pleut. » |\n| **Émotive** | L''émetteur | « Hélas ! » |\n| **Conative** | Le récepteur | « Écoute-moi ! » |\n| **Phatique** | Le contact | « Allô ? Tu m''entends ? » |\n| **Métalinguistique** | Le code | « Que signifie ce mot ? » |\n| **Poétique** | Le message | Jeux de mots, rimes |\n\n## Le pouvoir du langage\n- Le langage peut **manipuler** : propagande, publicité, rhétorique\n- Le langage peut **libérer** : poésie, littérature, revendications\n- Nommer les choses, c''est exercer un **pouvoir** sur elles"}',
  '[{"question": "Selon Hegel, quel est le rapport entre langage et pensée ?", "options": ["Le langage trahit la pensée", "C''est dans les mots que nous pensons", "Le langage est inutile pour penser", "La pensée est indépendante du langage"], "correct": 1, "explanation": "Pour Hegel, pensée et langage sont indissociables : ''C''est dans les mots que nous pensons.'' Sans les mots, la pensée reste confuse et indéterminée. Le langage ne vient pas après la pensée, il la constitue."},
  {"question": "Qu''est-ce que l''hypothèse Sapir-Whorf ?", "options": ["Le langage est universel", "La structure de la langue influence notre façon de penser", "Toutes les langues sont identiques", "Le langage est inné"], "correct": 1, "explanation": "L''hypothèse Sapir-Whorf (relativisme linguistique) soutient que la structure de notre langue influence notre perception et notre pensée du monde. Les catégories de notre langue orientent notre expérience."},
  {"question": "Pourquoi Bergson considère-t-il que le langage trahit la pensée ?", "options": ["Parce que les mots sont trop précis", "Parce que les mots sont généraux et figent la pensée singulière", "Parce que le langage est trop rapide", "Parce que le langage est réservé aux savants"], "correct": 1, "explanation": "Pour Bergson, les mots sont généraux et abstraits tandis que la pensée est singulière, mouvante et vivante. En mettant des mots sur nos pensées, nous les simplifions et les figeons."},
  {"question": "Qu''est-ce que la double articulation du langage selon Martinet ?", "options": ["Langage oral et langage écrit", "L''articulation en monèmes (sens) et en phonèmes (sons)", "Le sujet et le verbe", "La forme et le fond"], "correct": 1, "explanation": "La double articulation selon Martinet distingue deux niveaux : la 1ʳᵉ articulation en monèmes (unités de sens : in-croy-able) et la 2ᵉ articulation en phonèmes (unités de son : /ɛ̃/, /k/, /r/)."},
  {"question": "Quelle fonction du langage est centrée sur le récepteur ?", "options": ["Référentielle", "Émotive", "Conative", "Poétique"], "correct": 2, "explanation": "La fonction conative est centrée sur le récepteur : elle vise à agir sur lui (ordres, prières, conseils). Exemple : ''Écoute-moi !'', ''Fais attention !''"}]',
  '[{"question": "Que signifie ''relativisme linguistique'' ?", "answer": "Le relativisme linguistique (hypothèse Sapir-Whorf) soutient que la structure de notre langue influence notre façon de percevoir et penser le monde. Chaque langue découpe la réalité différemment.", "category": "Citation/Idée"},
  {"question": "Quelle est la thèse de Bergson sur le langage ?", "answer": "Bergson considère que le langage trahit la pensée. Les mots sont généraux et figent ce qui est singulier et mouvant dans notre pensée intérieure. Le langage est un outil imparfait d''expression.", "category": "Citation/Idée"},
  {"question": "Quelles sont les 6 fonctions du langage selon Jakobson ?", "answer": "1. Référentielle (contexte). 2. Émotive (émetteur). 3. Conative (récepteur). 4. Phatique (contact). 5. Métalinguistique (code). 6. Poétique (message).", "category": "Citation/Idée"},
  {"question": "Pourquoi dit-on que le langage est propre à l''homme ?", "answer": "Bien que les animaux communiquent, seul l''homme possède un langage articulé avec double articulation (monèmes et phonèmes), permettant de créer une infinité d''énoncés avec un nombre fini d''éléments.", "category": "Citation/Idée"}]',
  true, 1);

  -- ============================================================
  -- PHILOSOPHIE TLL - Chapitre 3 : L'Art et l'Esthétique
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_philo_id, 'art-esthetique', 3, 'L''Art et l''Esthétique', 'La nature du beau et la fonction de l''art', 3)
  RETURNING id INTO v_ch_28;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_28, 'art-esthetique', 'L''Art et l''Esthétique',
  'L''esthétique est la branche de la philosophie qui s''interroge sur le beau et l''art. Ce chapitre explore les conceptions du beau de Platon à l''art contemporain, et les fonctions de l''art.',
  '{"key_points": ["L''esthétique est la réflexion philosophique sur le beau et l''art", "Platon : le Beau est une Idée éternelle, l''art est imitation (mimésis) éloignée du vrai", "Aristote : l''art imite la nature mais la perfectionne (catharsis)", "Kant : le jugement de goût est subjectif mais prétend à l''universalité", "Hegel : l''art est une manifestation sensible de l''Idée", "L''art contemporain remet en question les critères traditionnels du beau", "L''art africain a ses propres critères esthétiques liés à la fonction sociale"], "content": "## Qu''est-ce que le Beau ?\n\n### Le Beau selon Platon\n- Le **Beau en soi** est une **Idée** éternelle, parfaite et immuable\n- Les belles choses du monde sensible ne sont que des **copies imparfaites** du Beau idéal\n- L''art est **mimésis** (imitation) : il copie le monde sensible, qui est lui-même copie des Idées\n- L''art est donc une **copie de copie**, éloignée de deux degrés de la vérité\n- Platon méfie de l''art car il s''adresse aux **émotions** et non à la raison\n\n### Le Beau selon Kant\n- Le jugement esthétique est **désintéressé** : on apprécie le beau sans vouloir le posséder\n- « Est beau ce qui plaît **universellement sans concept** »\n- Le goût est subjectif mais **prétend à l''universalité** : quand je dis « c''est beau », j''attends que les autres soient d''accord\n- Le **sublime** : sentiment face à ce qui dépasse notre imagination (tempête, montagne immense)\n\n### Le Beau selon Hegel\n- L''art est la **manifestation sensible de l''Idée** (l''Absolu)\n- L''art rend visible ce qui est invisible (les idées, les sentiments, le divin)\n- Hegel annonce la « **mort de l''art** » : l''art ne suffit plus à exprimer la vérité, remplacé par la philosophie\n\n## Les fonctions de l''art\n\n### 1. L''art comme imitation (mimésis)\n- L''art reproduit la réalité : peinture réaliste, photographie, roman naturaliste\n- **Aristote** : l''art n''imite pas servilement, il **perfectionne** la nature\n- La **catharsis** : l''art (la tragédie) purifie les passions en les représentant\n\n### 2. L''art comme expression\n- L''art exprime les **émotions** et la **subjectivité** de l''artiste\n- Mouvement romantique : l''artiste est un génie qui exprime son âme\n\n### 3. L''art comme engagement\n- L''art peut dénoncer les injustices et transformer la société\n- **Sartre** : la littérature engagée, l''écrivain est responsable devant l''Histoire\n- L''art africain : les œuvres de **Senghor**, **Césaire**, **Fanon** utilisent l''art pour lutter contre la colonisation\n\n### 4. L''art comme création\n- L''art ne copie pas, il **crée** un monde nouveau\n- L''art contemporain (Duchamp, Warhol) questionne la définition même de l''art\n- « L''art est un mensonge qui nous fait comprendre la vérité » (Picasso)\n\n## L''esthétique africaine\n- L''art africain traditionnel est **fonctionnel** : masques, sculptures liés aux rituels\n- Le Beau n''est pas séparé de l''**utile** et du **sacré**\n- Senghor : l''esthétique nègre est une « esthétique de la **participation** et du **rythme** »"}',
  '[{"question": "Que signifie la mimésis chez Platon ?", "options": ["La création originale", "L''imitation de la réalité", "La destruction de l''art", "L''abstraction"], "correct": 1, "explanation": "Chez Platon, la mimésis (imitation) signifie que l''art copie le monde sensible, qui est lui-même une copie des Idées. L''art est donc une copie de copie, éloignée de deux degrés de la vérité."},
  {"question": "Que signifie ''est beau ce qui plaît universellement sans concept'' (Kant) ?", "options": ["Le beau doit être compris par la raison", "Le jugement de goût est subjectif mais prétend à l''universalité", "Seuls les experts jugent le beau", "Le beau est objectif et mesurable"], "correct": 1, "explanation": "Pour Kant, le jugement esthétique est subjectif (il vient du sentiment, pas du concept) mais il prétend à l''universalité : quand je dis ''c''est beau'', j''attends que tout le monde soit d''accord, sans pouvoir le prouver rationnellement."},
  {"question": "Qu''est-ce que la catharsis selon Aristote ?", "options": ["La création d''une œuvre d''art", "La purification des passions par leur représentation artistique", "La destruction des émotions", "L''imitation servile de la nature"], "correct": 1, "explanation": "La catharsis selon Aristote est la purification des passions (pitié, crainte) que le spectateur éprouve en assistant à une tragédie. En vivant ces émotions par procuration, il s''en libère."},
  {"question": "Que signifie la ''mort de l''art'' selon Hegel ?", "options": ["L''art n''existe plus", "L''art ne suffit plus à exprimer la vérité absolue", "Les artistes ont disparu", "L''art est devenu commercial"], "correct": 1, "explanation": "Pour Hegel, la ''mort de l''art'' ne signifie pas sa disparition mais le fait que l''art ne suffit plus à exprimer la vérité absolue. La philosophie prend le relais pour atteindre l''Absolu par le concept."},
  {"question": "Comment Senghor caractérise-t-il l''esthétique africaine ?", "options": ["Une esthétique de l''abstraction", "Une esthétique de la participation et du rythme", "Une esthétique du silence", "Une esthétique identique à l''esthétique occidentale"], "correct": 1, "explanation": "Senghor décrit l''esthétique nègre comme une esthétique de la participation et du rythme, où l''art n''est pas séparé de la vie sociale, du sacré et de la communauté."}]',
  '[{"question": "Quelle est la différence entre le beau et le sublime chez Kant ?", "answer": "Le beau procure un plaisir calme lié à la forme harmonieuse d''un objet. Le sublime est un sentiment mêlé de plaisir et d''effroi face à ce qui dépasse notre imagination (océan, tempête, montagne immense).", "category": "Citation/Idée"},
  {"question": "Pourquoi Platon se méfie-t-il de l''art ?", "answer": "Platon se méfie de l''art car : 1) L''art est une imitation (copie de copie, éloignée de la vérité). 2) L''art s''adresse aux émotions et non à la raison. 3) L''art peut corrompre l''âme en nourrissant les passions.", "category": "Citation/Idée"},
  {"question": "Qu''est-ce que l''art engagé ?", "answer": "L''art engagé utilise la création artistique pour dénoncer les injustices et transformer la société. Sartre défend la littérature engagée. En Afrique, Senghor, Césaire et Fanon ont utilisé l''art contre la colonisation.", "category": "Citation/Idée"},
  {"question": "Que signifie l''art comme ''manifestation sensible de l''Idée'' (Hegel) ?", "answer": "Pour Hegel, l''art rend visible et sensible (par les formes, couleurs, sons) ce qui est invisible et abstrait (les idées, les sentiments, l''Absolu). L''art donne une forme concrète à la vérité.", "category": "Citation/Idée"}]',
  true, 1);

  -- ============================================================
  -- PHILOSOPHIE TLL - Chapitre 4 : La Culture et la Civilisation
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_philo_id, 'culture-civilisation', 4, 'La Culture et la Civilisation', 'Nature et culture, diversité culturelle et civilisation', 4)
  RETURNING id INTO v_ch_29;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_29, 'culture-civilisation', 'La Culture et la Civilisation',
  'La culture distingue l''homme de l''animal et varie selon les sociétés. Ce chapitre explore l''opposition nature/culture, le relativisme culturel, l''ethnocentrisme et la question de la civilisation.',
  '{"key_points": ["La culture est l''ensemble des acquis transmis socialement (vs la nature : l''inné)", "La prohibition de l''inceste marque le passage de la nature à la culture (Lévi-Strauss)", "L''ethnocentrisme est la tendance à juger les autres cultures selon ses propres normes", "Le relativisme culturel affirme que chaque culture a sa propre logique et ses propres valeurs", "Fanon analyse la domination culturelle coloniale et appelle à la libération culturelle", "La civilisation peut désigner un progrès universel ou la diversité des cultures", "Le dialogue interculturel est nécessaire face à la mondialisation"], "content": "## Nature et Culture\n\n### Définitions\n- **Nature** : ce qui est **inné**, biologique, universel chez l''homme (besoins vitaux, instincts)\n- **Culture** : ce qui est **acquis**, appris, transmis socialement (langage, coutumes, techniques, art)\n\n### Le passage de la nature à la culture\n- **Lévi-Strauss** : la **prohibition de l''inceste** est la règle universelle qui marque le passage de la nature à la culture\n  - C''est la seule règle à la fois **universelle** (comme la nature) et **normative** (comme la culture)\n  - Elle oblige à l''**échange** : en interdisant d''épouser dans sa propre famille, elle crée des liens entre groupes\n\n- **Rousseau** : l''homme à l''**état de nature** est bon et libre ; la société le corrompt\n  - L''état de nature est un modèle théorique, pas une réalité historique\n\n## Diversité culturelle et ethnocentrisme\n\n### L''ethnocentrisme\n- Tendance à juger les **autres cultures** à partir des critères de **sa propre culture**\n- Considérer sa culture comme **supérieure** et les autres comme inférieures ou primitives\n- **Lévi-Strauss** (Race et Histoire) : l''ethnocentrisme est l''attitude la plus ancienne et la plus répandue\n\n### Le relativisme culturel\n- Chaque culture a sa propre **logique interne** et ses propres **valeurs**\n- Il n''y a pas de hiérarchie objective entre les cultures\n- **Montaigne** : « Chacun appelle barbarie ce qui n''est pas de son usage »\n\n### Limites du relativisme\n- Le relativisme absolu peut justifier des pratiques inacceptables\n- Certains **droits universels** transcendent les cultures (droits de l''homme)\n\n## Colonisation et culture\n\n### Frantz Fanon (1925-1961)\n- Dans *Les Damnés de la terre*, Fanon dénonce la **violence culturelle** de la colonisation\n- Le colonisateur impose sa culture comme **supérieure** et dévalorise la culture du colonisé\n- Le colonisé intériorise cette dévalorisation (**aliénation culturelle**)\n- La **décolonisation** doit être aussi **culturelle** : reconquérir sa dignité et son identité\n\n### Aimé Césaire\n- Rejette l''assimilation culturelle\n- Défend le droit des peuples à leur **identité culturelle**\n\n## Culture et civilisation\n\n### Deux sens du mot « civilisation »\n1. **Sens universel** : processus de progrès (technique, moral, politique)\n2. **Sens pluriel** : les différentes civilisations (malienne, chinoise, européenne, etc.)\n\n### Le dialogue interculturel\n- Face à la **mondialisation**, la question du dialogue entre cultures est cruciale\n- **Senghor** : la « **civilisation de l''universel** » naîtra du dialogue entre toutes les cultures\n- Ni assimilation, ni repli identitaire : **métissage culturel** et respect mutuel"}',
  '[{"question": "Selon Lévi-Strauss, qu''est-ce qui marque le passage de la nature à la culture ?", "options": ["L''invention du feu", "La prohibition de l''inceste", "L''agriculture", "L''écriture"], "correct": 1, "explanation": "Selon Lévi-Strauss, la prohibition de l''inceste marque le passage de la nature à la culture car c''est la seule règle à la fois universelle (comme la nature) et normative (comme la culture). Elle oblige à l''échange entre groupes."},
  {"question": "Qu''est-ce que l''ethnocentrisme ?", "options": ["Le respect de toutes les cultures", "La tendance à juger les autres cultures selon sa propre culture", "L''étude scientifique des cultures", "Le mélange des cultures"], "correct": 1, "explanation": "L''ethnocentrisme est la tendance à considérer sa propre culture comme supérieure et à juger les autres cultures à partir de ses propres critères et normes."},
  {"question": "Que dénonce Fanon dans ''Les Damnés de la terre'' ?", "options": ["La violence physique uniquement", "La violence culturelle de la colonisation et l''aliénation du colonisé", "Le commerce international", "La religion"], "correct": 1, "explanation": "Fanon dénonce non seulement la violence physique mais aussi la violence culturelle de la colonisation : le colonisateur impose sa culture comme supérieure, le colonisé intériorise cette dévalorisation (aliénation culturelle)."},
  {"question": "Que signifie la phrase de Montaigne ''Chacun appelle barbarie ce qui n''est pas de son usage'' ?", "options": ["Certains peuples sont barbares", "Nous jugeons ''barbares'' les pratiques qui diffèrent des nôtres", "La barbarie est universelle", "Seuls les civilisés comprennent la barbarie"], "correct": 1, "explanation": "Montaigne dénonce l''ethnocentrisme : nous qualifions de ''barbares'' les pratiques culturelles qui diffèrent des nôtres, simplement parce qu''elles nous sont étrangères, et non parce qu''elles sont objectivement inférieures."},
  {"question": "Qu''est-ce que la ''civilisation de l''universel'' selon Senghor ?", "options": ["La domination d''une seule culture", "Une civilisation née du dialogue entre toutes les cultures", "L''élimination des cultures locales", "Le retour aux traditions anciennes"], "correct": 1, "explanation": "Senghor envisage une ''civilisation de l''universel'' qui naîtrait du dialogue et du métissage entre toutes les cultures du monde, sans domination de l''une sur les autres."}]',
  '[{"question": "Quelle est la différence entre nature et culture ?", "answer": "La nature désigne ce qui est inné, biologique et universel chez l''homme. La culture désigne ce qui est acquis, appris et transmis socialement (langage, coutumes, art, techniques).", "category": "Citation/Idée"},
  {"question": "Qu''est-ce que le relativisme culturel ?", "answer": "Le relativisme culturel est la position selon laquelle chaque culture a sa propre logique et ses propres valeurs, et qu''il n''y a pas de hiérarchie objective entre les cultures. Il s''oppose à l''ethnocentrisme.", "category": "Citation/Idée"},
  {"question": "Qu''est-ce que l''aliénation culturelle selon Fanon ?", "answer": "L''aliénation culturelle est le processus par lequel le colonisé intériorise la dévalorisation de sa propre culture imposée par le colonisateur. Il en vient à considérer sa propre culture comme inférieure.", "category": "Citation/Idée"},
  {"question": "Que signifie la prohibition de l''inceste pour Lévi-Strauss ?", "answer": "La prohibition de l''inceste est la règle universelle qui marque le passage de la nature à la culture. En interdisant l''union au sein de la même famille, elle oblige à l''échange entre groupes et fonde la vie sociale.", "category": "Citation/Idée"}]',
  true, 1);

  -- ============================================================
  -- HISTOIRE-GÉOGRAPHIE - Chapitre 1 : La Décolonisation en Afrique
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_histgeo_id, 'decolonisation-afrique', 1, 'La Décolonisation en Afrique', 'Le processus de décolonisation du continent africain', 1)
  RETURNING id INTO v_ch_30;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_30, 'decolonisation-afrique', 'La Décolonisation en Afrique',
  'La décolonisation est le processus par lequel les peuples colonisés accèdent à l''indépendance. Ce chapitre étudie les causes, les formes et les conséquences de la décolonisation en Afrique.',
  '{"key_points": ["La décolonisation africaine s''étend principalement de 1956 à 1975", "Les causes : montée du nationalisme, affaiblissement des métropoles, rôle de l''ONU et des USA/URSS", "Deux formes : décolonisation négociée (pacifique) et décolonisation par la lutte armée", "Le Mali accède à l''indépendance le 22 septembre 1960 sous Modibo Keïta", "La conférence de Bandung (1955) affirme le droit des peuples à disposer d''eux-mêmes", "Le panafricanisme et la négritude ont préparé intellectuellement la décolonisation", "Les défis post-indépendance : construction nationale, néocolonialisme, développement"], "content": "## Les causes de la décolonisation\n\n### Causes internes\n- Montée du **nationalisme** africain : revendication d''identité et de liberté\n- Rôle des **élites intellectuelles** formées en Europe (Senghor, Nkrumah, Lumumba)\n- Le **panafricanisme** : mouvement pour l''unité et la solidarité africaines\n- La **négritude** (Senghor, Césaire) : réhabilitation de la culture noire\n\n### Causes externes\n- **Affaiblissement des métropoles** après la Seconde Guerre mondiale\n- **Pression internationale** : la Charte de l''ONU affirme le droit des peuples à disposer d''eux-mêmes\n- Soutien des **USA** et de l''**URSS** (dans le contexte de la Guerre froide)\n- **Conférence de Bandung** (1955) : solidarité des peuples colonisés\n\n## Les formes de la décolonisation\n\n### Décolonisation négociée (pacifique)\n- Transition progressive vers l''indépendance par la négociation\n- Exemples : **Mali** (1960), Sénégal (1960), Côte d''Ivoire (1960)\n- La loi-cadre Defferre (1956) accorde l''autonomie interne aux colonies françaises\n\n### Décolonisation par la lutte armée\n- Quand la métropole refuse les revendications d''indépendance\n- **Algérie** (1954-1962) : guerre d''indépendance longue et violente\n- **Kenya** : révolte des Mau-Mau contre les Britanniques\n- **Guinée-Bissau, Angola, Mozambique** : luttes armées contre le Portugal\n\n## L''indépendance du Mali\n\n- **1958** : le Soudan français vote « Oui » au référendum de la Communauté française\n- **Janvier 1959** : création de la **Fédération du Mali** (Soudan + Sénégal)\n- **Août 1960** : éclatement de la Fédération\n- **22 septembre 1960** : indépendance de la **République du Mali** sous **Modibo Keïta**\n- Orientation socialiste, nationalisations, politique panafricaine\n\n## Les défis post-indépendance\n- **Construction de l''État-nation** : frontières héritées de la colonisation\n- **Néocolonialisme** : maintien de l''influence économique et politique des anciennes métropoles\n- **Développement économique** : industrialisation, éducation, santé\n- **Unité africaine** : création de l''OUA en 1963 (devenue UA en 2002)"}',
  '[{"question": "En quelle année le Mali est-il devenu indépendant ?", "options": ["1958", "1960", "1962", "1975"], "correct": 1, "explanation": "Le Mali a accédé à l''indépendance le 22 septembre 1960 sous la présidence de Modibo Keïta, après l''éclatement de la Fédération du Mali (Soudan + Sénégal)."},
  {"question": "Quelle conférence a affirmé le droit des peuples colonisés ?", "options": ["La conférence de Berlin", "La conférence de Bandung", "La conférence de Yalta", "La conférence de Paris"], "correct": 1, "explanation": "La conférence de Bandung (1955, Indonésie) a réuni 29 pays d''Afrique et d''Asie et a affirmé le droit des peuples à disposer d''eux-mêmes, marquant la solidarité des pays du Tiers-Monde."},
  {"question": "Quel pays africain a connu une longue guerre d''indépendance contre la France ?", "options": ["Le Sénégal", "Le Mali", "L''Algérie", "La Côte d''Ivoire"], "correct": 2, "explanation": "L''Algérie a connu une guerre d''indépendance longue et violente de 1954 à 1962 contre la France, car celle-ci considérait l''Algérie comme une partie intégrante de son territoire."},
  {"question": "Qui était le premier président du Mali indépendant ?", "options": ["Moussa Traoré", "Alpha Oumar Konaré", "Modibo Keïta", "Amadou Toumani Touré"], "correct": 2, "explanation": "Modibo Keïta fut le premier président de la République du Mali indépendant en 1960. Il adopta une orientation socialiste et une politique panafricaine."},
  {"question": "Qu''est-ce que le néocolonialisme ?", "options": ["Le retour à la colonisation directe", "Le maintien de l''influence des anciennes métropoles après l''indépendance", "La colonisation de nouveaux territoires", "Le refus de toute relation avec l''Occident"], "correct": 1, "explanation": "Le néocolonialisme désigne le maintien de l''influence économique, politique et culturelle des anciennes puissances coloniales sur les pays nouvellement indépendants, malgré l''indépendance formelle."}]',
  '[{"question": "Qu''est-ce que le panafricanisme ?", "answer": "Le panafricanisme est un mouvement politique et culturel qui prône l''unité, la solidarité et la coopération entre tous les peuples africains et de la diaspora pour défendre leurs intérêts communs.", "category": "Définition"},
  {"question": "Qu''est-ce que la Fédération du Mali ?", "answer": "La Fédération du Mali était une union entre le Soudan français et le Sénégal créée en janvier 1959. Elle éclata en août 1960 et le Soudan français prit le nom de République du Mali.", "category": "Définition"},
  {"question": "Qu''est-ce que la conférence de Bandung ?", "answer": "La conférence de Bandung (1955, Indonésie) réunit 29 pays d''Afrique et d''Asie. Elle affirma le droit des peuples à disposer d''eux-mêmes, le refus du colonialisme et la solidarité des pays du Tiers-Monde.", "category": "Définition"},
  {"question": "Quelles sont les deux formes de décolonisation ?", "answer": "1. Décolonisation négociée (pacifique) : par la négociation (Mali, Sénégal). 2. Décolonisation par la lutte armée : quand la métropole refuse (Algérie, Guinée-Bissau).", "category": "Définition"}]',
  false, 1);

  -- ============================================================
  -- HISTOIRE-GÉOGRAPHIE - Chapitre 2 : La Guerre Froide
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_histgeo_id, 'guerre-froide', 2, 'La Guerre Froide', 'L''affrontement Est-Ouest de 1947 à 1991', 2)
  RETURNING id INTO v_ch_31;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_31, 'guerre-froide', 'La Guerre Froide',
  'La Guerre froide est la période de tensions entre les États-Unis et l''URSS de 1947 à 1991, sans affrontement militaire direct. Ce chapitre analyse les causes, les crises et la fin de cette confrontation.',
  '{"key_points": ["La Guerre froide oppose le bloc occidental (USA, capitalisme) au bloc soviétique (URSS, communisme)", "Elle débute en 1947 avec la doctrine Truman et le plan Marshall", "Les crises majeures : blocus de Berlin (1948), guerre de Corée, crise de Cuba (1962)", "La course aux armements nucléaires crée l''équilibre de la terreur", "Le Tiers-Monde devient un enjeu entre les deux blocs", "La détente (1962-1979) puis la reprise des tensions", "La chute du mur de Berlin (1989) et la dissolution de l''URSS (1991) marquent la fin"], "content": "## Origines de la Guerre froide (1945-1947)\n\n### Deux superpuissances, deux systèmes\n\n| | USA | URSS |\n|--|-----|------|\n| **Économie** | Capitalisme, libre marché | Communisme, économie planifiée |\n| **Politique** | Démocratie libérale | Parti unique (PCUS) |\n| **Alliance** | OTAN (1949) | Pacte de Varsovie (1955) |\n\n### La rupture (1947)\n- **Doctrine Truman** : politique de containment (endiguement) du communisme\n- **Plan Marshall** : aide économique américaine pour reconstruire l''Europe\n- **Doctrine Jdanov** : le monde divisé en deux camps irréconciliables\n\n## Les grandes crises\n\n### Le blocus de Berlin (1948-1949)\n- L''URSS bloque les accès terrestres à Berlin-Ouest\n- Les USA organisent un **pont aérien** pendant 11 mois\n- Résultat : création de la RFA (Ouest) et de la RDA (Est) en 1949\n\n### La crise de Cuba (1962)\n- L''URSS installe des missiles nucléaires à Cuba\n- Le monde au bord de la **guerre nucléaire** pendant 13 jours\n- Recul de l''URSS après négociations\n- Conséquence : installation du « **téléphone rouge** » entre Washington et Moscou\n\n### La course aux armements\n- **Équilibre de la terreur** : les deux camps possèdent assez d''armes nucléaires pour se détruire mutuellement (MAD : Mutual Assured Destruction)\n- Course à l''espace : Spoutnik (1957), Apollo 11 (1969)\n\n## La fin de la Guerre froide\n\n- **Gorbatchev** (1985) : réformes (Glasnost = transparence, Perestroïka = restructuration)\n- **Chute du mur de Berlin** : 9 novembre 1989\n- **Dissolution de l''URSS** : 25 décembre 1991\n- Les USA deviennent l''unique superpuissance (monde unipolaire)"}',
  '[{"question": "En quelle année a débuté la Guerre froide ?", "options": ["1939", "1945", "1947", "1950"], "correct": 2, "explanation": "La Guerre froide débute en 1947 avec la doctrine Truman (politique d''endiguement du communisme) et le plan Marshall (aide économique américaine à l''Europe)."},
  {"question": "Qu''est-ce que l''équilibre de la terreur ?", "options": ["Une paix durable", "La capacité des deux camps à se détruire mutuellement", "Une alliance militaire", "Un accord de désarmement"], "correct": 1, "explanation": "L''équilibre de la terreur signifie que les USA et l''URSS possèdent tous deux suffisamment d''armes nucléaires pour détruire l''autre, ce qui paradoxalement empêche un conflit direct."},
  {"question": "Quel événement symbolise la fin de la Guerre froide ?", "options": ["La crise de Cuba", "La guerre de Corée", "La chute du mur de Berlin en 1989", "Le plan Marshall"], "correct": 2, "explanation": "La chute du mur de Berlin le 9 novembre 1989 est l''événement symbolique qui marque la fin de la Guerre froide, suivie de la dissolution de l''URSS en décembre 1991."},
  {"question": "Qu''est-ce que le plan Marshall ?", "options": ["Un plan militaire soviétique", "Une aide économique américaine pour reconstruire l''Europe", "Un accord de paix", "Un programme spatial"], "correct": 1, "explanation": "Le plan Marshall (1947) est un programme d''aide économique massive des États-Unis pour reconstruire l''Europe occidentale après la Seconde Guerre mondiale, afin de contrer l''influence communiste."},
  {"question": "Quelle crise a amené le monde au bord de la guerre nucléaire en 1962 ?", "options": ["Le blocus de Berlin", "La guerre de Corée", "La crise de Cuba", "La guerre du Vietnam"], "correct": 2, "explanation": "La crise de Cuba (octobre 1962) a amené le monde au bord de la guerre nucléaire quand l''URSS a installé des missiles à Cuba, à 150 km des côtes américaines."}]',
  '[{"question": "Qu''est-ce que la doctrine Truman ?", "answer": "La doctrine Truman (1947) est la politique américaine d''endiguement (containment) du communisme. Les USA s''engagent à aider tout pays menacé par l''expansion communiste.", "category": "Définition"},
  {"question": "Qu''est-ce que la Perestroïka ?", "answer": "La Perestroïka (restructuration) est la politique de réformes économiques lancée par Gorbatchev en URSS à partir de 1985, visant à moderniser le système soviétique. Elle a contribué à la fin de la Guerre froide.", "category": "Définition"},
  {"question": "Qu''est-ce que l''OTAN ?", "answer": "L''OTAN (Organisation du Traité de l''Atlantique Nord) est l''alliance militaire occidentale créée en 1949 sous leadership américain, face au bloc soviétique qui créa le Pacte de Varsovie en 1955.", "category": "Définition"},
  {"question": "Que signifie MAD ?", "answer": "MAD signifie Mutual Assured Destruction (Destruction Mutuelle Assurée). C''est le concept selon lequel les deux superpuissances possèdent assez d''armes nucléaires pour se détruire mutuellement.", "category": "Définition"}]',
  true, 1);

  -- ============================================================
  -- HISTOIRE-GÉOGRAPHIE - Chapitre 3 : Le Mali Contemporain
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_histgeo_id, 'mali-contemporain', 3, 'Le Mali Contemporain', 'L''histoire politique du Mali de l''indépendance à nos jours', 3)
  RETURNING id INTO v_ch_32;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_32, 'mali-contemporain', 'Le Mali Contemporain',
  'Depuis son indépendance en 1960, le Mali a connu plusieurs régimes politiques. Ce chapitre retrace l''évolution politique du pays, de Modibo Keïta à la période démocratique et les défis actuels.',
  '{"key_points": ["1960-1968 : Modibo Keïta, orientation socialiste et parti unique (US-RDA)", "1968-1991 : Moussa Traoré, régime militaire autoritaire", "Mars 1991 : révolution populaire, chute de Moussa Traoré", "1992 : nouvelle constitution, début de la IIIᵉ République démocratique", "Alpha Oumar Konaré (1992-2002) : consolidation démocratique", "Le Mali est considéré comme un modèle démocratique en Afrique de l''Ouest dans les années 1990-2000", "Défis : intégrité territoriale, sécurité, développement économique"], "content": "## La Première République (1960-1968)\n\n### Modibo Keïta\n- Premier président du Mali indépendant (22 septembre 1960)\n- **Orientation socialiste** : nationalisations, économie planifiée\n- Parti unique : l''**US-RDA** (Union Soudanaise - Rassemblement Démocratique Africain)\n- Politique **panafricaine** active\n- Difficultés économiques croissantes\n\n## Le régime militaire (1968-1991)\n\n### Moussa Traoré\n- **Coup d''État** du 19 novembre 1968\n- Régime **autoritaire** et parti unique (UDPM)\n- Sécheresses de 1973 et 1984 : famines et crises alimentaires\n- Opposition croissante dans les années 1980\n- Mouvement pro-démocratie : manifestations, répression\n\n## La Révolution de mars 1991\n\n- **26 mars 1991** : soulèvement populaire\n- Manifestations massives à Bamako et dans les grandes villes\n- **Amadou Toumani Touré (ATT)** dirige la transition militaire\n- Moussa Traoré est arrêté\n- **Conférence nationale** (1991) : adoption d''une nouvelle constitution\n- Le 26 mars est devenu **fête nationale** (Journée des Martyrs)\n\n## La IIIᵉ République démocratique (depuis 1992)\n\n### Alpha Oumar Konaré (1992-2002)\n- Premier président démocratiquement élu\n- **Deux mandats** respectés (alternance démocratique)\n- Décentralisation, liberté de la presse, multipartisme\n- Le Mali devient un **modèle démocratique** en Afrique de l''Ouest\n\n### Amadou Toumani Touré (2002-2012)\n- Élu démocratiquement après avoir dirigé la transition de 1991\n- Politique de **consensus** et de dialogue\n- Défis sécuritaires croissants au nord du pays\n\n## Les défis du Mali contemporain\n- **Intégrité territoriale** et stabilité\n- **Développement économique** : lutte contre la pauvreté\n- **Éducation** et **santé** pour tous\n- **Unité nationale** et cohésion sociale\n- Rôle du Mali dans les organisations régionales (CEDEAO, UA)"}',
  '[{"question": "Qui était le premier président du Mali ?", "options": ["Moussa Traoré", "Alpha Oumar Konaré", "Modibo Keïta", "Amadou Toumani Touré"], "correct": 2, "explanation": "Modibo Keïta fut le premier président de la République du Mali après l''indépendance le 22 septembre 1960. Il dirigea le pays avec une orientation socialiste jusqu''au coup d''État de 1968."},
  {"question": "Quelle est la date de la révolution populaire au Mali ?", "options": ["22 septembre 1960", "19 novembre 1968", "26 mars 1991", "8 juin 1992"], "correct": 2, "explanation": "Le 26 mars 1991, un soulèvement populaire a renversé le régime autoritaire de Moussa Traoré. Cette date est devenue la Journée des Martyrs, fête nationale du Mali."},
  {"question": "Qui a dirigé la transition démocratique après la révolution de 1991 ?", "options": ["Modibo Keïta", "Alpha Oumar Konaré", "Amadou Toumani Touré", "Moussa Traoré"], "correct": 2, "explanation": "Le lieutenant-colonel Amadou Toumani Touré (ATT) a dirigé la transition militaire après la chute de Moussa Traoré, organisant la conférence nationale et les premières élections démocratiques."},
  {"question": "Qui fut le premier président démocratiquement élu du Mali ?", "options": ["Modibo Keïta", "Moussa Traoré", "Alpha Oumar Konaré", "Amadou Toumani Touré"], "correct": 2, "explanation": "Alpha Oumar Konaré fut le premier président démocratiquement élu du Mali en 1992, après la transition démocratique. Il effectua deux mandats (1992-2002) et respecta l''alternance."},
  {"question": "Quel parti unique dirigeait le Mali sous Modibo Keïta ?", "options": ["UDPM", "ADEMA", "US-RDA", "RPM"], "correct": 2, "explanation": "L''US-RDA (Union Soudanaise - Rassemblement Démocratique Africain) était le parti unique sous Modibo Keïta, d''orientation socialiste et panafricaine."}]',
  '[{"question": "Qu''est-ce que la conférence nationale de 1991 ?", "answer": "La conférence nationale de 1991 fut une assemblée regroupant toutes les forces vives de la nation malienne pour décider de l''avenir du pays après la chute de Moussa Traoré. Elle aboutit à l''adoption d''une nouvelle constitution démocratique.", "category": "Définition"},
  {"question": "Pourquoi le 26 mars est-il une fête nationale au Mali ?", "answer": "Le 26 mars 1991 est la date de la révolution populaire qui a renversé le régime autoritaire de Moussa Traoré. Cette date est devenue la Journée des Martyrs, en hommage à ceux qui sont tombés pour la démocratie.", "category": "Définition"},
  {"question": "Qu''est-ce que la décentralisation ?", "answer": "La décentralisation est le transfert de compétences et de pouvoirs du gouvernement central vers les collectivités locales. Au Mali, elle a été mise en place sous Konaré pour rapprocher l''administration des citoyens.", "category": "Définition"},
  {"question": "Pourquoi le Mali était-il considéré comme un modèle démocratique ?", "answer": "Dans les années 1990-2000, le Mali était salué pour sa transition démocratique réussie, le multipartisme, la liberté de presse, l''alternance pacifique du pouvoir et la décentralisation.", "category": "Définition"}]',
  true, 1);

  -- ============================================================
  -- HISTOIRE-GÉOGRAPHIE - Chapitre 4 : La Mondialisation
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_histgeo_id, 'mondialisation', 4, 'La Mondialisation', 'Les dynamiques de la mondialisation et ses effets', 4)
  RETURNING id INTO v_ch_33;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_33, 'mondialisation', 'La Mondialisation',
  'La mondialisation est le processus d''intégration croissante des économies, des cultures et des sociétés à l''échelle mondiale. Ce chapitre analyse ses acteurs, ses effets et ses enjeux pour l''Afrique.',
  '{"key_points": ["La mondialisation est l''intégration croissante des économies et des sociétés à l''échelle mondiale", "Ses dimensions : économique, culturelle, politique, technologique", "Acteurs : États, firmes transnationales, organisations internationales (OMC, FMI, ONU)", "Les flux : marchandises, capitaux, informations, personnes", "Avantages : croissance, accès à l''information, échanges culturels", "Inconvénients : inégalités, dépendance, uniformisation culturelle", "Défis pour l''Afrique : s''intégrer sans perdre son identité ni accroître les inégalités"], "content": "## Définition et dimensions\n\nLa **mondialisation** (ou globalisation) est le processus d''intégration croissante des économies, des cultures et des sociétés à l''échelle planétaire.\n\n### Les dimensions\n- **Économique** : libre-échange, flux de capitaux, firmes transnationales\n- **Culturelle** : diffusion mondiale des modes de vie, médias, langues\n- **Politique** : organisations internationales, gouvernance mondiale\n- **Technologique** : Internet, télécommunications, transports rapides\n\n## Les acteurs de la mondialisation\n\n| Acteur | Rôle |\n|--------|------|\n| **États** | Politiques commerciales, accords internationaux |\n| **Firmes transnationales (FTN)** | Production et vente à l''échelle mondiale |\n| **Organisations internationales** | OMC, FMI, Banque mondiale, ONU |\n| **ONG** | Action humanitaire et plaidoyer |\n| **Médias et réseaux sociaux** | Diffusion de l''information |\n\n## Les flux mondiaux\n- **Flux de marchandises** : commerce international (matières premières, produits manufacturés)\n- **Flux de capitaux** : investissements, aide au développement\n- **Flux d''informations** : Internet, télévision, presse\n- **Flux de personnes** : migrations, tourisme, étudiants\n\n## Avantages et inconvénients\n\n### Avantages\n- **Croissance économique** et réduction de la pauvreté dans certains pays\n- **Accès à l''information** et au savoir grâce aux technologies\n- **Échanges culturels** et ouverture au monde\n- **Coopération internationale** face aux défis globaux\n\n### Inconvénients\n- **Accroissement des inégalités** entre pays riches et pauvres\n- **Uniformisation culturelle** : domination des cultures occidentales\n- **Dépendance économique** des pays du Sud\n- **Dégradation environnementale** liée à la croissance industrielle\n- **Perte de souveraineté** des États face aux FTN\n\n## L''Afrique dans la mondialisation\n- L''Afrique représente environ **3%** du commerce mondial\n- Exportation principalement de **matières premières** (or, coton, pétrole)\n- **Défi** : diversifier l''économie et monter en gamme\n- **Opportunités** : jeunesse démographique, ressources naturelles, marché intérieur croissant\n- **Intégration régionale** : CEDEAO, UEMOA, Zone de libre-échange continentale africaine (ZLECAf)"}',
  '[{"question": "Qu''est-ce que la mondialisation ?", "options": ["Le commerce entre deux pays", "L''intégration croissante des économies et sociétés à l''échelle mondiale", "La domination d''un pays sur les autres", "Le développement des villes"], "correct": 1, "explanation": "La mondialisation est le processus d''intégration croissante des économies, des cultures et des sociétés à l''échelle planétaire, facilité par les progrès technologiques et la libéralisation des échanges."},
  {"question": "Qu''est-ce qu''une firme transnationale (FTN) ?", "options": ["Une petite entreprise locale", "Une entreprise qui opère dans un seul pays", "Une entreprise qui produit et vend à l''échelle mondiale", "Une organisation gouvernementale"], "correct": 2, "explanation": "Une firme transnationale (FTN) est une grande entreprise qui possède des filiales et opère dans plusieurs pays à travers le monde, comme Apple, Total ou Nestlé."},
  {"question": "Quelle part du commerce mondial représente l''Afrique environ ?", "options": ["15%", "10%", "3%", "25%"], "correct": 2, "explanation": "L''Afrique représente environ 3% du commerce mondial, ce qui reflète sa faible intégration dans les échanges internationaux et sa dépendance aux exportations de matières premières."},
  {"question": "Quel est un inconvénient majeur de la mondialisation ?", "options": ["La paix mondiale", "L''accroissement des inégalités entre pays riches et pauvres", "La diminution du commerce", "L''isolement des pays"], "correct": 1, "explanation": "Un des principaux inconvénients de la mondialisation est l''accroissement des inégalités entre les pays développés et les pays en développement, les bénéfices étant inégalement répartis."},
  {"question": "Qu''est-ce que la ZLECAf ?", "options": ["Une monnaie africaine", "La Zone de Libre-Échange Continentale Africaine", "Une armée africaine", "Un programme éducatif"], "correct": 1, "explanation": "La ZLECAf (Zone de Libre-Échange Continentale Africaine) est un accord commercial visant à créer un marché unique africain en réduisant les barrières douanières entre les pays du continent."}]',
  '[{"question": "Quels sont les quatre types de flux mondiaux ?", "answer": "1. Flux de marchandises (commerce). 2. Flux de capitaux (investissements). 3. Flux d''informations (Internet, médias). 4. Flux de personnes (migrations, tourisme).", "category": "Définition"},
  {"question": "Qu''est-ce que l''OMC ?", "answer": "L''OMC (Organisation Mondiale du Commerce) est une organisation internationale qui régule le commerce mondial, négocie les accords commerciaux et règle les différends entre pays membres.", "category": "Définition"},
  {"question": "Qu''est-ce que la CEDEAO ?", "answer": "La CEDEAO (Communauté Économique des États de l''Afrique de l''Ouest) est une organisation régionale de 15 pays qui vise l''intégration économique et la coopération en Afrique de l''Ouest.", "category": "Définition"},
  {"question": "Qu''est-ce que l''uniformisation culturelle ?", "answer": "L''uniformisation culturelle est la tendance à l''homogénéisation des modes de vie, des valeurs et des pratiques culturelles sous l''effet de la mondialisation, souvent au profit des cultures occidentales dominantes.", "category": "Définition"}]',
  true, 1);

  -- ============================================================
  -- HISTOIRE-GÉOGRAPHIE - Chapitre 5 : Géographie du Mali
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_histgeo_id, 'geographie-mali', 5, 'Géographie du Mali', 'Le territoire malien, ses atouts et ses défis', 5)
  RETURNING id INTO v_ch_34;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_34, 'geographie-mali', 'Géographie du Mali',
  'Le Mali est un vaste pays enclavé d''Afrique de l''Ouest. Ce chapitre présente ses caractéristiques physiques, sa population, son économie et les enjeux de son développement territorial.',
  '{"key_points": ["Le Mali couvre 1 241 238 km² et est enclavé (sans accès à la mer)", "Trois zones climatiques : saharienne (nord), sahélienne (centre), soudanienne (sud)", "Les fleuves Niger et Sénégal sont essentiels à la vie économique", "Population d''environ 22 millions d''habitants, très jeune et en forte croissance", "Économie basée sur l''agriculture (coton, riz, mil), l''élevage et l''exploitation minière (or)", "Bamako est la capitale et la plus grande ville (environ 3 millions d''habitants)", "Défis : désertification, enclavement, urbanisation rapide, accès aux services de base"], "content": "## Situation géographique\n\n- **Superficie** : 1 241 238 km² (plus grand que la France et l''Allemagne réunies)\n- **Position** : Afrique de l''Ouest, pays **enclavé** (sans accès à la mer)\n- **Frontières** : 7 pays (Algérie, Niger, Burkina Faso, Côte d''Ivoire, Guinée, Sénégal, Mauritanie)\n- **Capitale** : Bamako\n\n## Les zones climatiques\n\n| Zone | Localisation | Pluviométrie | Végétation |\n|------|-------------|--------------|------------|\n| **Saharienne** | Nord (2/3 du territoire) | < 200 mm/an | Désert, oasis |\n| **Sahélienne** | Centre | 200-600 mm/an | Steppe, savane arbustive |\n| **Soudanienne** | Sud | 600-1500 mm/an | Savane arborée, forêts |\n\n## Les ressources en eau\n\n### Le fleuve Niger\n- **4 200 km** de long (3ᵉ fleuve d''Afrique)\n- Traverse le Mali sur **1 700 km**\n- **Delta intérieur du Niger** : zone inondable très fertile\n- Essentiel pour l''agriculture, la pêche et les transports\n\n### Le fleuve Sénégal\n- Arrose l''ouest du Mali\n- Source d''irrigation et d''hydroélectricité (barrage de Manantali)\n\n## Population et démographie\n\n- **Population** : environ 22 millions d''habitants (2024)\n- **Taux de croissance** : environ 3% par an (très élevé)\n- **Population très jeune** : plus de 60% a moins de 25 ans\n- **Densité** : très inégale (forte au sud, très faible au nord)\n- **Urbanisation** : environ 45%, en progression rapide\n- **Diversité ethnique** : Bambara, Peul, Songhaï, Dogon, Touareg, Soninké, etc.\n\n## Économie\n\n- **Agriculture** (35% du PIB) : coton, riz, mil, sorgho, arachide\n- Le Mali est le 2ᵉ producteur de **coton** en Afrique\n- **Élevage** : bovins, ovins, caprins (secteur important)\n- **Or** : 3ᵉ producteur d''or en Afrique\n- **Secteur informel** : emploie la majorité de la population active\n\n## Défis du développement\n- **Désertification** : avancée du désert vers le sud\n- **Enclavement** : coûts de transport élevés, dépendance des ports voisins\n- **Urbanisation rapide** : pression sur les infrastructures\n- **Accès aux services** : éducation, santé, eau potable, électricité"}',
  '[{"question": "Quelle est la superficie du Mali ?", "options": ["500 000 km²", "1 241 238 km²", "2 000 000 km²", "800 000 km²"], "correct": 1, "explanation": "Le Mali couvre 1 241 238 km², ce qui en fait l''un des plus grands pays d''Afrique de l''Ouest, plus grand que la France et l''Allemagne réunies."},
  {"question": "Combien de zones climatiques compte le Mali ?", "options": ["Deux", "Trois", "Quatre", "Une"], "correct": 1, "explanation": "Le Mali compte trois zones climatiques : la zone saharienne (désertique au nord), la zone sahélienne (semi-aride au centre) et la zone soudanienne (plus humide au sud)."},
  {"question": "Quel fleuve traverse le Mali sur 1 700 km ?", "options": ["Le Sénégal", "Le Congo", "Le Niger", "Le Nil"], "correct": 2, "explanation": "Le fleuve Niger, 3ᵉ plus long fleuve d''Afrique (4 200 km), traverse le Mali sur 1 700 km. Il est essentiel pour l''agriculture, la pêche et les transports."},
  {"question": "Quel est le principal produit d''exportation agricole du Mali ?", "options": ["Le café", "Le cacao", "Le coton", "Le thé"], "correct": 2, "explanation": "Le coton est le principal produit d''exportation agricole du Mali. Le pays est le 2ᵉ producteur de coton en Afrique."},
  {"question": "Pourquoi dit-on que le Mali est un pays enclavé ?", "options": ["Il est entouré de montagnes", "Il n''a pas d''accès à la mer", "Il est très petit", "Il est isolé politiquement"], "correct": 1, "explanation": "Le Mali est un pays enclavé car il n''a pas d''accès direct à la mer. Il dépend des ports des pays voisins (Dakar, Abidjan, Lomé) pour son commerce international."}]',
  '[{"question": "Qu''est-ce que le delta intérieur du Niger ?", "answer": "Le delta intérieur du Niger est une vaste zone inondable au centre du Mali où le Niger se divise en de nombreux bras. C''est une région très fertile, essentielle pour l''agriculture, la pêche et l''élevage.", "category": "Définition"},
  {"question": "Qu''est-ce que la désertification ?", "answer": "La désertification est l''avancée du désert vers les zones habitables, causée par le changement climatique, la déforestation et les pratiques agricoles. Au Mali, le Sahara avance vers le sud, menaçant les terres cultivables.", "category": "Définition"},
  {"question": "Quels sont les principaux groupes ethniques du Mali ?", "answer": "Les principaux groupes ethniques sont : les Bambara (les plus nombreux), les Peul, les Songhaï, les Dogon, les Touareg, les Soninké, les Bobo, les Sénoufo et les Malinké.", "category": "Définition"},
  {"question": "Qu''est-ce que l''enclavement ?", "answer": "L''enclavement est le fait pour un pays de ne pas avoir d''accès direct à la mer, ce qui augmente les coûts de transport et crée une dépendance vis-à-vis des pays côtiers pour le commerce international.", "category": "Définition"}]',
  true, 1);

  -- ============================================================
  -- HISTOIRE-GÉOGRAPHIE - Chapitre 6 : Population et Développement
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_histgeo_id, 'population-developpement', 6, 'Population et Développement', 'Les enjeux démographiques et le développement durable', 6)
  RETURNING id INTO v_ch_35;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_35, 'population-developpement', 'Population et Développement',
  'La croissance démographique rapide de l''Afrique pose des défis majeurs en termes de développement. Ce chapitre analyse la transition démographique, l''IDH et les objectifs de développement durable.',
  '{"key_points": ["La transition démographique décrit le passage d''un régime à forte natalité/mortalité à un régime à faible natalité/mortalité", "L''Afrique subsaharienne est encore en début de transition démographique", "L''IDH (Indice de Développement Humain) mesure le développement au-delà du PIB", "Les ODD (Objectifs de Développement Durable) fixent 17 objectifs pour 2030", "Le dividende démographique : une jeunesse nombreuse peut être un atout si elle est formée et employée", "Le développement durable concilie croissance économique, justice sociale et protection de l''environnement", "L''éducation des filles est un levier majeur du développement"], "content": "## La transition démographique\n\nLa **transition démographique** est le passage d''un régime démographique ancien (forte natalité, forte mortalité) à un régime moderne (faible natalité, faible mortalité).\n\n### Les 4 phases\n1. **Phase 1** : natalité et mortalité élevées → croissance lente\n2. **Phase 2** : mortalité baisse (progrès médicaux), natalité reste élevée → forte croissance\n3. **Phase 3** : natalité baisse progressivement → croissance ralentit\n4. **Phase 4** : natalité et mortalité basses → croissance faible ou nulle\n\n**L''Afrique subsaharienne** est principalement en **phase 2** : la mortalité a baissé grâce aux progrès médicaux, mais la natalité reste élevée.\n\n## Mesurer le développement\n\n### Le PIB (Produit Intérieur Brut)\n- Mesure la **richesse économique** produite par un pays\n- Limite : ne mesure pas le bien-être, les inégalités ou la santé\n\n### L''IDH (Indice de Développement Humain)\nCréé par le PNUD, l''IDH combine **3 critères** :\n1. **Espérance de vie** à la naissance (santé)\n2. **Durée de scolarisation** (éducation)\n3. **Revenu national brut** par habitant (niveau de vie)\n\nÉchelle de 0 à 1 : plus l''IDH est élevé, plus le pays est développé.\n\n## Le développement durable\n\nDéfini par le rapport Brundtland (1987) : un développement qui répond aux besoins du présent **sans compromettre** la capacité des générations futures à répondre aux leurs.\n\n### Les 3 piliers\n1. **Économique** : croissance et emploi\n2. **Social** : justice sociale, réduction des inégalités, éducation, santé\n3. **Environnemental** : protection des ressources et de la biodiversité\n\n### Les ODD (Objectifs de Développement Durable)\n- **17 objectifs** adoptés par l''ONU en 2015 pour l''horizon **2030**\n- Exemples : pas de pauvreté, faim zéro, éducation de qualité, égalité des sexes, eau propre\n\n## Le dividende démographique\n\nUne population jeune et nombreuse peut être un **atout économique** si :\n- Les jeunes sont **éduqués** et **formés**\n- Des **emplois** sont créés pour les absorber\n- Les investissements en **santé** et **éducation** sont suffisants\n\nSinon, la croissance démographique devient un frein au développement.\n\n## L''éducation des filles\nL''éducation des filles est un **levier majeur** du développement :\n- Réduit la fécondité\n- Améliore la santé des enfants\n- Augmente la productivité économique\n- Renforce l''autonomie des femmes"}',
  '[{"question": "Qu''est-ce que la transition démographique ?", "options": ["La migration des populations", "Le passage d''un régime de forte natalité/mortalité à faible natalité/mortalité", "Le vieillissement de la population", "L''urbanisation"], "correct": 1, "explanation": "La transition démographique décrit le passage d''un régime démographique ancien (natalité et mortalité élevées) à un régime moderne (natalité et mortalité basses), en passant par une phase de forte croissance."},
  {"question": "Quels sont les trois critères de l''IDH ?", "options": ["PIB, inflation, chômage", "Espérance de vie, scolarisation, revenu par habitant", "Population, superficie, densité", "Exportations, importations, dette"], "correct": 1, "explanation": "L''IDH (Indice de Développement Humain) combine trois critères : l''espérance de vie à la naissance (santé), la durée de scolarisation (éducation) et le revenu national brut par habitant (niveau de vie)."},
  {"question": "Quels sont les 3 piliers du développement durable ?", "options": ["Politique, économique, militaire", "Économique, social, environnemental", "Agriculture, industrie, services", "National, régional, local"], "correct": 1, "explanation": "Le développement durable repose sur trois piliers : économique (croissance et emploi), social (justice, éducation, santé) et environnemental (protection des ressources et de la biodiversité)."},
  {"question": "En quelle année les ODD ont-ils été adoptés ?", "options": ["2000", "2010", "2015", "2020"], "correct": 2, "explanation": "Les 17 Objectifs de Développement Durable (ODD) ont été adoptés par l''ONU en 2015, fixant des cibles à atteindre d''ici 2030 pour un développement durable et inclusif."},
  {"question": "Qu''est-ce que le dividende démographique ?", "options": ["L''augmentation de la population âgée", "Le potentiel économique d''une population jeune et nombreuse si elle est formée", "La baisse de la natalité", "L''émigration des jeunes"], "correct": 1, "explanation": "Le dividende démographique est le potentiel de croissance économique que représente une population jeune et nombreuse, à condition que les jeunes soient éduqués, formés et employés."}]',
  '[{"question": "Qu''est-ce que l''IDH ?", "answer": "L''IDH (Indice de Développement Humain) est un indicateur créé par le PNUD qui mesure le développement d''un pays sur une échelle de 0 à 1, en combinant espérance de vie, scolarisation et revenu par habitant.", "category": "Définition"},
  {"question": "Qu''est-ce que le développement durable ?", "answer": "Le développement durable est un développement qui répond aux besoins du présent sans compromettre la capacité des générations futures à répondre aux leurs (rapport Brundtland, 1987).", "category": "Définition"},
  {"question": "Pourquoi l''éducation des filles est-elle un levier de développement ?", "answer": "L''éducation des filles réduit la fécondité, améliore la santé des enfants, augmente la productivité économique et renforce l''autonomie des femmes. C''est un investissement à fort impact.", "category": "Définition"},
  {"question": "Combien d''ODD y a-t-il et pour quelle échéance ?", "answer": "Il y a 17 Objectifs de Développement Durable (ODD) adoptés par l''ONU en 2015, à atteindre d''ici 2030. Ils couvrent la pauvreté, la faim, la santé, l''éducation, l''égalité, l''environnement, etc.", "category": "Définition"}]',
  true, 1);

  -- ============================================================
  -- MATHÉMATIQUES - Chapitre 1 : Statistiques et Probabilités
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_maths_id, 'statistiques-probabilites', 1, 'Statistiques et Probabilités', 'Les bases des statistiques descriptives et des probabilités', 1)
  RETURNING id INTO v_ch_36;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_36, 'statistiques-probabilites', 'Statistiques et Probabilités',
  'Les statistiques permettent de collecter, organiser et interpréter des données. Les probabilités mesurent la chance qu''un événement se produise. Ce chapitre couvre les indicateurs statistiques et le calcul des probabilités.',
  '{"key_points": ["La moyenne est la somme des valeurs divisée par l''effectif total", "La médiane partage la série en deux parties égales", "L''écart-type mesure la dispersion des valeurs autour de la moyenne", "La probabilité d''un événement est comprise entre 0 et 1", "P(A) = nombre de cas favorables / nombre de cas possibles", "Deux événements sont incompatibles s''ils ne peuvent pas se produire en même temps", "P(A ∪ B) = P(A) + P(B) - P(A ∩ B)"], "content": "## Statistiques descriptives\n\n### Les indicateurs de position\n\n#### La moyenne\nx̄ = (somme de toutes les valeurs) / (effectif total N)\n\nFormule : x̄ = (x₁·n₁ + x₂·n₂ + ... + xₖ·nₖ) / N\n\n**Exemple** : Notes de 5 élèves : 8, 12, 14, 10, 16\nx̄ = (8 + 12 + 14 + 10 + 16) / 5 = 60 / 5 = **12**\n\n#### La médiane\nValeur qui partage la série ordonnée en **deux parties égales**.\n- Si n est impair : c''est la valeur centrale\n- Si n est pair : c''est la moyenne des deux valeurs centrales\n\n**Exemple** : Série ordonnée : 8, 10, **12**, 14, 16 → Médiane = 12\n\n#### Le mode\nValeur la plus **fréquente** de la série.\n\n### Les indicateurs de dispersion\n\n#### L''étendue\nÉtendue = valeur max - valeur min\n\n#### La variance\nV = (1/N) × Σ nᵢ × (xᵢ - x̄)²\n\nC''est la moyenne des carrés des écarts à la moyenne.\n\n#### L''écart-type\nσ = √V (racine carrée de la variance)\n\nPlus l''écart-type est **grand**, plus les valeurs sont **dispersées** autour de la moyenne.\n\n## Probabilités\n\n### Définitions\n- **Expérience aléatoire** : une expérience dont on ne peut pas prévoir le résultat avec certitude\n- **Univers** (Ω) : ensemble de tous les résultats possibles\n- **Événement** : sous-ensemble de l''univers\n\n### Calcul de probabilité\nP(A) = nombre de cas favorables / nombre de cas possibles\n\n**Exemple** : On lance un dé équilibré. P(obtenir un 6) = 1/6\n\n### Propriétés\n- 0 ≤ P(A) ≤ 1\n- P(Ω) = 1 (événement certain)\n- P(∅) = 0 (événement impossible)\n- P(contraire de A) = 1 - P(A)\n\n### Événements incompatibles\nDeux événements A et B sont **incompatibles** si A ∩ B = ∅\n→ P(A ∪ B) = P(A) + P(B)\n\n### Formule générale\nP(A ∪ B) = P(A) + P(B) - P(A ∩ B)"}',
  '[{"question": "Comment calcule-t-on la moyenne d''une série ?", "options": ["On prend la valeur du milieu", "On prend la valeur la plus fréquente", "On divise la somme des valeurs par l''effectif total", "On soustrait le minimum du maximum"], "correct": 2, "explanation": "La moyenne se calcule en divisant la somme de toutes les valeurs par l''effectif total : x̄ = Σx/N."},
  {"question": "Qu''est-ce que la médiane ?", "options": ["La valeur la plus fréquente", "La moyenne des valeurs", "La valeur qui partage la série ordonnée en deux parties égales", "La différence entre le max et le min"], "correct": 2, "explanation": "La médiane est la valeur qui partage la série statistique ordonnée en deux parties de même effectif. 50% des valeurs sont en dessous, 50% au-dessus."},
  {"question": "Quelle est la probabilité d''un événement impossible ?", "options": ["1", "0,5", "0", "-1"], "correct": 2, "explanation": "La probabilité d''un événement impossible est 0. Un événement impossible ne peut jamais se produire, donc P(∅) = 0."},
  {"question": "Que mesure l''écart-type ?", "options": ["La valeur moyenne", "La valeur la plus fréquente", "La dispersion des valeurs autour de la moyenne", "Le nombre de valeurs"], "correct": 2, "explanation": "L''écart-type mesure la dispersion (l''étalement) des valeurs autour de la moyenne. Plus il est grand, plus les valeurs sont éloignées de la moyenne."},
  {"question": "Deux événements sont incompatibles quand :", "options": ["Ils ont la même probabilité", "Ils ne peuvent pas se produire en même temps", "Ils se produisent toujours ensemble", "Leur probabilité vaut 1"], "correct": 1, "explanation": "Deux événements sont incompatibles (ou mutuellement exclusifs) s''ils ne peuvent pas se produire en même temps, c''est-à-dire A ∩ B = ∅. Dans ce cas, P(A ∪ B) = P(A) + P(B)."}]',
  '[{"question": "Comment calcule-t-on la variance ?", "answer": "La variance V est la moyenne des carrés des écarts à la moyenne : V = Σ nᵢ(xᵢ - x̄)² / N. L''écart-type σ est la racine carrée de la variance.", "category": "Définition"},
  {"question": "Qu''est-ce qu''une expérience aléatoire ?", "answer": "Une expérience aléatoire est une expérience dont on ne peut pas prévoir le résultat avec certitude avant de la réaliser. Exemples : lancer un dé, tirer une carte.", "category": "Définition"},
  {"question": "Quelle est la formule de P(A ∪ B) ?", "answer": "P(A ∪ B) = P(A) + P(B) - P(A ∩ B). Si A et B sont incompatibles (A ∩ B = ∅), alors P(A ∪ B) = P(A) + P(B).", "category": "Définition"},
  {"question": "Qu''est-ce que le mode d''une série statistique ?", "answer": "Le mode est la valeur qui apparaît le plus souvent dans une série statistique, c''est-à-dire la valeur ayant le plus grand effectif.", "category": "Définition"}]',
  false, 1);

  -- ============================================================
  -- MATHÉMATIQUES - Chapitre 2 : Suites Numériques
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_maths_id, 'suites-numeriques', 2, 'Suites Numériques', 'Les suites arithmétiques et géométriques', 2)
  RETURNING id INTO v_ch_37;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_37, 'suites-numeriques', 'Suites Numériques',
  'Une suite numérique est une liste ordonnée de nombres suivant une règle. Ce chapitre étudie les suites arithmétiques et géométriques, leurs formules et applications.',
  '{"key_points": ["Une suite arithmétique a une raison r constante : u(n+1) = u(n) + r", "Terme général arithmétique : u(n) = u(0) + n × r", "Somme des n premiers termes arithmétiques : S = n × (u(1) + u(n)) / 2", "Une suite géométrique a une raison q constante : u(n+1) = u(n) × q", "Terme général géométrique : u(n) = u(0) × q^n", "Somme des n premiers termes géométriques : S = u(1) × (1 - q^n) / (1 - q)", "Applications : intérêts simples (arithmétique), intérêts composés (géométrique)"], "content": "## Les suites arithmétiques\n\n### Définition\nUne suite (uₙ) est **arithmétique** si chaque terme est obtenu en ajoutant une constante **r** (la raison) au terme précédent :\n\nu(n+1) = u(n) + r\n\n### Terme général\nu(n) = u(0) + n × r\n\n**Exemple** : u₀ = 3, r = 5\n- u₀ = 3, u₁ = 8, u₂ = 13, u₃ = 18...\n- uₙ = 3 + 5n\n- u₁₀ = 3 + 5 × 10 = 53\n\n### Somme des n premiers termes\nSₙ = (n / 2) × (u₁ + uₙ) = (nombre de termes / 2) × (premier + dernier)\n\n**Exemple** : Somme des entiers de 1 à 100\nS = (100 / 2) × (1 + 100) = 50 × 101 = **5050**\n\n## Les suites géométriques\n\n### Définition\nUne suite (uₙ) est **géométrique** si chaque terme est obtenu en multipliant le terme précédent par une constante **q** (la raison) :\n\nu(n+1) = u(n) × q\n\n### Terme général\nu(n) = u(0) × qⁿ\n\n**Exemple** : u₀ = 2, q = 3\n- u₀ = 2, u₁ = 6, u₂ = 18, u₃ = 54...\n- uₙ = 2 × 3ⁿ\n\n### Somme des n premiers termes (q ≠ 1)\nSₙ = u₁ × (1 - qⁿ) / (1 - q)\n\n## Applications pratiques\n\n### Intérêts simples (suite arithmétique)\nUn capital C placé à un taux annuel t en intérêts simples :\nCₙ = C₀ + n × C₀ × t = C₀(1 + nt)\n\n### Intérêts composés (suite géométrique)\nUn capital C placé à un taux annuel t en intérêts composés :\nCₙ = C₀ × (1 + t)ⁿ\n\n**Exemple** : 1 000 000 FCFA placés à 5% pendant 3 ans\n- Intérêts simples : C₃ = 1 000 000 × (1 + 0,15) = 1 150 000 FCFA\n- Intérêts composés : C₃ = 1 000 000 × (1,05)³ = 1 157 625 FCFA\n\n## Sens de variation\n- Suite **croissante** : u(n+1) > u(n) pour tout n\n- Suite **décroissante** : u(n+1) < u(n) pour tout n\n- Arithmétique croissante si r > 0, décroissante si r < 0\n- Géométrique : dépend de q et du signe de u₀"}',
  '[{"question": "Qu''est-ce qu''une suite arithmétique ?", "options": ["Une suite où chaque terme est le double du précédent", "Une suite où la différence entre deux termes consécutifs est constante", "Une suite de nombres premiers", "Une suite alternée"], "correct": 1, "explanation": "Une suite arithmétique est une suite dans laquelle chaque terme est obtenu en ajoutant une constante r (la raison) au terme précédent : u(n+1) = u(n) + r."},
  {"question": "Quel est le terme général d''une suite géométrique ?", "options": ["u(n) = u(0) + n × r", "u(n) = u(0) × q^n", "u(n) = n × q", "u(n) = u(0) / n"], "correct": 1, "explanation": "Le terme général d''une suite géométrique est u(n) = u(0) × q^n, où u(0) est le premier terme et q la raison (facteur multiplicatif constant)."},
  {"question": "Quelle est la somme des entiers de 1 à 100 ?", "options": ["1000", "5050", "10000", "5000"], "correct": 1, "explanation": "En utilisant la formule S = n/2 × (premier + dernier) : S = 100/2 × (1 + 100) = 50 × 101 = 5050."},
  {"question": "Les intérêts composés correspondent à quel type de suite ?", "options": ["Arithmétique", "Géométrique", "Constante", "Alternée"], "correct": 1, "explanation": "Les intérêts composés correspondent à une suite géométrique de raison q = (1 + t), car les intérêts sont calculés sur le capital augmenté des intérêts précédents."},
  {"question": "Quand une suite arithmétique est-elle croissante ?", "options": ["Quand r < 0", "Quand r > 0", "Quand r = 0", "Quand u(0) > 0"], "correct": 1, "explanation": "Une suite arithmétique est croissante lorsque sa raison r est strictement positive (r > 0), car chaque terme est plus grand que le précédent."}]',
  '[{"question": "Quelle est la formule du terme général d''une suite arithmétique ?", "answer": "u(n) = u(0) + n × r, où u(0) est le premier terme et r est la raison (différence constante entre deux termes consécutifs).", "category": "Définition"},
  {"question": "Comment calculer la somme de n termes d''une suite arithmétique ?", "answer": "S = (nombre de termes / 2) × (premier terme + dernier terme). Formule : S = n/2 × (u(1) + u(n)).", "category": "Définition"},
  {"question": "Quelle est la différence entre intérêts simples et composés ?", "answer": "Intérêts simples : les intérêts sont calculés uniquement sur le capital initial (suite arithmétique). Intérêts composés : les intérêts sont calculés sur le capital + intérêts accumulés (suite géométrique).", "category": "Définition"},
  {"question": "Qu''est-ce que la raison d''une suite ?", "answer": "La raison est la constante qui définit la régularité de la suite. Pour une suite arithmétique, c''est la différence r entre deux termes consécutifs. Pour une suite géométrique, c''est le quotient q.", "category": "Définition"}]',
  true, 1);

  -- ============================================================
  -- MATHÉMATIQUES - Chapitre 3 : Fonctions et Dérivation
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_maths_id, 'fonctions-derivation', 3, 'Fonctions et Dérivation', 'L''étude des fonctions et le calcul de dérivées', 3)
  RETURNING id INTO v_ch_38;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_38, 'fonctions-derivation', 'Fonctions et Dérivation',
  'La dérivation permet d''étudier les variations d''une fonction. Ce chapitre couvre les formules de dérivation, l''étude des variations et les applications aux problèmes d''optimisation.',
  '{"key_points": ["La dérivée mesure le taux de variation instantané d''une fonction", "Formules de base : (xⁿ)'' = n × x^(n-1), (constante)'' = 0", "Dérivée d''une somme : (u+v)'' = u'' + v''", "Dérivée d''un produit : (u×v)'' = u''×v + u×v''", "Si f''(x) > 0, f est croissante ; si f''(x) < 0, f est décroissante", "Le tableau de variations résume le comportement de la fonction", "Applications : optimisation (maximiser/minimiser une quantité)"], "content": "## La dérivée\n\n### Définition\nLa **dérivée** d''une fonction f en un point a est le taux de variation instantané :\n\nf''(a) = lim (h→0) [f(a+h) - f(a)] / h\n\nGéométriquement, f''(a) est le **coefficient directeur de la tangente** à la courbe au point d''abscisse a.\n\n## Formules de dérivation\n\n| Fonction f(x) | Dérivée f''(x) |\n|--------------|---------------|\n| k (constante) | 0 |\n| x | 1 |\n| x² | 2x |\n| x³ | 3x² |\n| xⁿ | n × x^(n-1) |\n| 1/x | -1/x² |\n| √x | 1/(2√x) |\n\n## Opérations sur les dérivées\n\n- **(k × f)'' = k × f''** (constante × fonction)\n- **(f + g)'' = f'' + g''** (somme)\n- **(f × g)'' = f'' × g + f × g''** (produit)\n- **(f/g)'' = (f'' × g - f × g'') / g²** (quotient)\n\n## Étude des variations\n\n### Règle fondamentale\n- Si **f''(x) > 0** sur un intervalle, alors f est **croissante** sur cet intervalle\n- Si **f''(x) < 0** sur un intervalle, alors f est **décroissante** sur cet intervalle\n- Si **f''(x) = 0**, c''est un **extremum possible** (maximum ou minimum)\n\n### Méthode d''étude d''une fonction\n1. Calculer la **dérivée** f''(x)\n2. Résoudre **f''(x) = 0** pour trouver les valeurs critiques\n3. Étudier le **signe** de f''(x) sur chaque intervalle\n4. Construire le **tableau de variations**\n5. Calculer les **extremums** (valeurs de f aux points critiques)\n\n### Exemple\nf(x) = x³ - 3x + 1\n\n1. f''(x) = 3x² - 3 = 3(x² - 1) = 3(x-1)(x+1)\n2. f''(x) = 0 → x = -1 ou x = 1\n3. Signe de f'' :\n   - x < -1 : f'' > 0 (croissante)\n   - -1 < x < 1 : f'' < 0 (décroissante)\n   - x > 1 : f'' > 0 (croissante)\n4. Maximum local en x = -1 : f(-1) = 3\n5. Minimum local en x = 1 : f(1) = -1\n\n## Application : optimisation\nLa dérivation permet de trouver le **maximum** ou le **minimum** d''une grandeur :\n- Maximiser une aire, un volume, un profit\n- Minimiser un coût, une distance"}',
  '[{"question": "Quelle est la dérivée de f(x) = x³ ?", "options": ["x²", "3x²", "3x", "x³"], "correct": 1, "explanation": "La dérivée de x^n est n × x^(n-1). Donc la dérivée de x³ est 3x²."},
  {"question": "Si f''(x) > 0 sur un intervalle, alors f est :", "options": ["Décroissante", "Croissante", "Constante", "Nulle"], "correct": 1, "explanation": "Si la dérivée f''(x) est strictement positive sur un intervalle, la fonction f est strictement croissante sur cet intervalle."},
  {"question": "Quelle est la dérivée de f(x) = 5x² + 3x - 2 ?", "options": ["10x + 3", "5x + 3", "10x² + 3", "10x - 2"], "correct": 0, "explanation": "En appliquant les règles : (5x²)'' = 10x, (3x)'' = 3, (-2)'' = 0. Donc f''(x) = 10x + 3."},
  {"question": "Que représente géométriquement la dérivée en un point ?", "options": ["L''aire sous la courbe", "Le coefficient directeur de la tangente", "La longueur de la courbe", "L''ordonnée du point"], "correct": 1, "explanation": "Géométriquement, f''(a) représente le coefficient directeur (la pente) de la tangente à la courbe de f au point d''abscisse a."},
  {"question": "Comment trouve-t-on un extremum d''une fonction ?", "options": ["On calcule f(0)", "On résout f''(x) = 0 et on vérifie le changement de signe", "On trace la courbe", "On calcule la limite"], "correct": 1, "explanation": "Pour trouver un extremum, on résout f''(x) = 0 pour trouver les valeurs critiques, puis on vérifie que f'' change de signe (+ vers - pour un max, - vers + pour un min)."}]',
  '[{"question": "Quelle est la formule de dérivation d''un produit ?", "answer": "(u × v)'' = u'' × v + u × v''. C''est la formule de Leibniz. Exemple : (x² × sin(x))'' = 2x × sin(x) + x² × cos(x).", "category": "Définition"},
  {"question": "Qu''est-ce qu''un maximum local ?", "answer": "Un maximum local est un point où la fonction atteint une valeur supérieure ou égale aux valeurs voisines. On le trouve là où f'' s''annule et change de signe (de + à -).", "category": "Définition"},
  {"question": "Quelles sont les étapes d''une étude de fonction ?", "answer": "1. Calculer la dérivée f''(x). 2. Résoudre f''(x) = 0. 3. Étudier le signe de f''. 4. Construire le tableau de variations. 5. Calculer les extremums.", "category": "Définition"},
  {"question": "Quelle est la dérivée de 1/x ?", "answer": "La dérivée de f(x) = 1/x est f''(x) = -1/x². Cette formule est valable pour x ≠ 0.", "category": "Définition"}]',
  true, 1);

  -- ============================================================
  -- ECM - Chapitre 1 : Les Droits de l'Homme
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_ecm_id, 'droits-homme', 1, 'Les Droits de l''Homme', 'Les droits fondamentaux et leur protection', 1)
  RETURNING id INTO v_ch_39;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_39, 'droits-homme', 'Les Droits de l''Homme',
  'Les droits de l''homme sont des droits fondamentaux reconnus à tout être humain. Ce chapitre étudie la Déclaration universelle, les générations de droits et leur application au Mali.',
  '{"key_points": ["La DUDH (1948) proclame les droits fondamentaux de tous les êtres humains", "Les droits civils et politiques : libertés individuelles (1ʳᵉ génération)", "Les droits économiques et sociaux : droit au travail, à l''éducation, à la santé (2ᵉ génération)", "Les droits de solidarité : droit à la paix, au développement, à l''environnement (3ᵉ génération)", "La Constitution malienne de 1992 garantit les droits fondamentaux", "La Charte africaine des droits de l''homme et des peuples (1981)", "Défis : écart entre les textes et la réalité, accès à la justice"], "content": "## La Déclaration Universelle des Droits de l''Homme (1948)\n\nAdoptée le **10 décembre 1948** par l''Assemblée générale de l''ONU, la DUDH proclame que tous les êtres humains naissent **libres et égaux** en dignité et en droits.\n\n### Principes fondamentaux\n- **Universalité** : les droits s''appliquent à tous sans distinction\n- **Inaliénabilité** : on ne peut pas renoncer à ses droits\n- **Indivisibilité** : tous les droits sont liés et interdépendants\n\n## Les trois générations de droits\n\n### 1ʳᵉ génération : droits civils et politiques\n- Droit à la **vie**, à la **liberté**, à la **sûreté**\n- Liberté d''**expression**, de **pensée**, de **religion**\n- Droit de **vote** et de participation politique\n- Interdiction de l''esclavage et de la torture\n\n### 2ᵉ génération : droits économiques, sociaux et culturels\n- Droit au **travail** et à des conditions justes\n- Droit à l''**éducation**\n- Droit à la **santé**\n- Droit à la **sécurité sociale**\n- Droit à un **niveau de vie suffisant**\n\n### 3ᵉ génération : droits de solidarité\n- Droit à la **paix**\n- Droit au **développement**\n- Droit à un **environnement sain**\n- Droit au **patrimoine commun de l''humanité**\n\n## Les droits de l''homme au Mali\n\n### La Constitution de 1992\n- Garantit les **libertés fondamentales** : expression, presse, association\n- Affirme l''**égalité** devant la loi\n- Interdit la **discrimination**\n- Reconnaît le droit à l''**éducation** et à la **santé**\n\n### La Charte africaine des droits de l''homme et des peuples (1981)\n- Adoptée par l''OUA (aujourd''hui UA)\n- Affirme les droits individuels **et** les droits des **peuples**\n- Insiste sur les **devoirs** de l''individu envers la communauté\n- Spécificité africaine : lien entre droits et **devoirs**\n\n## Les mécanismes de protection\n- **ONU** : Conseil des droits de l''homme, Haut-Commissariat\n- **UA** : Commission africaine des droits de l''homme et des peuples\n- **Société civile** : ONG (Amnesty International, Human Rights Watch)\n- **Justice nationale** : tribunaux, médiateur de la République"}',
  '[{"question": "En quelle année a été adoptée la DUDH ?", "options": ["1945", "1948", "1960", "1992"], "correct": 1, "explanation": "La Déclaration Universelle des Droits de l''Homme a été adoptée le 10 décembre 1948 par l''Assemblée générale des Nations Unies."},
  {"question": "Quels droits appartiennent à la 1ʳᵉ génération ?", "options": ["Droit au travail et à la santé", "Droit à la paix et au développement", "Droits civils et politiques (liberté, vote, expression)", "Droit à l''environnement"], "correct": 2, "explanation": "Les droits de 1ʳᵉ génération sont les droits civils et politiques : droit à la vie, à la liberté, à l''expression, au vote, interdiction de la torture et de l''esclavage."},
  {"question": "Quelle est la spécificité de la Charte africaine par rapport à la DUDH ?", "options": ["Elle ne reconnaît pas les droits individuels", "Elle insiste sur les devoirs de l''individu envers la communauté", "Elle est plus ancienne", "Elle ne concerne que l''Afrique du Nord"], "correct": 1, "explanation": "La Charte africaine des droits de l''homme et des peuples (1981) a la spécificité d''insister sur les devoirs de l''individu envers sa famille et sa communauté, en plus des droits individuels."},
  {"question": "Que signifie l''universalité des droits de l''homme ?", "options": ["Les droits ne concernent que les adultes", "Les droits s''appliquent à tous les êtres humains sans distinction", "Les droits varient selon les pays", "Les droits ne concernent que les citoyens"], "correct": 1, "explanation": "L''universalité signifie que les droits de l''homme s''appliquent à tous les êtres humains, sans distinction de race, de sexe, de nationalité, de religion ou de tout autre statut."},
  {"question": "Quel droit appartient à la 3ᵉ génération ?", "options": ["Droit de vote", "Droit au travail", "Droit à un environnement sain", "Droit à la liberté d''expression"], "correct": 2, "explanation": "Le droit à un environnement sain fait partie des droits de 3ᵉ génération (droits de solidarité), avec le droit à la paix, au développement et au patrimoine commun de l''humanité."}]',
  '[{"question": "Que signifie l''inaliénabilité des droits ?", "answer": "L''inaliénabilité signifie qu''on ne peut pas renoncer à ses droits fondamentaux, ni les vendre, ni les transférer. Ils sont inhérents à la personne humaine.", "category": "Définition"},
  {"question": "Quelles sont les trois générations de droits de l''homme ?", "answer": "1ʳᵉ génération : droits civils et politiques (liberté, vote). 2ᵉ génération : droits économiques et sociaux (travail, éducation, santé). 3ᵉ génération : droits de solidarité (paix, développement, environnement).", "category": "Définition"},
  {"question": "Qu''est-ce que la Charte africaine des droits de l''homme ?", "answer": "Adoptée en 1981 par l''OUA, la Charte africaine des droits de l''homme et des peuples reconnaît les droits individuels et collectifs, et insiste sur les devoirs de l''individu envers la communauté.", "category": "Définition"},
  {"question": "Quels mécanismes protègent les droits de l''homme ?", "answer": "Au niveau international : l''ONU (Conseil des droits de l''homme). Au niveau africain : la Commission africaine. Au niveau national : les tribunaux, le médiateur. La société civile et les ONG jouent aussi un rôle crucial.", "category": "Définition"}]',
  false, 1);

  -- ============================================================
  -- ECM - Chapitre 2 : La Citoyenneté et la Démocratie
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_ecm_id, 'citoyennete-democratie', 2, 'La Citoyenneté et la Démocratie', 'Les principes de la démocratie et les devoirs du citoyen', 2)
  RETURNING id INTO v_ch_40;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_40, 'citoyennete-democratie', 'La Citoyenneté et la Démocratie',
  'La citoyenneté est le statut qui donne des droits et des devoirs au sein d''une communauté politique. Ce chapitre explore les principes démocratiques et le rôle du citoyen.',
  '{"key_points": ["La citoyenneté confère des droits (voter, être élu) et des devoirs (respecter la loi, payer ses impôts)", "La démocratie est le gouvernement du peuple, par le peuple, pour le peuple", "Principes démocratiques : séparation des pouvoirs, élections libres, État de droit", "Montesquieu : séparation des pouvoirs législatif, exécutif et judiciaire", "La démocratie malienne : régime semi-présidentiel, multipartisme", "La participation citoyenne va au-delà du vote : engagement associatif, vigilance", "Menaces : corruption, abstention, manipulation de l''information"], "content": "## La citoyenneté\n\n### Définition\nLa **citoyenneté** est le statut juridique et politique qui confère à un individu des **droits** et des **devoirs** au sein d''un État.\n\n### Droits du citoyen\n- Droit de **vote** et d''éligibilité\n- Droit d''**expression** et d''**opinion**\n- Droit d''**association** et de **manifestation**\n- Droit à la **protection** de l''État\n- Accès aux **services publics**\n\n### Devoirs du citoyen\n- **Respecter** les lois et la Constitution\n- **Payer** ses impôts\n- **Défendre** la patrie si nécessaire\n- **Voter** (devoir moral)\n- **Respecter** les droits d''autrui\n- **Contribuer** au bien commun\n\n## La démocratie\n\n### Définition\nLa démocratie est un régime politique dans lequel le **pouvoir appartient au peuple** qui l''exerce directement ou par ses représentants.\n\n« Gouvernement du peuple, par le peuple, pour le peuple » (Abraham Lincoln)\n\n### Types de démocratie\n- **Directe** : les citoyens décident eux-mêmes (référendum)\n- **Représentative** : les citoyens élisent des représentants\n- **Participative** : consultation et dialogue avec les citoyens\n\n### Principes fondamentaux\n\n#### 1. La séparation des pouvoirs (Montesquieu)\n\n| Pouvoir | Fonction | Institution au Mali |\n|---------|----------|--------------------|\n| **Législatif** | Fait les lois | Assemblée nationale |\n| **Exécutif** | Applique les lois | Président, Gouvernement |\n| **Judiciaire** | Juge les infractions | Tribunaux, Cour suprême |\n\n#### 2. L''État de droit\n- Tous sont soumis à la loi, y compris les gouvernants\n- Indépendance de la justice\n- Protection des libertés fondamentales\n\n#### 3. Le pluralisme\n- Multipartisme : plusieurs partis politiques\n- Liberté de la presse\n- Droit d''opposition\n\n## La démocratie au Mali\n- **Régime semi-présidentiel** : président élu au suffrage universel + premier ministre\n- **Multipartisme** depuis 1991\n- **Décentralisation** : collectivités territoriales\n- Institutions : Assemblée nationale, Cour constitutionnelle, Haut Conseil des collectivités\n\n## Menaces et défis\n- **Corruption** : détournement de fonds publics\n- **Abstention** : désintérêt des citoyens pour le vote\n- **Désinformation** : fake news, manipulation de l''opinion\n- **Violence politique** : atteinte au processus démocratique"}',
  '[{"question": "Qu''est-ce que la citoyenneté ?", "options": ["Le fait de vivre dans une ville", "Le statut qui confère des droits et des devoirs au sein d''un État", "Le droit de voyager", "L''appartenance à une religion"], "correct": 1, "explanation": "La citoyenneté est le statut juridique et politique qui confère à un individu des droits (voter, s''exprimer) et des devoirs (respecter la loi, payer ses impôts) au sein d''un État."},
  {"question": "Qui a théorisé la séparation des pouvoirs ?", "options": ["Rousseau", "Voltaire", "Montesquieu", "Locke"], "correct": 2, "explanation": "Montesquieu a théorisé la séparation des pouvoirs (législatif, exécutif, judiciaire) dans ''L''Esprit des lois'' (1748) pour éviter la concentration du pouvoir et protéger les libertés."},
  {"question": "Quels sont les trois pouvoirs dans une démocratie ?", "options": ["Militaire, religieux, économique", "Législatif, exécutif, judiciaire", "Présidentiel, parlementaire, monarchique", "Local, régional, national"], "correct": 1, "explanation": "Les trois pouvoirs sont : le législatif (fait les lois), l''exécutif (applique les lois) et le judiciaire (juge les infractions). Leur séparation garantit l''équilibre démocratique."},
  {"question": "Qu''est-ce que l''État de droit ?", "options": ["Un État dirigé par un roi", "Un État où tous sont soumis à la loi, y compris les gouvernants", "Un État sans loi", "Un État militaire"], "correct": 1, "explanation": "L''État de droit est un système dans lequel tous, y compris les gouvernants, sont soumis à la loi. Il garantit l''indépendance de la justice et la protection des libertés fondamentales."},
  {"question": "Quel type de régime politique a le Mali ?", "options": ["Monarchie", "Régime parlementaire", "Régime semi-présidentiel", "Théocratie"], "correct": 2, "explanation": "Le Mali a un régime semi-présidentiel : le président est élu au suffrage universel direct et nomme un premier ministre qui dirige le gouvernement."}]',
  '[{"question": "Qu''est-ce que la démocratie représentative ?", "answer": "La démocratie représentative est un système politique dans lequel les citoyens élisent des représentants qui exercent le pouvoir en leur nom. C''est le modèle le plus courant de démocratie.", "category": "Définition"},
  {"question": "Quels sont les devoirs fondamentaux du citoyen ?", "answer": "Les devoirs du citoyen sont : respecter les lois et la Constitution, payer ses impôts, défendre la patrie si nécessaire, voter (devoir moral), respecter les droits d''autrui et contribuer au bien commun.", "category": "Définition"},
  {"question": "Qu''est-ce que le multipartisme ?", "answer": "Le multipartisme est un système politique dans lequel plusieurs partis politiques coexistent et peuvent participer aux élections. Il s''oppose au système de parti unique et est essentiel à la démocratie.", "category": "Définition"},
  {"question": "Qu''est-ce que la séparation des pouvoirs ?", "answer": "La séparation des pouvoirs (Montesquieu) divise le pouvoir en trois : législatif (fait les lois), exécutif (applique les lois), judiciaire (juge). Cette séparation empêche la concentration du pouvoir.", "category": "Définition"}]',
  true, 1);

  -- ============================================================
  -- EPS - Chapitre 1 : Physiologie de l'Effort
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_eps_id, 'physiologie-effort', 1, 'Physiologie de l''Effort', 'Le fonctionnement du corps pendant l''activité physique', 1)
  RETURNING id INTO v_ch_41;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_41, 'physiologie-effort', 'Physiologie de l''Effort',
  'Comprendre comment le corps fonctionne pendant l''effort physique est essentiel en EPS. Ce chapitre couvre les systèmes énergétiques, l''adaptation cardiorespiratoire et la récupération.',
  '{"key_points": ["Les trois filières énergétiques : anaérobie alactique, anaérobie lactique, aérobie", "La fréquence cardiaque augmente avec l''intensité de l''effort", "FC max théorique = 220 - âge", "L''échauffement prépare le corps à l''effort et prévient les blessures", "La VO2max mesure la capacité aérobie maximale", "Les étirements et l''hydratation sont essentiels pour la récupération", "L''alimentation du sportif doit être équilibrée et adaptée à l''effort"], "content": "## Les filières énergétiques\n\nLe corps utilise **trois systèmes** pour produire l''énergie (ATP) nécessaire à l''effort :\n\n### 1. Filière anaérobie alactique\n- **Durée** : 0 à 10 secondes\n- **Intensité** : maximale (sprint, saut)\n- **Source** : réserves de phosphocréatine (PCr) dans les muscles\n- **Pas de production d''acide lactique**\n- Exemple : sprint 100m, lancer de poids\n\n### 2. Filière anaérobie lactique\n- **Durée** : 10 secondes à 2-3 minutes\n- **Intensité** : sous-maximale à haute\n- **Source** : glycolyse anaérobie (dégradation du glucose sans oxygène)\n- **Produit de l''acide lactique** → fatigue musculaire\n- Exemple : 400m, 800m\n\n### 3. Filière aérobie\n- **Durée** : au-delà de 3 minutes\n- **Intensité** : modérée à moyenne\n- **Source** : oxydation des glucides et des lipides **avec** oxygène\n- **Pas d''accumulation d''acide lactique**\n- Exemple : course de fond, football, cyclisme\n\n## L''adaptation cardiorespiratoire\n\n### La fréquence cardiaque (FC)\n- **Au repos** : 60-80 bpm (battements par minute)\n- **À l''effort** : augmente proportionnellement à l''intensité\n- **FC maximale théorique** : 220 - âge\n  - Exemple : à 18 ans, FC max = 220 - 18 = 202 bpm\n\n### La ventilation\n- La fréquence respiratoire augmente avec l''effort\n- Plus d''oxygène est apporté aux muscles\n- Plus de CO₂ est évacué\n\n### La VO2max\nC''est le **volume maximal d''oxygène** que le corps peut utiliser par minute. Plus la VO2max est élevée, meilleure est l''endurance.\n\n## L''échauffement\n\nL''échauffement est **indispensable** avant tout effort :\n- **Augmente** la température musculaire\n- **Améliore** l''élasticité des muscles et tendons\n- **Active** le système cardiorespiratoire\n- **Prévient** les blessures (claquages, entorses)\n- **Durée** : 10 à 15 minutes minimum\n\n### Structure de l''échauffement\n1. **Échauffement général** : course légère, mobilisations articulaires\n2. **Échauffement spécifique** : gestes de l''activité à pratiquer\n\n## La récupération\n- **Retour au calme** progressif (pas d''arrêt brutal)\n- **Étirements** doux après l''effort\n- **Hydratation** : boire avant, pendant et après l''effort\n- **Alimentation** : glucides pour reconstituer les réserves\n- **Sommeil** : essentiel pour la récupération musculaire"}',
  '[{"question": "Quelle filière énergétique est utilisée lors d''un sprint de 100m ?", "options": ["Aérobie", "Anaérobie lactique", "Anaérobie alactique", "Toutes à parts égales"], "correct": 2, "explanation": "Le sprint de 100m utilise la filière anaérobie alactique car l''effort est maximal et dure moins de 10 secondes. Elle utilise les réserves de phosphocréatine sans produire d''acide lactique."},
  {"question": "Comment calcule-t-on la FC maximale théorique ?", "options": ["200 - âge", "220 - âge", "180 + âge", "200 + âge"], "correct": 1, "explanation": "La formule de la fréquence cardiaque maximale théorique est : FC max = 220 - âge. Pour un élève de 18 ans : FC max = 220 - 18 = 202 bpm."},
  {"question": "Pourquoi l''échauffement est-il important ?", "options": ["Pour fatiguer les muscles", "Pour augmenter la température musculaire et prévenir les blessures", "Pour perdre du poids", "Pour ralentir le cœur"], "correct": 1, "explanation": "L''échauffement augmente la température musculaire, améliore l''élasticité des muscles et tendons, active le système cardiorespiratoire et prévient les blessures."},
  {"question": "Quelle filière produit de l''acide lactique ?", "options": ["Anaérobie alactique", "Aérobie", "Anaérobie lactique", "Aucune"], "correct": 2, "explanation": "La filière anaérobie lactique (effort de 10 sec à 3 min) produit de l''acide lactique comme déchet de la glycolyse anaérobie, ce qui provoque la fatigue musculaire."},
  {"question": "Qu''est-ce que la VO2max ?", "options": ["Le volume maximal de sang pompé", "Le volume maximal d''oxygène utilisé par minute", "La vitesse maximale de course", "Le volume des poumons"], "correct": 1, "explanation": "La VO2max est le volume maximal d''oxygène que le corps peut consommer par minute pendant un effort intense. C''est le principal indicateur de la capacité aérobie."}]',
  '[{"question": "Quelles sont les trois filières énergétiques ?", "answer": "1. Anaérobie alactique (0-10 sec, effort max, pas d''acide lactique). 2. Anaérobie lactique (10 sec-3 min, produit de l''acide lactique). 3. Aérobie (> 3 min, utilise l''oxygène).", "category": "Définition"},
  {"question": "Pourquoi faut-il s''hydrater pendant l''effort ?", "answer": "L''effort provoque une perte d''eau par la transpiration. La déshydratation diminue les performances, augmente le risque de blessure et peut provoquer des crampes. Il faut boire avant, pendant et après l''effort.", "category": "Définition"},
  {"question": "Qu''est-ce que l''acide lactique ?", "answer": "L''acide lactique est un déchet métabolique produit lors de la filière anaérobie lactique (effort intense de 10 sec à 3 min). Son accumulation dans les muscles provoque la sensation de brûlure et la fatigue.", "category": "Définition"},
  {"question": "Quelle est la structure d''un bon échauffement ?", "answer": "1. Échauffement général (10 min) : course légère, mobilisations articulaires. 2. Échauffement spécifique (5 min) : gestes techniques de l''activité. Durée totale : 10-15 minutes minimum.", "category": "Définition"}]',
  false, 1);

  -- ============================================================
  -- EPS - Chapitre 2 : Règles et Valeurs du Sport
  -- ============================================================
  INSERT INTO chapters (id, subject_id, slug, number, title, description, display_order)
  VALUES (gen_random_uuid(), v_eps_id, 'regles-valeurs-sport', 2, 'Règles et Valeurs du Sport', 'L''esprit sportif, les règles et les valeurs éducatives du sport', 2)
  RETURNING id INTO v_ch_42;

  INSERT INTO fiches (id, chapter_id, slug, title, summary, content, quiz, flashcards, is_premium, display_order)
  VALUES (gen_random_uuid(), v_ch_42, 'regles-valeurs-sport', 'Règles et Valeurs du Sport',
  'Le sport est porteur de valeurs éducatives fondamentales. Ce chapitre explore les règles sportives, l''esprit sportif, le fair-play et le rôle social du sport.',
  '{"key_points": ["Le fair-play est le respect des règles, des adversaires, des arbitres et de soi-même", "Le sport transmet des valeurs : solidarité, respect, persévérance, dépassement de soi", "Les règles sportives garantissent l''équité et la sécurité", "Le dopage est interdit car il est dangereux et contraire à l''éthique sportive", "Le sport contribue à la santé physique et mentale", "Le sport est un outil d''intégration sociale et de cohésion", "Les Jeux Olympiques symbolisent l''idéal sportif : plus vite, plus haut, plus fort, ensemble"], "content": "## Le fair-play et l''esprit sportif\n\n### Définition\nLe **fair-play** est une attitude qui consiste à respecter les **règles du jeu**, les **adversaires**, les **arbitres**, les **coéquipiers** et **soi-même**.\n\n### Les composantes du fair-play\n- **Respect des règles** : jouer dans le cadre défini\n- **Respect de l''adversaire** : ne pas tricher, ne pas blesser volontairement\n- **Respect de l''arbitre** : accepter ses décisions\n- **Accepter la défaite** avec dignité et la victoire avec humilité\n- **Maîtrise de soi** : contrôler ses émotions et ses réactions\n\n## Les valeurs éducatives du sport\n\n### Valeurs individuelles\n- **Persévérance** : continuer malgré les difficultés\n- **Dépassement de soi** : repousser ses limites\n- **Discipline** : rigueur dans l''entraînement\n- **Confiance en soi** : croire en ses capacités\n- **Gestion des émotions** : contrôler le stress et la pression\n\n### Valeurs collectives\n- **Solidarité** : soutenir ses coéquipiers\n- **Coopération** : travailler ensemble vers un objectif commun\n- **Respect** : de l''autre, des différences\n- **Intégration** : le sport unit au-delà des origines et des cultures\n\n## Les règles sportives\n\n### Pourquoi des règles ?\n- Garantir l''**équité** : les mêmes conditions pour tous\n- Assurer la **sécurité** des pratiquants\n- Permettre le **déroulement ordonné** de la compétition\n- Donner un **cadre commun** reconnu par tous\n\n### L''arbitrage\nL''arbitre est le **garant des règles**. Il assure :\n- L''application correcte du règlement\n- La sécurité des joueurs\n- L''équité de la compétition\n\n## Le dopage\n\n### Définition\nLe **dopage** est l''utilisation de substances ou méthodes interdites pour améliorer artificiellement les performances sportives.\n\n### Pourquoi le dopage est interdit\n- **Dangereux** pour la santé (risques cardiaques, hormonaux, psychologiques)\n- **Contraire à l''éthique** sportive (triche)\n- Rompt l''**égalité des chances** entre compétiteurs\n- Donne un **mauvais exemple** à la jeunesse\n\n## Le rôle social du sport\n- Outil d''**intégration sociale** et de lutte contre l''exclusion\n- Facteur de **cohésion nationale** (équipes nationales)\n- Moyen de **santé publique** (lutte contre la sédentarité)\n- Vecteur de **développement** (infrastructures, emplois, tourisme)\n\n## L''olympisme\nLa devise olympique : **« Plus vite, plus haut, plus fort — ensemble »**\n- Les **Jeux Olympiques** symbolisent la paix, l''amitié et le respect entre les peuples\n- La **Charte olympique** promeut l''éthique, la solidarité et le sport pour tous"}',
  '[{"question": "Qu''est-ce que le fair-play ?", "options": ["Gagner à tout prix", "Le respect des règles, des adversaires et des arbitres", "Tricher sans se faire prendre", "Ne pas participer aux compétitions"], "correct": 1, "explanation": "Le fair-play est l''attitude qui consiste à respecter les règles du jeu, les adversaires, les arbitres, les coéquipiers et soi-même. C''est l''essence de l''esprit sportif."},
  {"question": "Pourquoi le dopage est-il interdit ?", "options": ["Parce qu''il est trop cher", "Parce qu''il est dangereux pour la santé et contraire à l''éthique", "Parce qu''il ne fonctionne pas", "Parce qu''il est naturel"], "correct": 1, "explanation": "Le dopage est interdit car il est dangereux pour la santé (risques cardiaques, hormonaux), contraire à l''éthique sportive (triche), rompt l''égalité des chances et donne un mauvais exemple."},
  {"question": "Quelle est la devise olympique actuelle ?", "options": ["L''essentiel est de participer", "Plus vite, plus haut, plus fort — ensemble", "Que le meilleur gagne", "Un pour tous, tous pour un"], "correct": 1, "explanation": "La devise olympique est ''Plus vite, plus haut, plus fort — ensemble'' (Citius, Altius, Fortius — Communiter). Le mot ''ensemble'' a été ajouté en 2021 pour souligner la solidarité."},
  {"question": "Quel est le rôle de l''arbitre ?", "options": ["Entraîner les joueurs", "Garantir l''application des règles, la sécurité et l''équité", "Décider qui gagne avant le match", "Punir les joueurs"], "correct": 1, "explanation": "L''arbitre est le garant des règles du jeu. Il assure l''application correcte du règlement, la sécurité des joueurs et l''équité de la compétition."},
  {"question": "Quelle valeur le sport de compétition développe-t-il particulièrement ?", "options": ["La paresse", "Le dépassement de soi", "L''individualisme", "L''agressivité"], "correct": 1, "explanation": "Le sport de compétition développe particulièrement le dépassement de soi : la capacité à repousser ses limites, à persévérer malgré la difficulté et à donner le meilleur de soi-même."}]',
  '[{"question": "Quelles sont les valeurs individuelles du sport ?", "answer": "Persévérance, dépassement de soi, discipline, confiance en soi, gestion des émotions. Ces valeurs développées par le sport sont transférables dans la vie quotidienne.", "category": "Définition"},
  {"question": "Qu''est-ce que le dopage ?", "answer": "Le dopage est l''utilisation de substances (stéroïdes, EPO) ou méthodes interdites (transfusion sanguine) pour améliorer artificiellement les performances sportives. Il est dangereux et contraire à l''éthique.", "category": "Définition"},
  {"question": "Pourquoi les règles sportives sont-elles nécessaires ?", "answer": "Les règles garantissent l''équité (mêmes conditions pour tous), la sécurité des pratiquants, le bon déroulement de la compétition et fournissent un cadre commun reconnu par tous les participants.", "category": "Définition"},
  {"question": "Comment le sport contribue-t-il à l''intégration sociale ?", "answer": "Le sport unit les personnes au-delà des différences d''origine, de culture ou de classe sociale. Il favorise la coopération, le respect mutuel et la solidarité, contribuant ainsi à la cohésion sociale.", "category": "Définition"}]',
  true, 1);

END;
$$;
